	DefaultPortRanges []string      `yaml:"default_port_ranges"`
}

type PackageManagerConfig struct {
	EnabledManagers []string `yaml:"enabled_managers"`
	AutoUpdate      bool     `yaml:"auto_update"`
	CheckSecurity   bool     `yaml:"check_security"`
}

type ContainerMgmtConfig struct {
