// Actions

// activateSelectedItem activates the currently selected setting item
func (sp *SettingsPageModel) activateSelectedItem() tea.Cmd {
	items := sp.getSectionItems(sp.currentSection)
	if sp.selectedItem >= len(items) {
		return nil
	}

	item := items[sp.selectedItem]

	switch item.Type {
	case ItemTypeString, ItemTypeNumber, ItemTypeHotkey:
		// Enter edit mode
		sp.editMode = true
		sp.editingItem = item.Name
		sp.editValue = fmt.Sprintf("%v", item.Value)
		sp.editCursorPos = len(sp.editValue)

	case ItemTypeBool:
		// Toggle boolean value
		if sp.configManager != nil && item.Section != "" && item.Key != "" {
			currentValue, _ := item.Value.(bool)
			return tea.Cmd(func() tea.Msg {
				err := sp.configManager.UpdateSetting(sp.config, item.Section, item.Key, !currentValue)
				if err == nil && sp.config.General.AutoSave {
					sp.configManager.SaveConfig(sp.config)
				}
				return ConfigUpdateMsg{Config: sp.config}
			})
		}

	case ItemTypeSelection:
		// Cycle through options
		if len(item.Options) > 0 {
			currentIndex := 0
			currentValue := fmt.Sprintf("%v", item.Value)
			for i, option := range item.Options {
				if option == currentValue {
					currentIndex = i
					break
				}
			}
			nextIndex := (currentIndex + 1) % len(item.Options)
			newValue := item.Options[nextIndex]

			if sp.configManager != nil && item.Section != "" && item.Key != "" {
				return tea.Cmd(func() tea.Msg {
					err := sp.configManager.UpdateSetting(sp.config, item.Section, item.Key, newValue)
					if err == nil && sp.config.General.AutoSave {
						sp.configManager.SaveConfig(sp.config)
					}
					return ConfigUpdateMsg{Config: sp.config}
				})
			}
		}

	case ItemTypeAction:
		// Execute action
		if item.Action != nil {
			item.Action()
		}

	case ItemTypeColor:
		// TODO: Implement color picker
		break
	}

	return nil
}

// saveEditedValue saves the currently edited value
func (sp *SettingsPageModel) saveEditedValue() tea.Cmd {
	items := sp.getSectionItems(sp.currentSection)
	if sp.selectedItem >= len(items) {
		return nil
	}

	item := items[sp.selectedItem]
	if sp.configManager == nil || item.Section == "" || item.Key == "" {
		return nil
	}

	// Parse the edited value based on the item type
	var value interface{}

	switch item.Type {
	case ItemTypeString, ItemTypeHotkey:
		value = sp.editValue
	case ItemTypeNumber:
		if val, parseErr := time.ParseDuration(sp.editValue + "ms"); parseErr == nil {
			// Handle duration values
			value = val
		} else {
			var val float64
			if floatVal, parseErr := fmt.Sscanf(sp.editValue, "%f", &val); parseErr == nil && floatVal == 1 {
				// Handle numeric values
				if item.Key == "particle_count" || item.Key == "memory_usage_limit_mb" {
					value = int(val)
				} else {
					value = val
				}
			} else {
				return nil // Invalid format
			}
		}
	default:
		return nil
	}

	// Update the configuration
	return tea.Cmd(func() tea.Msg {
		err := sp.configManager.UpdateSetting(sp.config, item.Section, item.Key, value)
		if err == nil && sp.config.General.AutoSave {
			sp.configManager.SaveConfig(sp.config)
		}
		return ConfigUpdateMsg{Config: sp.config}
	})
}

// resetSectionToDefaults resets the current section to default values
func (sp *SettingsPageModel) resetSectionToDefaults() tea.Cmd {
	if sp.configManager == nil {
		return nil
	}

	return tea.Cmd(func() tea.Msg {
		defaultConfig := sp.configManager.GetDefaultConfig()

		// Reset current section based on which section is active
		switch sp.currentSection {
		case SectionGeneral:
			sp.config.General = defaultConfig.General
		case SectionThemes:
			sp.config.Theme = defaultConfig.Theme
		case SectionHotkeys:
			sp.config.KeyBindings = defaultConfig.KeyBindings
		case SectionAdvanced:
			sp.config.AdvancedUI = defaultConfig.AdvancedUI
			sp.config.RefreshRates = defaultConfig.RefreshRates
		}

		if sp.config.General.AutoSave {
			sp.configManager.SaveConfig(sp.config)
		}

		return ConfigUpdateMsg{Config: sp.config}
	})
}

// saveSettings saves all current settings
func (sp *SettingsPageModel) saveSettings() tea.Cmd {
	if sp.configManager == nil {
		return nil
	}

	return tea.Cmd(func() tea.Msg {
		sp.configManager.SaveConfig(sp.config)
		return StatusUpdateMsg{
			Status: "Settings saved successfully",
			Color:  lipgloss.Color("#10b981"),
		}
	})
}

// Visual effects

// updateVisualEffects updates the visual effects state
func (sp *SettingsPageModel) updateVisualEffects() {
	sp.frame++
	sp.pulsePhase += 0.05
}

// tickCmd returns a command for visual effects timing
func (sp *SettingsPageModel) tickCmd() tea.Cmd {
	return tea.Tick(time.Millisecond*50, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

// Rendering

// renderSettings renders the main settings interface
func (sp *SettingsPageModel) renderSettings() string {
	var s strings.Builder

	// Header
	header := sp.renderHeader()
	s.WriteString(header + "\n")

	// Navigation tabs
	nav := sp.renderNavigation()
	s.WriteString(nav + "\n")

	// Content area
	content := sp.renderContent()
	s.WriteString(content)

	// Status bar
	status := sp.renderStatusBar()
	s.WriteString(status)

	return s.String()
}

// renderHeader renders the settings page header
func (sp *SettingsPageModel) renderHeader() string {
	title := "⚙️ QUANTUM SETTINGS"

	titleStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Align(lipgloss.Center).
		Width(sp.width)

	return titleStyle.Render(title)
}

// renderNavigation renders the section navigation tabs
func (sp *SettingsPageModel) renderNavigation() string {
	var tabs []string

	sectionInfo := []struct {
		section SettingsSection
		icon    string
		key     string
	}{
		{SectionGeneral, "⚙️", "1"},
		{SectionThemes, "🎨", "2"},
		{SectionHotkeys, "⌨️", "3"},
		{SectionAdvanced, "🔧", "4"},
		{SectionProfiles, "👤", "5"},
		{SectionAbout, "ℹ️", "6"},
	}

	for _, info := range sectionInfo {
		content := fmt.Sprintf("%s %s %s", info.icon, info.key, info.section.String())

		if info.section == sp.currentSection {
			// Active tab
			tabs = append(tabs, lipgloss.NewStyle().
				Foreground(lipgloss.Color("#0f0f23")).
				Background(lipgloss.Color("#6366f1")).
				Bold(true).
				Padding(0, 2).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#6366f1")).
				Render(content))
		} else {
			// Inactive tab
			tabs = append(tabs, lipgloss.NewStyle().
				Foreground(lipgloss.Color("#6366f1")).
				Border(lipgloss.RoundedBorder()).
				BorderForeground(lipgloss.Color("#64748b")).
				Padding(0, 2).
				Render(content))
		}
	}

	return lipgloss.JoinHorizontal(lipgloss.Center, tabs...)
}

// renderContent renders the settings content for the current section
func (sp *SettingsPageModel) renderContent() string {
	var s strings.Builder

	// Section title
	sectionTitle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#8b5cf6")).
		Bold(true).
		Render(fmt.Sprintf("📋 %s Settings", sp.currentSection.String()))
	s.WriteString(sectionTitle + "\n\n")

	// Settings items
	items := sp.getSectionItems(sp.currentSection)
	visibleHeight := sp.height - 12 // Leave space for header, nav, status

	startIdx := sp.scrollOffset
	endIdx := startIdx + visibleHeight
	if endIdx > len(items) {
		endIdx = len(items)
	}

	for i := startIdx; i < endIdx; i++ {
		item := items[i]
		isSelected := i == sp.selectedItem

		// Render item
		itemStr := sp.renderSettingsItem(item, isSelected)
		s.WriteString(itemStr + "\n")
	}

	return s.String()
}

// renderSettingsItem renders a single settings item
func (sp *SettingsPageModel) renderSettingsItem(item SettingsItem, selected bool) string {
	var s strings.Builder

	// Selection indicator
	indicator := "  "
	if selected {
		indicator = "► "
	}

	// Item name and value
	nameStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#e2e8f0")).
		Bold(selected)

	valueStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8"))

	if selected {
		nameStyle = nameStyle.Background(lipgloss.Color("#1e1e3f"))
		valueStyle = valueStyle.Background(lipgloss.Color("#1e1e3f"))
	}

	// Format value based on type
	var valueStr string
	switch item.Type {
	case ItemTypeBool:
		if val, ok := item.Value.(bool); ok && val {
			valueStr = "✅ Enabled"
		} else {
			valueStr = "❌ Disabled"
		}
	case ItemTypeAction:
		valueStr = "Press Enter"
	default:
		valueStr = fmt.Sprintf("%v", item.Value)
	}

	// Edit mode indicator
	if sp.editMode && sp.editingItem == item.Name {
		// Show edit cursor
		displayValue := sp.editValue
		if sp.editCursorPos < len(displayValue) {
			displayValue = displayValue[:sp.editCursorPos] + "█" + displayValue[sp.editCursorPos+1:]
		} else {
			displayValue += "█"
		}
		valueStr = displayValue
		valueStyle = valueStyle.Foreground(lipgloss.Color("#f59e0b"))
	}

	itemLine := fmt.Sprintf("%s%-30s %s", indicator, item.Name, valueStr)
	s.WriteString(nameStyle.Width(sp.width - 2).Render(itemLine))

	// Description (if selected)
	if selected && item.Description != "" {
		descStyle := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#64748b")).
			Italic(true)
		s.WriteString("\n  " + descStyle.Render(item.Description))
	}

	return s.String()
}

// renderStatusBar renders the settings status bar
func (sp *SettingsPageModel) renderStatusBar() string {
	var statusParts []string

	// Current section info
	statusParts = append(statusParts,
		lipgloss.NewStyle().Foreground(lipgloss.Color("#8b5cf6")).Render(
			fmt.Sprintf("📂 %s", sp.currentSection.String())))

	// Edit mode indicator
	if sp.editMode {
		statusParts = append(statusParts,
			lipgloss.NewStyle().Foreground(lipgloss.Color("#f59e0b")).Render("✏️ Editing"))
	}

	// Item count
	items := sp.getSectionItems(sp.currentSection)
	statusParts = append(statusParts,
		lipgloss.NewStyle().Foreground(lipgloss.Color("#06b6d4")).Render(
			fmt.Sprintf("📊 %d/%d", sp.selectedItem+1, len(items))))

	// Auto save indicator
	if sp.config != nil && sp.config.General.AutoSave {
		statusParts = append(statusParts,
			lipgloss.NewStyle().Foreground(lipgloss.Color("#10b981")).Render("💾 Auto-save ON"))
	}

	// Help text
	statusParts = append(statusParts,
		lipgloss.NewStyle().Foreground(lipgloss.Color("#64748b")).Render("💡 ←→: sections, ↑↓: items, Enter: edit, S: save"))

	status := strings.Join(statusParts, " • ")

	return lipgloss.NewStyle().
		Background(lipgloss.Color("#1e1e3f")).
		Foreground(lipgloss.Color("#e2e8f0")).
		Width(sp.width).
		Padding(0, 1).
		Render(status)
}

