    10→// ViewManager handles view routing and state management
    11→type ViewManager struct {
    12→	// Current state
    13→	currentView  ViewType
    14→	previousView ViewType
    15→	viewHistory  []ViewType
    16→
    17→	// Component registry
    18→	components map[ViewType]ToolComponent
    19→
    20→	// State preservation
