    34→		currentView:     ViewOverview,
    35→		previousView:    ViewOverview,
    36→		viewHistory:     make([]ViewType, 0),
    37→		components:      make(map[ViewType]ToolComponent),
    38→		componentStates: make(map[ViewType]interface{}),
    39→		maxHistorySize:  10,
    40→	}
    41→}
    42→
    43→// RegisterComponent registers a tool component with the view manager
    44→func (vm *ViewManager) RegisterComponent(viewType ViewType, component ToolComponent) {
    45→	vm.components[viewType] = component
    46→	if component != nil {
    47→		component.SetSize(vm.width, vm.height)
    48→		component.SetActive(viewType == vm.currentView)
    49→	}
    50→}
    51→
    52→// UnregisterComponent removes a component from the view manager
    53→func (vm *ViewManager) UnregisterComponent(viewType ViewType) {
    54→	if component, exists := vm.components[viewType]; exists {
    55→		if component != nil {
    56→			component.SetActive(false)
    57→		}
    58→		delete(vm.components, viewType)
    59→		delete(vm.componentStates, viewType)
    60→	}
    61→}
    62→
    63→// SwitchView switches to a new view with state preservation
    64→func (vm *ViewManager) SwitchView(newView ViewType) tea.Cmd {
    65→	if newView == vm.currentView {
    66→		return nil
    67→	}
    68→
    69→	// Save current component state
    70→	vm.preserveCurrentState()
    71→
    72→	// Deactivate current component
    73→	if currentComponent := vm.GetCurrentComponent(); currentComponent != nil {
    74→		currentComponent.SetActive(false)
    75→	}
    76→
    77→	// Update view state
    78→	vm.addToHistory(vm.currentView)
    79→	vm.previousView = vm.currentView
    80→	vm.currentView = newView
    81→
    82→	// Restore new component state
    83→	vm.restoreComponentState(newView)
    84→
    85→	// Activate new component
    86→	if newComponent := vm.GetCurrentComponent(); newComponent != nil {
    87→		newComponent.SetActive(true)
    88→		// Initialize component if it hasn't been initialized yet
    89→		return newComponent.Init()
    90→	}
    91→
    92→	return nil
    93→}
    94→
    95→// GoBack navigates to the previous view
    96→func (vm *ViewManager) GoBack() tea.Cmd {
    97→	if len(vm.viewHistory) > 0 {
    98→		// Get the last view from history
    99→		lastView := vm.viewHistory[len(vm.viewHistory)-1]
   100→		vm.viewHistory = vm.viewHistory[:len(vm.viewHistory)-1]
   101→
   102→		return vm.SwitchView(lastView)
   103→	}
   104→
   105→	// If no history, go to overview
   106→	if vm.currentView != ViewOverview {
   107→		return vm.SwitchView(ViewOverview)
   108→	}
   109→
   110→	return nil
   111→}
   112→
   113→// GetCurrentView returns the current view type
   114→func (vm *ViewManager) GetCurrentView() ViewType {
   115→	return vm.currentView
   116→}
   117→
   118→// GetPreviousView returns the previous view type
   119→func (vm *ViewManager) GetPreviousView() ViewType {
   120→	return vm.previousView
   121→}
   122→
   123→// GetCurrentComponent returns the currently active component
   124→func (vm *ViewManager) GetCurrentComponent() ToolComponent {
   125→	return vm.components[vm.currentView]
   126→}
   127→
   128→// GetComponent returns a specific component by view type
   129→func (vm *ViewManager) GetComponent(viewType ViewType) ToolComponent {
   130→	return vm.components[viewType]
   131→}
   132→
   133→// RouteMessage routes a message to the appropriate component
   134→func (vm *ViewManager) RouteMessage(msg tea.Msg) ([]ToolComponent, []tea.Cmd) {
   135→	var updatedComponents []ToolComponent
   136→	var cmds []tea.Cmd
   137→
   138→	switch msg := msg.(type) {
   139→	case ViewSwitchMsg:
