// Init initializes the AI assistant component
func (ai *AIAssistantModel) Init() tea.Cmd {
	return tea.Batch(
		tea.Tick(50*time.Millisecond, func(t time.Time) tea.Msg {
			return tickMsg(t)
		}),
	)
}

// Update handles messages for the AI assistant
func (ai *AIAssistantModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	if !ai.active {
		return ai, nil
	}

	switch msg := msg.(type) {
	case tea.KeyMsg:
		return ai.handleKeyPress(msg)

	case tickMsg:
		ai.frame++
		ai.pulsePhase += 0.1
		ai.glowIntensity = 0.3 + 0.4*float64(math.Sin(ai.pulsePhase))
		return ai, nil

	case aiResponseMsg:
		ai.isProcessing = false
		if msg.error != nil {
			ai.addMessage("assistant", fmt.Sprintf("Error: %v", msg.error), msg.agent)
		} else {
			ai.addMessage("assistant", msg.response, msg.agent)
		}
		if ai.autoScroll {
			ai.scrollToBottom()
		}
		return ai, nil

	case aiProcessingMsg:
		ai.isProcessing = msg.processing
		return ai, nil
	}

	return ai, nil
}

// handleKeyPress handles keyboard input
func (ai *AIAssistantModel) handleKeyPress(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch {
	case msg.String() == "tab":
		ai.showAgentSelector = !ai.showAgentSelector
		return ai, nil

	case msg.String() == "ctrl+h":
		ai.showChatHistory = !ai.showChatHistory
		return ai, nil

	case msg.String() == "ctrl+c":
		if ai.isProcessing {
			ai.isProcessing = false
			ai.addMessage("system", "Processing cancelled", "system")
		}
		return ai, nil

	case msg.String() == "ctrl+l":
		ai.chatHistory = make([]AIMessage, 0)
		return ai, nil

	case ai.showAgentSelector:
		return ai.handleAgentSelection(msg)

	default:
		return ai.handleChatInput(msg)
	}
}

// handleAgentSelection handles agent selection interface
func (ai *AIAssistantModel) handleAgentSelection(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch msg.String() {
	case "up", "k":
		if ai.selectedAgentIdx > 0 {
			ai.selectedAgentIdx--
		}
	case "down", "j":
		if ai.selectedAgentIdx < len(ai.availableAgents)-1 {
			ai.selectedAgentIdx++
		}
	case "enter":
		if ai.selectedAgentIdx < len(ai.availableAgents) {
			ai.currentAgent = ai.availableAgents[ai.selectedAgentIdx].Command
			ai.showAgentSelector = false
			ai.addMessage("system", fmt.Sprintf("Switched to %s", ai.availableAgents[ai.selectedAgentIdx].Name), "system")
		}
	case "esc":
		ai.showAgentSelector = false
	}
	return ai, nil
}

// handleChatInput handles chat input
func (ai *AIAssistantModel) handleChatInput(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch msg.String() {
	case "enter":
		if ai.input != "" {
			return ai.sendMessage()
		}
	case "backspace":
		if ai.cursorPos > 0 {
			ai.input = ai.input[:ai.cursorPos-1] + ai.input[ai.cursorPos:]
			ai.cursorPos--
		}
	case "left":
		if ai.cursorPos > 0 {
			ai.cursorPos--
		}
	case "right":
		if ai.cursorPos < len(ai.input) {
			ai.cursorPos++
		}
	case "home", "ctrl+a":
		ai.cursorPos = 0
	case "end", "ctrl+e":
		ai.cursorPos = len(ai.input)
	case "up":
		ai.scrollUp()
	case "down":
		ai.scrollDown()
	default:
		if len(msg.String()) == 1 {
			ai.input = ai.input[:ai.cursorPos] + msg.String() + ai.input[ai.cursorPos:]
			ai.cursorPos++
		}
	}
	return ai, nil
}

// sendMessage sends a message to the AI
func (ai *AIAssistantModel) sendMessage() (ToolComponent, tea.Cmd) {
	message := strings.TrimSpace(ai.input)
	if message == "" {
		return ai, nil
	}

	// Add user message to history
	ai.addMessage("user", message, ai.currentAgent)

	// Clear input
	ai.input = ""
	ai.cursorPos = 0

	// Set processing state
	ai.isProcessing = true

	if ai.autoScroll {
		ai.scrollToBottom()
	}

	// Send to AI agent
	return ai, ai.processAIRequest(message)
}

// processAIRequest processes the AI request
func (ai *AIAssistantModel) processAIRequest(message string) tea.Cmd {
	return func() tea.Msg {
		// Find the current agent
		var agent *AIAgent
		for _, a := range ai.availableAgents {
			if a.Command == ai.currentAgent {
				agent = &a
				break
			}
		}

		if agent == nil || !agent.Available {
			return aiResponseMsg{
				response: "The selected AI agent is not available. Please check your installation or select a different agent.",
				agent:    ai.currentAgent,
				error:    fmt.Errorf("agent not available"),
			}
		}

		// Construct command based on agent type
		var cmd *exec.Cmd
		switch agent.Command {
		case "claude-code":
			// Claude Code: Try claude command if available
			cmd = exec.Command("claude", message)
		case "gemini":
			// Gemini CLI: Use -p flag for prompt
			cmd = exec.Command("gemini", "-p", message)
		case "gh copilot":
			// GitHub Copilot CLI: Use suggest command for code suggestions
			cmd = exec.Command("gh", "copilot", "suggest", message)
		case "opencode":
			cmd = exec.Command("opencode", message)
		case "aider":
			// Aider: Use --message flag for non-interactive mode
			cmd = exec.Command("aider", "--message", message)
		case "sgpt":
			// Shell GPT: Direct message input
			cmd = exec.Command("sgpt", message)
		default:
			return aiResponseMsg{
				response: "",
				agent:    agent.Command,
				error:    fmt.Errorf("unknown agent command: %s", agent.Command),
			}
		}

		// Set working directory
		if wd, err := os.Getwd(); err == nil {
			cmd.Dir = wd
		}

		// Execute command
		output, err := cmd.CombinedOutput()
		return aiResponseMsg{
			response: string(output),
			agent:    agent.Command,
			error:    err,
		}
	}
}

// View renders the AI assistant interface
func (ai *AIAssistantModel) View() string {
	if !ai.active {
		return ""
	}

	var sections []string

	// Header
	sections = append(sections, ai.renderHeader())

	// Agent selector or chat interface
	if ai.showAgentSelector {
		sections = append(sections, ai.renderAgentSelector())
	} else {
		// Chat history
		if ai.showChatHistory {
			sections = append(sections, ai.renderChatHistory())
		}

		// Input area
		sections = append(sections, ai.renderInputArea())
	}

	// Help footer
	sections = append(sections, ai.renderHelp())

	return lipgloss.JoinVertical(lipgloss.Left, sections...)
}

// renderHeader renders the header section
func (ai *AIAssistantModel) renderHeader() string {
	currentAgentName := "Unknown"
	currentAgentIcon := "🤖"
	currentAgentColor := lipgloss.Color("#6b7280")

	for _, agent := range ai.availableAgents {
		if agent.Command == ai.currentAgent {
			currentAgentName = agent.Name
			currentAgentIcon = agent.Icon
			currentAgentColor = agent.Color
			break
		}
	}

	titleStyle := lipgloss.NewStyle().
		Foreground(currentAgentColor).
		Bold(true).
		Padding(0, 1)

	statusStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Italic(true)

	processingIndicator := ""
	if ai.isProcessing {
		dots := strings.Repeat(".", (ai.frame/10)%4)
		processingIndicator = statusStyle.Render(fmt.Sprintf(" (processing%s)", dots))
	}

	title := titleStyle.Render(fmt.Sprintf("%s AI Assistant - %s", currentAgentIcon, currentAgentName))

	headerBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(currentAgentColor).
		Padding(1, 2).
		Width(ai.width - 4)

	return headerBox.Render(title + processingIndicator)
}

// renderAgentSelector renders the agent selection interface
func (ai *AIAssistantModel) renderAgentSelector() string {
	var items []string

	for i, agent := range ai.availableAgents {
		style := lipgloss.NewStyle().Padding(0, 2)

		if i == ai.selectedAgentIdx {
			style = style.Background(agent.Color).Foreground(lipgloss.Color("#000000"))
		} else if !agent.Available {
			style = style.Foreground(lipgloss.Color("#6b7280"))
		} else {
			style = style.Foreground(agent.Color)
		}

		status := "✓"
		if !agent.Available {
			status = "✗"
		}

		item := fmt.Sprintf("%s %s %s - %s", status, agent.Icon, agent.Name, agent.Description)
		items = append(items, style.Render(item))
	}

	selectorBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#6b7280")).
		Padding(1, 2).
		Width(ai.width - 4).
		Height(ai.height - 8)

	content := lipgloss.JoinVertical(lipgloss.Left, items...)
	return selectorBox.Render(content)
}

// renderChatHistory renders the chat history
func (ai *AIAssistantModel) renderChatHistory() string {
	if len(ai.chatHistory) == 0 {
		emptyStyle := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Align(lipgloss.Center).
			Padding(2)

		return emptyStyle.Render("No conversation yet. Type a message to start chatting with your AI assistant!")
	}

	var messages []string
	visibleHeight := ai.height - 12 // Account for header, input, and help

	startIdx := ai.scrollOffset
	endIdx := len(ai.chatHistory)

	if endIdx-startIdx > visibleHeight {
		endIdx = startIdx + visibleHeight
	}

	for i := startIdx; i < endIdx && i < len(ai.chatHistory); i++ {
		msg := ai.chatHistory[i]
		messages = append(messages, ai.renderMessage(msg))
	}

	chatBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#374151")).
		Padding(1, 2).
		Width(ai.width - 4).
		Height(visibleHeight)

	content := lipgloss.JoinVertical(lipgloss.Left, messages...)
	return chatBox.Render(content)
}

// renderMessage renders a single chat message
func (ai *AIAssistantModel) renderMessage(msg AIMessage) string {
	var style lipgloss.Style
	var prefix string

	switch msg.Role {
	case "user":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#3b82f6"))
		prefix = "You: "
	case "assistant":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#10b981"))
		prefix = "AI: "
	case "system":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#6b7280")).Italic(true)
		prefix = "System: "
	}

	timestamp := ""
	if ai.timestamps {
		timestamp = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Render(fmt.Sprintf("[%s] ", msg.Timestamp.Format("15:04:05")))
	}

	content := style.Render(prefix + msg.Content)
	return timestamp + content
}

// renderInputArea renders the input area
func (ai *AIAssistantModel) renderInputArea() string {
	cursor := ""
	if ai.cursorPos == len(ai.input) {
		cursor = "│"
	}

	displayInput := ai.input[:ai.cursorPos] + cursor + ai.input[ai.cursorPos:]

	inputStyle := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#6366f1")).
		Padding(0, 2).
		Width(ai.width - 4)

	placeholder := ""
	if ai.input == "" && !ai.isProcessing {
		placeholder = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Render("Type your message here...")
	}

	content := displayInput + placeholder
	if ai.isProcessing {
		content = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Render("Processing your request...")
	}

	return inputStyle.Render(content)
}

// renderHelp renders the help footer
func (ai *AIAssistantModel) renderHelp() string {
	helpStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6b7280")).
		Padding(0, 1)

	help := "Tab: Select Agent • Ctrl+H: Toggle History • Ctrl+L: Clear • Ctrl+C: Cancel • ↑↓: Scroll • Enter: Send"
	return helpStyle.Render(help)
}

// Helper methods

// addMessage adds a message to the chat history
func (ai *AIAssistantModel) addMessage(role, content, agent string) {
	msg := AIMessage{
		Role:      role,
		Content:   content,
		Timestamp: time.Now(),
		Agent:     agent,
	}

	ai.chatHistory = append(ai.chatHistory, msg)

	// Limit history size
	if len(ai.chatHistory) > ai.maxHistorySize {
		ai.chatHistory = ai.chatHistory[len(ai.chatHistory)-ai.maxHistorySize:]
	}
}

// scrollUp scrolls the chat history up
func (ai *AIAssistantModel) scrollUp() {
	if ai.scrollOffset > 0 {
		ai.scrollOffset--
	}
}

// scrollDown scrolls the chat history down
func (ai *AIAssistantModel) scrollDown() {
	maxScroll := len(ai.chatHistory) - (ai.height - 12)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if ai.scrollOffset < maxScroll {
		ai.scrollOffset++
	}
}

// scrollToBottom scrolls to the bottom of chat history
func (ai *AIAssistantModel) scrollToBottom() {
	maxScroll := len(ai.chatHistory) - (ai.height - 12)
	if maxScroll < 0 {
		maxScroll = 0
	}
	ai.scrollOffset = maxScroll
}

// Component interface implementation

// SetSize sets the component size
func (ai *AIAssistantModel) SetSize(width, height int) {
	ai.width = width
	ai.height = height
}

// GetViewType returns the view type
func (ai *AIAssistantModel) GetViewType() ViewType {
	return ViewAIAssistant
}

// IsActive returns whether the component is active
func (ai *AIAssistantModel) IsActive() bool {
	return ai.active
}

// SetActive sets the active state
func (ai *AIAssistantModel) SetActive(active bool) {
	ai.active = active
	if active {
		// Add welcome message if this is the first time
		if len(ai.chatHistory) == 0 {
			ai.addMessage("system", "Welcome to the AI Assistant! Select an agent with Tab and start chatting.", "system")
		}
	}
}

