	headers := []string{"PID", "USER", "CPU%", "MEM%", "STATE", "COMMAND"}
	widths := []int{8, 12, 8, 8, 8, m.width - 50}

	var headerParts []string
	for i, header := range headers {
		headerStyle := lipgloss.NewStyle().
			Foreground(primary).
			Bold(true).
			Width(widths[i]).
			Align(lipgloss.Left)
