   363→// applyMigrations applies any necessary configuration migrations
   364→func (cm *ConfigManager) applyMigrations(config *Config) error {
   365→	// Use config.Version instead of assuming version 1
   366→	currentVersion := config.Version
   367→	if currentVersion == 0 {
   368→		currentVersion = 1 // Default to version 1 for legacy configs
   369→	}
   370→
   371→	// Apply migrations in sequence
   372→	for currentVersion < cm.schemaVersion {
   373→		migrated := false
   374→		for _, rule := range cm.migrationRules {
   375→			if rule.FromVersion == currentVersion {
   376→				if err := rule.Migrate(config); err != nil {
   377→					return fmt.Errorf("migration from version %d to %d failed: %w",
   378→						rule.FromVersion, rule.ToVersion, err)
   379→				}
   380→				currentVersion = rule.ToVersion
   381→				config.Version = currentVersion
   382→				migrated = true
   383→				break
   384→			}
   385→		}
   386→
   387→		if !migrated {
   388→			return fmt.Errorf("no migration path found from version %d to %d",
   389→				currentVersion, cm.schemaVersion)
   390→		}
   391→	}
   392→
   393→	return nil
   394→}
