   656→func (cm *ConfigManager) validateDirectory(value interface{}) error {
   657→	dir, ok := value.(string)
   658→	if !ok {
   659→		return fmt.Errorf("directory must be a string")
   660→	}
   661→
   662→	if dir == "" {
   663→		return fmt.Errorf("directory cannot be empty")
   664→	}
   665→
   666→	// Expand tilde
   667→	if strings.HasPrefix(dir, "~/") {
   668→		homeDir, err := os.UserHomeDir()
   669→		if err != nil {
   670→			return fmt.Errorf("cannot resolve home directory: %w", err)
   671→		}
   672→		dir = filepath.Join(homeDir, dir[2:])
   673→	}
   674→
   675→	// Check if directory exists or can be created
   676→	info, err := os.Stat(dir)
   677→	if err != nil {
   678→		// Try to create the directory
   679→		if err := os.MkdirAll(dir, 0755); err != nil {
   680→			return fmt.Errorf("cannot create directory: %w", err)
   681→		}
   682→		return nil
   683→	}
   684→
   685→	if !info.IsDir() {
   686→		return fmt.Errorf("path exists but is not a directory")
   687→	}
   688→
   689→	// Check if directory is writable
   690→	testFile := filepath.Join(dir, ".write_test")
   691→	if err := os.WriteFile(testFile, []byte("test"), 0644); err != nil {
   692→		return fmt.Errorf("directory is not writable: %w", err)
   693→	}
   694→	os.Remove(testFile) // Cleanup
   695→
   696→	return nil
   697→}
