  1129→// WatchConfig watches for configuration file changes and reloads automatically
  1130→func (cm *ConfigManager) WatchConfig(callback func(*Config)) error {
  1131→	// Get initial modification time
  1132→	initialInfo, err := os.Stat(cm.configPath)
  1133→	if err != nil {
