// BashTerminalModel implements a bash terminal interface with AI assistant integration
type BashTerminalModel struct {
	// Component state
	active bool
	width  int
	height int

	// Terminal state
	currentDir    string
	prompt        string
	input         string
	cursorPos     int
	history       []string
	historyPos    int
	output        []OutputLine
	scrollOffset  int
	maxOutputSize int

	// Command execution
	runningCmd  *exec.Cmd
	cmdOutput   chan string
	cmdDone     chan bool
	isExecuting bool

	// AI Assistant panel state
	showAIPanel     bool
	aiPanelWidth    int
	aiInput         string
	aiCursorPos     int
	aiHistory       []AIMessage
	selectedAgent   string
	availableAgents []AIAgent

	// Visual effects
	frame         int
	pulsePhase    float64
	glowIntensity float64
}

// OutputLine represents a line of terminal output with styling
type OutputLine struct {
	Text      string
	Timestamp time.Time
	Type      OutputType
	Color     lipgloss.Color
}

// OutputType represents different types of terminal output
type OutputType int

const (
	OutputCommand OutputType = iota
	OutputResult
	OutputError
	OutputInfo
	OutputAI
)

// AIMessage represents a message in the AI chat
type AIMessage struct {
	Role      string // "user", "assistant", "system"
	Content   string
	Timestamp time.Time
	Agent     string
}

// AIAgent represents an available AI assistant
type AIAgent struct {
	Name        string
	Command     string
	Description string
	Icon        string
	Color       lipgloss.Color
	Available   bool
}

// Terminal command execution messages
type (
	cmdOutputMsg struct {
		output string
	}
	cmdCompleteMsg struct {
		exitCode int
		error    error
	}
	cmdStartMsg struct {
		command string
	}
)

