// HistoricalDataPoint represents a single data point in time
type HistoricalDataPoint struct {
	Timestamp time.Time
	Value     float64
	Label     string
}

// MetricHistory holds historical data for a specific metric
type MetricHistory struct {
	Name        string
	Unit        string
	MaxPoints   int
	DataPoints  []HistoricalDataPoint
	MinValue    float64
	MaxValue    float64
	LastUpdated time.Time
}

// HistoryManager manages historical data collection and storage
type HistoryManager struct {
	metrics         map[string]*MetricHistory
	retentionPeriod time.Duration
	cleanupInterval time.Duration
	lastCleanup     time.Time
}

// NewHistoryManager creates a new history manager
func NewHistoryManager() *HistoryManager {
	hm := &HistoryManager{
		metrics:         make(map[string]*MetricHistory),
		retentionPeriod: 12 * time.Hour,   // Keep 12 hours of data
		cleanupInterval: 30 * time.Minute, // Cleanup every 30 minutes
		lastCleanup:     time.Now(),
	}
	hm.initializeMetrics()
	return hm
}

// initializeMetrics sets up default metric histories
func (hm *HistoryManager) initializeMetrics() {
	metrics := []struct {
		name      string
		unit      string
		maxPoints int
	}{
		{"cpu_usage", "%", 720},            // 12 hours at 1-minute intervals
		{"memory_usage", "%", 720},         // 12 hours at 1-minute intervals
		{"load_average", "", 720},          // 12 hours at 1-minute intervals
		{"disk_usage", "%", 288},           // 12 hours at 2.5-minute intervals
		{"network_in", "MB/s", 720},        // 12 hours at 1-minute intervals
		{"network_out", "MB/s", 720},       // 12 hours at 1-minute intervals
		{"process_count", "count", 720},    // 12 hours at 1-minute intervals
		{"connection_count", "count", 720}, // 12 hours at 1-minute intervals
	}

	for _, metric := range metrics {
		hm.metrics[metric.name] = &MetricHistory{
			Name:        metric.name,
			Unit:        metric.unit,
			MaxPoints:   metric.maxPoints,
			DataPoints:  make([]HistoricalDataPoint, 0, metric.maxPoints),
			MinValue:    math.Inf(1),  // Positive infinity
			MaxValue:    math.Inf(-1), // Negative infinity
			LastUpdated: time.Now(),
		}
	}
}

// AddDataPoint adds a new data point to a metric's history
func (hm *HistoryManager) AddDataPoint(metricName string, value float64, timestamp time.Time) {
	metric, exists := hm.metrics[metricName]
	if !exists {
		return
	}

	dataPoint := HistoricalDataPoint{
		Timestamp: timestamp,
		Value:     value,
		Label:     fmt.Sprintf("%.2f", value),
	}

	// Add the data point
	metric.DataPoints = append(metric.DataPoints, dataPoint)

	// Update min/max values
	if value < metric.MinValue {
		metric.MinValue = value
	}
	if value > metric.MaxValue {
		metric.MaxValue = value
	}

	// Keep only the most recent points
	if len(metric.DataPoints) > metric.MaxPoints {
		metric.DataPoints = metric.DataPoints[1:]
	}

	metric.LastUpdated = timestamp

	// Perform cleanup if needed
	if time.Since(hm.lastCleanup) > hm.cleanupInterval {
		hm.cleanup()
	}
}

// cleanup removes old data points beyond the retention period
func (hm *HistoryManager) cleanup() {
	cutoff := time.Now().Add(-hm.retentionPeriod)

	for _, metric := range hm.metrics {
		// Find the first data point within retention period
		cutoffIndex := 0
		for i, point := range metric.DataPoints {
			if point.Timestamp.After(cutoff) {
				cutoffIndex = i
				break
			}
		}

		// Remove old data points
		if cutoffIndex > 0 {
			metric.DataPoints = metric.DataPoints[cutoffIndex:]

			// Recalculate min/max values
			metric.MinValue = math.Inf(1)
			metric.MaxValue = math.Inf(-1)
			for _, point := range metric.DataPoints {
				if point.Value < metric.MinValue {
					metric.MinValue = point.Value
				}
				if point.Value > metric.MaxValue {
					metric.MaxValue = point.Value
				}
			}
		}
	}

	hm.lastCleanup = time.Now()
}

// GetMetricHistory returns the history for a specific metric
func (hm *HistoryManager) GetMetricHistory(metricName string) *MetricHistory {
	if metric, exists := hm.metrics[metricName]; exists {
		// Return a copy to prevent external modification
		historyCopy := &MetricHistory{
			Name:        metric.Name,
			Unit:        metric.Unit,
			MaxPoints:   metric.MaxPoints,
			DataPoints:  make([]HistoricalDataPoint, len(metric.DataPoints)),
			MinValue:    metric.MinValue,
			MaxValue:    metric.MaxValue,
			LastUpdated: metric.LastUpdated,
		}
		copy(historyCopy.DataPoints, metric.DataPoints)
		return historyCopy
	}
	return nil
}

// GetAllMetrics returns a list of all available metric names
func (hm *HistoryManager) GetAllMetrics() []string {
	metrics := make([]string, 0, len(hm.metrics))
	for name := range hm.metrics {
		metrics = append(metrics, name)
	}
	sort.Strings(metrics)
	return metrics
}

// UpdateSystemMetrics updates historical data with current system metrics
func (hm *HistoryManager) UpdateSystemMetrics(stats SystemStats, processes []Process, connections []NetworkConnection, interfaces []NetworkInterface) {
	now := time.Now()

	// CPU usage (average)
	if len(stats.CPUUsage) > 0 {
		avgCPU := 0.0
		for _, usage := range stats.CPUUsage {
			avgCPU += usage
		}
		avgCPU /= float64(len(stats.CPUUsage))
		hm.AddDataPoint("cpu_usage", avgCPU, now)
	}

	// Memory usage
	if stats.MemTotal > 0 {
		memUsage := float64(stats.MemUsed) / float64(stats.MemTotal) * 100
		hm.AddDataPoint("memory_usage", memUsage, now)
	}

	// Load average
	hm.AddDataPoint("load_average", stats.LoadAvg[0], now)

	// Process count
	hm.AddDataPoint("process_count", float64(len(processes)), now)

	// Connection count
	hm.AddDataPoint("connection_count", float64(len(connections)), now)

	// Network throughput (simplified - would need rate calculation for real implementation)
	totalBytesIn := uint64(0)
	totalBytesOut := uint64(0)
	for _, iface := range interfaces {
		totalBytesIn += iface.BytesIn
		totalBytesOut += iface.BytesOut
	}

	// Convert to MB/s (this is simplified - real implementation would track deltas)
	hm.AddDataPoint("network_in", float64(totalBytesIn)/(1024*1024), now)
	hm.AddDataPoint("network_out", float64(totalBytesOut)/(1024*1024), now)
}

// Message types for system monitor
type (
	processDataMsg struct {
		processes   []Process
		systemStats SystemStats
		lastUpdate  time.Time
	}

	networkDataMsg struct {
		connections []NetworkConnection
		interfaces  []NetworkInterface
		lastUpdate  time.Time
	}

	alertDataMsg struct {
		alerts     []SystemAlert
		lastUpdate time.Time
	}
)

// NewSystemMonitorModel creates a new system monitor component
func NewSystemMonitorModel() *SystemMonitorModel {
	numCores := runtime.NumCPU()

	sm := &SystemMonitorModel{
		active:         false,
		sortColumn:     "CPU",
		sortReverse:    true,
		selectedRow:    0,
		scrollOffset:   0,
		cpuHistory:     make([][]float64, numCores),
		memHistory:     make([]float64, 60),
		bandwidthIn:    make([]float64, 60),
		bandwidthOut:   make([]float64, 60),
		networkTraffic: make([]float64, 60),
		orbs:           make([]orb, 8),
		lightRays:      make([]lightRay, 12),
		matrixRain:     make([]matrixDrop, 20),
		energyField:    make([]energyNode, 15),
		glowIntensity:  0.5,
		pulsePhase:     0,
		alertManager:   NewAlertManager(),
		historyManager: NewHistoryManager(),
	}

	// Initialize CPU history
	for i := range sm.cpuHistory {
		sm.cpuHistory[i] = make([]float64, 60)
	}

	// Initialize visual effects
	sm.initializeVisualEffects()

	return sm
}

// ToolComponent interface implementation

// Init initializes the system monitor component
func (sm *SystemMonitorModel) Init() tea.Cmd {
	return tea.Batch(
		sm.fetchProcessesCmd(),
		sm.fetchNetworkDataCmd(),
		sm.fetchSystemAlertsCmd(),
		sm.tickCmd(),
	)
}

// Update handles messages for the system monitor
func (sm *SystemMonitorModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case tea.KeyMsg:
		if !sm.active {
			return sm, nil
		}

		if cmd := sm.handleKeyMsg(msg); cmd != nil {
			cmds = append(cmds, cmd)
		}

	case processDataMsg:
		sm.updateProcessData(msg)

	case networkDataMsg:
		sm.updateNetworkData(msg)

	case alertDataMsg:
		sm.updateAlertData(msg)

	case tickMsg:
		sm.updateVisualEffects()

		// Fetch new data periodically
		if sm.frame%40 == 0 { // 2 seconds
			cmds = append(cmds, sm.fetchProcessesCmd())
		}
		if sm.frame%50 == 0 { // 2.5 seconds
			cmds = append(cmds, sm.fetchNetworkDataCmd())
		}
		if sm.frame%80 == 0 { // 4 seconds
			cmds = append(cmds, sm.fetchSystemAlertsCmd())
		}

		cmds = append(cmds, sm.tickCmd())
	}

	return sm, tea.Batch(cmds...)
}

