// Helper methods

// handleKeyMsg processes key messages for the system monitor
func (sm *SystemMonitorModel) handleKeyMsg(msg tea.KeyMsg) tea.Cmd {
	if sm.showKillDialog {
		switch msg.String() {
		case "y", "Y":
			sm.killProcess(sm.killPID)
			sm.showKillDialog = false
			return sm.fetchProcessesCmd()
		case "n", "N", "esc":
			sm.showKillDialog = false
			return nil
		}
		return nil
	}

	if sm.searchMode {
		switch msg.String() {
		case "esc":
			sm.searchMode = false
			sm.searchQuery = ""
			sm.filteredProcs = sm.processes
			return nil
		case "enter":
			sm.searchMode = false
			return nil
		case "backspace":
			if len(sm.searchQuery) > 0 {
				sm.searchQuery = sm.searchQuery[:len(sm.searchQuery)-1]
				sm.filteredProcs = sm.filterProcesses(sm.processes, sm.searchQuery)
			}
			return nil
		default:
			if len(msg.String()) == 1 {
				sm.searchQuery += msg.String()
				sm.filteredProcs = sm.filterProcesses(sm.processes, sm.searchQuery)
			}
			return nil
		}
	}

	switch msg.String() {
	case "k":
		if len(sm.filteredProcs) > 0 && sm.selectedRow < len(sm.filteredProcs) {
			sm.killPID = sm.filteredProcs[sm.selectedRow].PID
			sm.showKillDialog = true
		}
		return nil

	case "/":
		sm.searchMode = true
		sm.searchQuery = ""
		return nil

	case "up", "j":
		if sm.selectedRow > 0 {
			sm.selectedRow--
			if sm.selectedRow < sm.scrollOffset {
				sm.scrollOffset = sm.selectedRow
			}
		}
		return nil

	case "down":
		if sm.selectedRow < len(sm.filteredProcs)-1 {
			sm.selectedRow++
			visibleRows := sm.height - 15
			if sm.selectedRow >= sm.scrollOffset+visibleRows {
				sm.scrollOffset = sm.selectedRow - visibleRows + 1
			}
		}
		return nil

	case "c":
		sm.sortColumn = string(SortByCPU)
		sm.sortProcesses()
		return nil

	case "m":
		sm.sortColumn = string(SortByMemory)
		sm.sortProcesses()
		return nil

	case "p":
		sm.sortColumn = string(SortByPID)
		sm.sortProcesses()
		return nil

	case "n":
		sm.sortColumn = string(SortByName)
		sm.sortProcesses()
		return nil

	case "u":
		sm.sortColumn = string(SortByUser)
		sm.sortProcesses()
		return nil

	case "s":
		sm.sortColumn = string(SortByState)
		sm.sortProcesses()
		return nil

	case "t":
		sm.sortColumn = string(SortByThreads)
		sm.sortProcesses()
		return nil

	case "r":
		sm.sortColumn = string(SortByRuntime)
		sm.sortProcesses()
		return nil

	case "R":
		// Toggle sort direction
		sm.sortReverse = !sm.sortReverse
		sm.sortProcesses()
		return nil

	case "A":
		// Show alert management interface
		return sm.showAlertManagement()

	case "T":
		// Show threshold configuration
		return sm.showThresholdConfig()

	case "H":
		// Show alert history
		return sm.showAlertHistory()
	}

	return nil
}

