// Data update methods

// updateProcessData updates process and system stats data
func (sm *SystemMonitorModel) updateProcessData(msg processDataMsg) {
	sm.processes = msg.processes
	sm.systemStats = msg.systemStats

	// Update historical data using the history manager
	sm.historyManager.UpdateSystemMetrics(sm.systemStats, sm.processes, sm.connections, sm.interfaces)

	// Update legacy histories for backward compatibility
	for i, usage := range msg.systemStats.CPUUsage {
		if i < len(sm.cpuHistory) {
			sm.cpuHistory[i] = append(sm.cpuHistory[i][1:], usage)
		}
	}

	memUsagePercent := float64(msg.systemStats.MemUsed) / float64(msg.systemStats.MemTotal) * 100
	sm.memHistory = append(sm.memHistory[1:], memUsagePercent)

	sm.sortProcesses()
	sm.filteredProcs = sm.filterProcesses(sm.processes, sm.searchQuery)

	if sm.selectedRow >= len(sm.filteredProcs) {
		sm.selectedRow = max(0, len(sm.filteredProcs)-1)
	}
}

// updateNetworkData updates network connection and interface data
func (sm *SystemMonitorModel) updateNetworkData(msg networkDataMsg) {
	sm.connections = msg.connections
	sm.interfaces = msg.interfaces

	// Update network traffic history
	totalTraffic := 0.0
	for _, iface := range sm.interfaces {
		totalTraffic += float64(iface.BytesIn+iface.BytesOut) / 1024 / 1024 // MB
	}
	sm.networkTraffic = append(sm.networkTraffic[1:], totalTraffic)
}

// updateAlertData updates system alerts data
func (sm *SystemMonitorModel) updateAlertData(msg alertDataMsg) {
	sm.alerts = msg.alerts
}

// Visual effects methods

// updateVisualEffects updates the visual effects state
func (sm *SystemMonitorModel) updateVisualEffects() {
	sm.frame++
	sm.pulsePhase += 0.05
	sm.glowIntensity = 0.3 + 0.2*math.Sin(sm.pulsePhase)

	// Update orbs
	for i := range sm.orbs {
		orb := &sm.orbs[i]
		orb.x += orb.vx
		orb.y += orb.vy

		// Gentle bouncing
		if orb.x <= 0 || orb.x >= float64(sm.width) {
			orb.vx *= -0.8
			orb.x = math.Max(0, math.Min(float64(sm.width), orb.x))
		}
		if orb.y <= 0 || orb.y >= float64(sm.height) {
			orb.vy *= -0.8
			orb.y = math.Max(0, math.Min(float64(sm.height), orb.y))
		}

		orb.intensity = 0.3 + 0.5*math.Sin(float64(sm.frame)*0.02*orb.pulsePeriod+orb.pulseOffset)
	}

	// Update light rays
	for i := range sm.lightRays {
		ray := &sm.lightRays[i]
		ray.angle += 0.01
		ray.intensity = 0.2 + 0.4*math.Sin(float64(sm.frame)*0.03+float64(i))
	}

	// Update matrix rain
	for i := range sm.matrixRain {
		drop := &sm.matrixRain[i]
		drop.y += drop.speed
		if drop.y > float64(sm.height) {
			drop.y = -float64(drop.length)
			drop.x = float64(sm.width * int(drop.x) / sm.width) // Keep within bounds
		}
	}

	// Update energy field
	for i := range sm.energyField {
		node := &sm.energyField[i]
		node.pulsePhase += 0.02
		node.energy = 0.4 + 0.4*math.Sin(node.pulsePhase)
	}
}

// initializeVisualEffects sets up the visual effects
func (sm *SystemMonitorModel) initializeVisualEffects() {
	// Initialize orbs with elegant colors
	colors := []lipgloss.Color{
		lipgloss.Color("#6366f1"), // primary
		lipgloss.Color("#8b5cf6"), // secondary
		lipgloss.Color("#06b6d4"), // accent
		lipgloss.Color("#10b981"), // success
		lipgloss.Color("#f59e0b"), // warning
	}

	for i := range sm.orbs {
		sm.orbs[i] = orb{
			x:           float64(i * 15), // Spread them out initially
			y:           float64(i * 5),
			vx:          (float64(i%2)*2 - 1) * 0.2,
			vy:          (float64(i%3)*2 - 1) * 0.15,
			radius:      2.0 + float64(i%3),
			intensity:   0.5,
			color:       colors[i%len(colors)],
			pulsePeriod: 2.0 + float64(i%4),
			pulseOffset: float64(i) * 1.57, // π/2 offset
		}
	}

	// Initialize other effects similarly...
	// (Simplified for brevity - full implementation would include all effects)
}

// Helper function for max
func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

// Helper function for min
func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

// Rendering methods for historical data visualization

// renderHistoricalOverview renders a compact overview of historical metrics with sparklines
func (sm *SystemMonitorModel) renderHistoricalOverview() string {
	var s strings.Builder

	title := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Render("📊 HISTORICAL METRICS")
	s.WriteString(title + "\n\n")

	// Key metrics to display
	metrics := []struct {
		name  string
		label string
		unit  string
		color lipgloss.Color
	}{
		{"cpu_usage", "CPU Usage", "%", lipgloss.Color("#ef4444")},
		{"memory_usage", "Memory Usage", "%", lipgloss.Color("#f59e0b")},
		{"load_average", "Load Average", "", lipgloss.Color("#06b6d4")},
		{"process_count", "Process Count", "", lipgloss.Color("#10b981")},
		{"connection_count", "Network Connections", "", lipgloss.Color("#8b5cf6")},
	}

	for _, metric := range metrics {
		history := sm.historyManager.GetMetricHistory(metric.name)
		if history == nil || len(history.DataPoints) == 0 {
			continue
		}

		// Get latest value
		latest := history.DataPoints[len(history.DataPoints)-1]

		// Create sparkline
		sparkline := sm.renderSparkline(metric.name, 30)

		// Format the metric line
		labelStyle := lipgloss.NewStyle().
			Foreground(metric.color).
			Bold(true).
			Width(18)

		valueStyle := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#e2e8f0")).
			Width(10)

		sparklineStyle := lipgloss.NewStyle().
			Foreground(metric.color)

		line := fmt.Sprintf("%s %s %s %s",
			labelStyle.Render(metric.label+":"),
			valueStyle.Render(fmt.Sprintf("%.1f%s", latest.Value, metric.unit)),
			sparklineStyle.Render(sparkline),
			lipgloss.NewStyle().Foreground(lipgloss.Color("#94a3b8")).Render(
				fmt.Sprintf("(%.1f-%.1f)", history.MinValue, history.MaxValue)))

		s.WriteString(line + "\n")
	}

	return s.String()
}

// renderSparkline creates a sparkline chart for a metric
func (sm *SystemMonitorModel) renderSparkline(metricName string, width int) string {
	history := sm.historyManager.GetMetricHistory(metricName)
	if history == nil || len(history.DataPoints) == 0 {
		return strings.Repeat("▁", width)
	}

	// Sample data points to fit the width
	dataPoints := sm.sampleDataPoints(history.DataPoints, width)

	// Sparkline characters from lowest to highest
	sparkChars := []string{"▁", "▂", "▃", "▄", "▅", "▆", "▇", "█"}

	var sparkline strings.Builder

	// Calculate range for normalization
	minVal := history.MinValue
	maxVal := history.MaxValue
	if minVal == maxVal {
		maxVal = minVal + 1 // Avoid division by zero
	}

	for _, point := range dataPoints {
		// Normalize value to 0-7 range for sparkline characters
		normalized := (point.Value - minVal) / (maxVal - minVal)
		index := int(normalized * float64(len(sparkChars)-1))
		if index < 0 {
			index = 0
		}
		if index >= len(sparkChars) {
			index = len(sparkChars) - 1
		}
		sparkline.WriteString(sparkChars[index])
	}

	return sparkline.String()
}

// sampleDataPoints samples data points to fit a target width
func (sm *SystemMonitorModel) sampleDataPoints(dataPoints []HistoricalDataPoint, targetWidth int) []HistoricalDataPoint {
	if len(dataPoints) <= targetWidth {
		return dataPoints
	}

	sampled := make([]HistoricalDataPoint, targetWidth)
	step := float64(len(dataPoints)) / float64(targetWidth)

	for i := 0; i < targetWidth; i++ {
		index := int(float64(i) * step)
		if index >= len(dataPoints) {
			index = len(dataPoints) - 1
		}
		sampled[i] = dataPoints[index]
	}

	return sampled
}

// renderASCIIChart renders a full ASCII chart for a specific metric
func (sm *SystemMonitorModel) renderASCIIChart(metricName string, width, height int) string {
	history := sm.historyManager.GetMetricHistory(metricName)
	if history == nil || len(history.DataPoints) == 0 {
		return sm.renderNoDataChart(metricName, width, height)
	}

	return sm.createASCIIChart(history, width, height)
}

// renderNoDataChart renders a chart when no data is available
func (sm *SystemMonitorModel) renderNoDataChart(metricName string, width, height int) string {
	var s strings.Builder

	title := strings.Title(strings.ReplaceAll(metricName, "_", " "))
	titleStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Align(lipgloss.Center).
		Width(width)

	s.WriteString(titleStyle.Render(title) + "\n")
	s.WriteString(strings.Repeat("─", width) + "\n")

	// Center the "No data available" message
	noDataMsg := "No data available"
	padding := (width - len(noDataMsg)) / 2
	if padding < 0 {
		padding = 0
	}

	for i := 0; i < height-4; i++ {
		if i == height/2-2 {
			s.WriteString(strings.Repeat(" ", padding) + noDataMsg + "\n")
		} else {
			s.WriteString("\n")
		}
	}

	s.WriteString(strings.Repeat("─", width))

	return s.String()
}

// createASCIIChart creates a detailed ASCII chart from historical data
func (sm *SystemMonitorModel) createASCIIChart(history *MetricHistory, width, height int) string {
	var s strings.Builder

	// Title
	title := strings.Title(strings.ReplaceAll(history.Name, "_", " "))
	titleStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Align(lipgloss.Center).
		Width(width)

	s.WriteString(titleStyle.Render(title) + "\n")

	// Chart area dimensions (leave space for title, axes, and labels)
	chartWidth := width - 10  // Leave space for Y-axis labels
	chartHeight := height - 6 // Leave space for title and X-axis

	if chartWidth < 10 || chartHeight < 3 {
		return sm.renderNoDataChart(history.Name, width, height)
	}

	// Sample data to fit chart width
	dataPoints := sm.sampleDataPoints(history.DataPoints, chartWidth)

	// Calculate value range
	minVal := history.MinValue
	maxVal := history.MaxValue
	if minVal == maxVal {
		maxVal = minVal + 1
	}

	// Create chart grid
	chart := make([][]string, chartHeight)
	for i := range chart {
		chart[i] = make([]string, chartWidth)
		for j := range chart[i] {
			chart[i][j] = " "
		}
	}

	// Plot data points
	for i, point := range dataPoints {
		if i >= chartWidth {
			break
		}

		// Normalize value to chart height
		normalized := (point.Value - minVal) / (maxVal - minVal)
		y := int(float64(chartHeight-1) * (1.0 - normalized)) // Invert Y axis

		if y < 0 {
			y = 0
		}
		if y >= chartHeight {
			y = chartHeight - 1
		}

		// Use different characters for different intensities
		chart[y][i] = "█"

		// Add connecting line to previous point if possible
		if i > 0 {
			prevNormalized := (dataPoints[i-1].Value - minVal) / (maxVal - minVal)
			prevY := int(float64(chartHeight-1) * (1.0 - prevNormalized))

			if prevY < 0 {
				prevY = 0
			}
			if prevY >= chartHeight {
				prevY = chartHeight - 1
			}

			// Draw connecting line
			startY := prevY
			endY := y
			if startY > endY {
				startY, endY = endY, startY
			}

			for lineY := startY; lineY <= endY; lineY++ {
				if chart[lineY][i-1] == " " {
					if lineY == startY || lineY == endY {
						chart[lineY][i-1] = "▆"
					} else {
						chart[lineY][i-1] = "▄"
					}
				}
			}
		}
	}

	// Render the chart
	s.WriteString("┌" + strings.Repeat("─", chartWidth) + "┐\n")

	for i, row := range chart {
		// Y-axis label
		progress := float64(i) / float64(chartHeight-1)
		value := maxVal - (progress * (maxVal - minVal))
		label := fmt.Sprintf("%6.1f", value)

		s.WriteString(label + "│")
		for _, cell := range row {
			s.WriteString(cell)
		}
		s.WriteString("│\n")
	}

	s.WriteString("└" + strings.Repeat("─", chartWidth) + "┘\n")

	// X-axis labels (time)
	if len(dataPoints) > 0 {
		firstTime := dataPoints[0].Timestamp.Format("15:04")
		lastTime := dataPoints[len(dataPoints)-1].Timestamp.Format("15:04")

		timeLabel := fmt.Sprintf("%s%s%s",
			firstTime,
			strings.Repeat(" ", chartWidth-len(firstTime)-len(lastTime)),
			lastTime)

		s.WriteString("        " + timeLabel + "\n")
	}

	// Chart info
	infoStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Align(lipgloss.Center).
		Width(width)

	info := fmt.Sprintf("Range: %.1f - %.1f %s | Points: %d | Updated: %s",
		history.MinValue, history.MaxValue, history.Unit,
		len(history.DataPoints), history.LastUpdated.Format("15:04:05"))

	s.WriteString(infoStyle.Render(info))

	return s.String()
}

