// renderElegantBar renders a progress bar with gradient colors
func (sm *SystemMonitorModel) renderElegantBar(value, max float64, width int, lowColor, highColor lipgloss.Color) string {
	if max == 0 {
		return ""
	}

	ratio := value / max
	filled := int(ratio * float64(width))
	if filled > width {
		filled = width
	}

	// Create gradient effect
	var segments []string
	for i := 0; i < width; i++ {
		if i < filled {
			if ratio > 0.7 {
				segments = append(segments, lipgloss.NewStyle().Foreground(highColor).Render("█"))
			} else if ratio > 0.4 {
				segments = append(segments, lipgloss.NewStyle().Foreground(lipgloss.Color("#f59e0b")).Render("█"))
			} else {
				segments = append(segments, lipgloss.NewStyle().Foreground(lowColor).Render("█"))
			}
		} else {
			segments = append(segments, lipgloss.NewStyle().Foreground(lipgloss.Color("#64748b")).Render("░"))
		}
	}

	return strings.Join(segments, "")
}

// formatBytes formats byte values in human-readable format
func (sm *SystemMonitorModel) formatBytes(bytes uint64) string {
	const unit = 1024
	if bytes < unit {
		return fmt.Sprintf("%d B", bytes)
	}
	div, exp := int64(unit), 0
	for n := bytes / unit; n >= unit; n /= unit {
		div *= unit
		exp++
	}
	return fmt.Sprintf("%.1f %cB", float64(bytes)/float64(div), "KMGTPE"[exp])
}

