// getProcesses retrieves the current process list with enhanced information
func (sm *SystemMonitorModel) getProcesses() []Process {
	var processes []Process

	// Use ps command to get comprehensive process information
	// Include additional fields: priority, nice, threads, rss, vsz, etime
	cmd := exec.Command("ps", "axo", "pid,user,pcpu,pmem,stat,ppid,lstart,comm,command,pri,nice,nlwp,rss,vsz,etime")
	output, err := cmd.Output()
	if err != nil {
		// Fallback to basic ps command if extended format fails
		return sm.getBasicProcesses()
	}

	lines := strings.Split(string(output), "\n")
	for i, line := range lines {
		if i == 0 || line == "" { // Skip header and empty lines
			continue
		}

		fields := strings.Fields(line)
		if len(fields) < 15 {
			continue
		}

		pid, _ := strconv.Atoi(fields[0])
		cpu, _ := strconv.ParseFloat(fields[2], 64)
		memory, _ := strconv.ParseFloat(fields[3], 64)
		ppid, _ := strconv.Atoi(fields[5])
		priority, _ := strconv.Atoi(fields[9])
		nice, _ := strconv.Atoi(fields[10])
		threads, _ := strconv.Atoi(fields[11])
		rss, _ := strconv.ParseUint(fields[12], 10, 64)
		vsz, _ := strconv.ParseUint(fields[13], 10, 64)

		// Parse runtime from etime field
		runtime := sm.parseElapsedTime(fields[14])

		// Join command parts (everything after field 14)
		command := strings.Join(fields[8:9], " ") // Just the command part
		if len(fields) > 15 {
			command = strings.Join(fields[15:], " ") // Full command line
		}
		if len(command) > 200 {
			command = command[:197] + "..."
		}

		process := Process{
			PID:         pid,
			User:        fields[1],
			CPU:         cpu,
			Memory:      memory,
			State:       fields[4],
			PPID:        ppid,
			StartTime:   strings.Join(fields[6:8], " "),
			Name:        fields[7],
			Command:     command,
			Priority:    priority,
			Nice:        nice,
			Threads:     threads,
			MemoryRSS:   rss * 1024, // Convert KB to bytes
			MemoryVSZ:   vsz * 1024, // Convert KB to bytes
			Runtime:     runtime,
			Environment: make(map[string]string),
			OpenFiles:   []string{},
		}

		// Get additional detailed information for selected processes
		if sm.shouldGetDetailedInfo(process) {
			sm.enrichProcessInfo(&process)
		}

		processes = append(processes, process)
	}

	return processes
}

