// shouldGetDetailedInfo determines if we should fetch detailed info for a process
func (sm *SystemMonitorModel) shouldGetDetailedInfo(proc Process) bool {
	// Get detailed info for:
	// 1. Currently selected process
	// 2. High CPU/memory usage processes
	// 3. Processes matching current search

	if len(sm.filteredProcs) > 0 && sm.selectedRow < len(sm.filteredProcs) {
		if sm.filteredProcs[sm.selectedRow].PID == proc.PID {
			return true
		}
	}

	// High resource usage
	if proc.CPU > 10.0 || proc.Memory > 5.0 {
		return true
	}

	// Matches current search
	if sm.searchQuery != "" && sm.matchesFilter(proc, strings.ToLower(sm.searchQuery)) {
		return true
	}

	return false
}

// enrichProcessInfo adds detailed information to a process
func (sm *SystemMonitorModel) enrichProcessInfo(proc *Process) {
	// Get working directory
	if wd := sm.getProcessWorkingDir(proc.PID); wd != "" {
		proc.WorkingDir = wd
	}

	// Get environment variables (limited to avoid performance issues)
	if env := sm.getProcessEnvironment(proc.PID); len(env) > 0 {
		proc.Environment = env
	}

	// Get open files (limited to first 10 to avoid performance issues)
	if files := sm.getProcessOpenFiles(proc.PID); len(files) > 0 {
		proc.OpenFiles = files
	}
}

// parseElapsedTime parses the elapsed time format from ps etime field
func (sm *SystemMonitorModel) parseElapsedTime(etime string) time.Duration {
	// etime format can be: "mm:ss", "hh:mm:ss", "dd-hh:mm:ss"

	if strings.Contains(etime, "-") {
		// Format: dd-hh:mm:ss
		parts := strings.Split(etime, "-")
		if len(parts) == 2 {
			days, _ := strconv.Atoi(parts[0])
			timePart := parts[1]
			if duration := sm.parseTimeOnly(timePart); duration > 0 {
				return time.Duration(days)*24*time.Hour + duration
			}
		}
	} else {
		// Format: hh:mm:ss or mm:ss
		return sm.parseTimeOnly(etime)
	}

	return 0
}

// parseTimeOnly parses time in hh:mm:ss or mm:ss format
func (sm *SystemMonitorModel) parseTimeOnly(timeStr string) time.Duration {
	parts := strings.Split(timeStr, ":")

	if len(parts) == 2 {
		// mm:ss format
		minutes, _ := strconv.Atoi(parts[0])
		seconds, _ := strconv.Atoi(parts[1])
		return time.Duration(minutes)*time.Minute + time.Duration(seconds)*time.Second
	} else if len(parts) == 3 {
		// hh:mm:ss format
		hours, _ := strconv.Atoi(parts[0])
		minutes, _ := strconv.Atoi(parts[1])
		seconds, _ := strconv.Atoi(parts[2])
		return time.Duration(hours)*time.Hour + time.Duration(minutes)*time.Minute + time.Duration(seconds)*time.Second
	}

	return 0
}

// getProcessWorkingDir gets the working directory of a process
func (sm *SystemMonitorModel) getProcessWorkingDir(pid int) string {
	if runtime.GOOS == "darwin" {
		// On macOS, use lsof to get working directory
		cmd := exec.Command("lsof", "-p", fmt.Sprintf("%d", pid), "-d", "cwd", "-Fn")
		output, err := cmd.Output()
		if err != nil {
			return ""
		}

		lines := strings.Split(string(output), "\n")
		for _, line := range lines {
			if strings.HasPrefix(line, "n") {
				return line[1:] // Remove 'n' prefix
			}
		}
	} else {
		// On Linux, read /proc/PID/cwd symlink
		link := fmt.Sprintf("/proc/%d/cwd", pid)
		if wd, err := os.Readlink(link); err == nil {
			return wd
		}
	}
	return ""
}

// getProcessEnvironment gets environment variables for a process (limited set)
func (sm *SystemMonitorModel) getProcessEnvironment(pid int) map[string]string {
	env := make(map[string]string)

	if runtime.GOOS == "darwin" {
		// On macOS, use ps to get environment (limited)
		cmd := exec.Command("ps", "eww", fmt.Sprintf("%d", pid))
		output, err := cmd.Output()
		if err != nil {
			return env
		}

		// Parse environment variables from ps output
		lines := strings.Split(string(output), "\n")
		if len(lines) > 1 {
			// Extract environment variables from the command line
			parts := strings.Fields(lines[1])
			for _, part := range parts {
				if strings.Contains(part, "=") {
					kv := strings.SplitN(part, "=", 2)
					if len(kv) == 2 {
						env[kv[0]] = kv[1]
					}
				}
			}
		}
	} else {
		// On Linux, read /proc/PID/environ
		envFile := fmt.Sprintf("/proc/%d/environ", pid)
		if data, err := os.ReadFile(envFile); err == nil {
			// Environment variables are null-separated
			vars := strings.Split(string(data), "\x00")
			for _, v := range vars {
				if strings.Contains(v, "=") {
					kv := strings.SplitN(v, "=", 2)
					if len(kv) == 2 {
						env[kv[0]] = kv[1]
					}
				}
			}
		}
	}

	// Limit to important environment variables to avoid clutter
	important := []string{"HOME", "PATH", "USER", "SHELL", "DISPLAY", "LANG"}
	filtered := make(map[string]string)
	for _, key := range important {
		if value, exists := env[key]; exists {
			filtered[key] = value
		}
	}

	return filtered
}

// getProcessOpenFiles gets open files for a process (limited set)
func (sm *SystemMonitorModel) getProcessOpenFiles(pid int) []string {
	var files []string

	// Use lsof to get open files (works on both macOS and Linux)
	cmd := exec.Command("lsof", "-p", fmt.Sprintf("%d", pid), "-Fn")
	output, err := cmd.Output()
	if err != nil {
		return files
	}

	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.HasPrefix(line, "n") && len(line) > 1 {
			filename := line[1:] // Remove 'n' prefix
			// Filter out common system files and focus on user files
			if sm.isInterestingFile(filename) {
				files = append(files, filename)
			}
		}

		// Limit to first 10 files to avoid performance issues
		if len(files) >= 10 {
			break
		}
	}

	return files
}

// isInterestingFile determines if a file is worth showing in the process details
func (sm *SystemMonitorModel) isInterestingFile(filename string) bool {
	// Skip common system files and focus on user-relevant files
	skipPrefixes := []string{
		"/dev/",
		"/proc/",
		"/sys/",
		"/usr/lib/",
		"/lib/",
		"/System/Library/", // macOS
	}

	for _, prefix := range skipPrefixes {
		if strings.HasPrefix(filename, prefix) {
			return false
		}
	}

	// Include files in user directories, config files, and data files
	interestingPrefixes := []string{
		"/home/",
		"/Users/", // macOS
		"/tmp/",
		"/var/log/",
		"/etc/",
	}

	for _, prefix := range interestingPrefixes {
		if strings.HasPrefix(filename, prefix) {
			return true
		}
	}

	// Include files with interesting extensions
	interestingExtensions := []string{
		".log", ".conf", ".cfg", ".ini", ".json", ".xml", ".yaml", ".yml",
		".txt", ".md", ".pdf", ".doc", ".docx", ".xls", ".xlsx",
		".db", ".sqlite", ".sql",
	}

	for _, ext := range interestingExtensions {
		if strings.HasSuffix(filename, ext) {
			return true
		}
	}

	return false
}

