// renderDetailedAlerts renders detailed alert information
func (sm *SystemMonitorModel) renderDetailedAlerts() string {
	activeAlerts := sm.alertManager.GetActiveAlerts()
	if len(activeAlerts) == 0 {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("#10b981")).
			Align(lipgloss.Center).
			Width(sm.width).
			Border(lipgloss.RoundedBorder()).
			BorderForeground(lipgloss.Color("#10b981")).
			Padding(2).
			Render("✓ No Active Alerts\n\nAll systems are operating within normal parameters")
	}

	var s strings.Builder

	title := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#f59e0b")).
		Bold(true).
		Render("⚠ ACTIVE SYSTEM ALERTS")
	s.WriteString(title + "\n\n")

	maxAlerts := min(len(activeAlerts), sm.height-10)
	for i := 0; i < maxAlerts; i++ {
		alert := activeAlerts[i]

		var levelColor lipgloss.Color
		var icon string

		switch alert.Level {
		case AlertLevelCritical:
			levelColor = lipgloss.Color("#ef4444")
			icon = "🔴"
		case AlertLevelWarning:
			levelColor = lipgloss.Color("#f59e0b")
			icon = "🟡"
		case AlertLevelError:
			levelColor = lipgloss.Color("#ef4444")
			icon = "🔴"
		case AlertLevelInfo:
			levelColor = lipgloss.Color("#06b6d4")
			icon = "🔵"
		default:
			levelColor = lipgloss.Color("#94a3b8")
			icon = "⚪"
		}

		timestamp := alert.Timestamp.Format("15:04:05")

		alertCard := lipgloss.NewStyle().
			Border(lipgloss.RoundedBorder()).
			BorderForeground(levelColor).
			Padding(1).
			Margin(0, 0, 1, 0).
			Width(sm.width - 4)

		header := lipgloss.JoinHorizontal(lipgloss.Left,
			lipgloss.NewStyle().Foreground(levelColor).Bold(true).Render(fmt.Sprintf("%s %s", icon, string(alert.Level))),
			lipgloss.NewStyle().Foreground(lipgloss.Color("#94a3b8")).Align(lipgloss.Right).Width(sm.width-20).Render(timestamp),
		)

		content := fmt.Sprintf("%s\n\n%s",
			header,
			lipgloss.NewStyle().Foreground(lipgloss.Color("#e2e8f0")).Render(alert.Message))

		if alert.Description != "" {
			content += "\n\n" + lipgloss.NewStyle().Foreground(lipgloss.Color("#94a3b8")).Render(alert.Description)
		}

		if len(alert.Actions) > 0 {
			content += "\n\nRecommended Actions:"
			for _, action := range alert.Actions {
				content += "\n• " + lipgloss.NewStyle().Foreground(lipgloss.Color("#06b6d4")).Render(action)
			}
		}

		content += fmt.Sprintf("\n\nSource: %s • Type: %s",
			lipgloss.NewStyle().Foreground(lipgloss.Color("#94a3b8")).Render(alert.Source),
			lipgloss.NewStyle().Foreground(lipgloss.Color("#94a3b8")).Render(string(alert.Type)))

		s.WriteString(alertCard.Render(content) + "\n")
	}

	return s.String()
}

