	}

	// Get CPU usage per core (simplified - would need more complex implementation for real per-core stats)
	stats.CPUUsage = make([]float64, stats.CPUCores)
	for i := range stats.CPUUsage {
		stats.CPUUsage[i] = float64(i*10 + sm.frame%20) // Placeholder - real implementation would read /proc/stat
	}

	// Get memory information (macOS specific using vm_stat)
	if runtime.GOOS == "darwin" {
		sm.getMacOSMemoryStats(&stats)
	} else {
		sm.getLinuxMemoryStats(&stats)
	}

	// Get load average
	sm.getLoadAverage(&stats)

	// Get uptime
	sm.getUptime(&stats)

	return stats
}

// getMacOSMemoryStats gets memory statistics on macOS
func (sm *SystemMonitorModel) getMacOSMemoryStats(stats *SystemStats) {
	cmd := exec.Command("vm_stat")
	output, err := cmd.Output()
	if err != nil {
		return
	}

	lines := strings.Split(string(output), "\n")
	var pageSize uint64 = 4096 // Default page size
	var freePages, activePages, inactivePages, wiredPages uint64

	for _, line := range lines {
		if strings.Contains(line, "page size of") {
			parts := strings.Fields(line)
			if len(parts) >= 8 {
				if size, err := strconv.ParseUint(parts[7], 10, 64); err == nil {
					pageSize = size
				}
			}
		} else if strings.Contains(line, "Pages free:") {
			parts := strings.Fields(line)
			if len(parts) >= 3 {
				if pages, err := strconv.ParseUint(strings.TrimSuffix(parts[2], "."), 10, 64); err == nil {
					freePages = pages
				}
			}
		} else if strings.Contains(line, "Pages active:") {
			parts := strings.Fields(line)
			if len(parts) >= 3 {
				if pages, err := strconv.ParseUint(strings.TrimSuffix(parts[2], "."), 10, 64); err == nil {
					activePages = pages
				}
			}
		} else if strings.Contains(line, "Pages inactive:") {
			parts := strings.Fields(line)
			if len(parts) >= 3 {
				if pages, err := strconv.ParseUint(strings.TrimSuffix(parts[2], "."), 10, 64); err == nil {
					inactivePages = pages
				}
			}
		} else if strings.Contains(line, "Pages wired down:") {
			parts := strings.Fields(line)
			if len(parts) >= 4 {
				if pages, err := strconv.ParseUint(strings.TrimSuffix(parts[3], "."), 10, 64); err == nil {
					wiredPages = pages
				}
			}
		}
	}

	totalPages := freePages + activePages + inactivePages + wiredPages
	usedPages := activePages + inactivePages + wiredPages

	stats.MemTotal = totalPages * pageSize
	stats.MemUsed = usedPages * pageSize
}

// getLinuxMemoryStats gets memory statistics on Linux
func (sm *SystemMonitorModel) getLinuxMemoryStats(stats *SystemStats) {
	// Read /proc/meminfo
	data, err := os.ReadFile("/proc/meminfo")
	if err != nil {
		return
	}

	lines := strings.Split(string(data), "\n")
	for _, line := range lines {
		fields := strings.Fields(line)
		if len(fields) < 2 {
			continue
		}

		value, err := strconv.ParseUint(fields[1], 10, 64)
		if err != nil {
			continue
		}

		// Convert from KB to bytes
		value *= 1024

		switch fields[0] {
		case "MemTotal:":
			stats.MemTotal = value
		case "MemAvailable:":
			stats.MemUsed = stats.MemTotal - value
		case "SwapTotal:":
			stats.SwapTotal = value
		case "SwapFree:":
			stats.SwapUsed = stats.SwapTotal - value
		}
	}
}

// getLoadAverage gets the system load average
func (sm *SystemMonitorModel) getLoadAverage(stats *SystemStats) {
	if runtime.GOOS == "darwin" {
		cmd := exec.Command("sysctl", "-n", "vm.loadavg")
		output, err := cmd.Output()
		if err != nil {
			return
		}

		// Parse output like "{ 1.23 2.34 3.45 }"
		line := strings.TrimSpace(string(output))
		line = strings.Trim(line, "{}")
		fields := strings.Fields(line)

		if len(fields) >= 3 {
			if load, err := strconv.ParseFloat(fields[0], 64); err == nil {
				stats.LoadAvg[0] = load
			}
			if load, err := strconv.ParseFloat(fields[1], 64); err == nil {
				stats.LoadAvg[1] = load
			}
			if load, err := strconv.ParseFloat(fields[2], 64); err == nil {
				stats.LoadAvg[2] = load
			}
		}
	} else {
		// Linux: read /proc/loadavg
		data, err := os.ReadFile("/proc/loadavg")
		if err != nil {
			return
		}

		fields := strings.Fields(string(data))
		if len(fields) >= 3 {
			if load, err := strconv.ParseFloat(fields[0], 64); err == nil {
				stats.LoadAvg[0] = load
			}
			if load, err := strconv.ParseFloat(fields[1], 64); err == nil {
				stats.LoadAvg[1] = load
			}
			if load, err := strconv.ParseFloat(fields[2], 64); err == nil {
				stats.LoadAvg[2] = load
			}
		}
	}
}

// getUptime gets the system uptime
func (sm *SystemMonitorModel) getUptime(stats *SystemStats) {
	if runtime.GOOS == "darwin" {
		cmd := exec.Command("sysctl", "-n", "kern.boottime")
		output, err := cmd.Output()
		if err != nil {
			return
		}

		// Parse output like "{ sec = 1234567890, usec = 123456 } ..."
		line := strings.TrimSpace(string(output))
		if strings.Contains(line, "sec = ") {
			start := strings.Index(line, "sec = ") + 6
			end := strings.Index(line[start:], ",")
			if end > 0 {
				if bootTime, err := strconv.ParseInt(line[start:start+end], 10, 64); err == nil {
					stats.Uptime = time.Since(time.Unix(bootTime, 0))
				}
			}
		}
	} else {
		// Linux: read /proc/uptime
		data, err := os.ReadFile("/proc/uptime")
		if err != nil {
			return
		}

		fields := strings.Fields(string(data))
		if len(fields) >= 1 {
			if uptime, err := strconv.ParseFloat(fields[0], 64); err == nil {
				stats.Uptime = time.Duration(uptime * float64(time.Second))
			}
		}
	}
}

// getNetworkConnections retrieves current network connections
func (sm *SystemMonitorModel) getNetworkConnections() []NetworkConnection {
	var connections []NetworkConnection

	// Use netstat to get network connections
	cmd := exec.Command("netstat", "-an")
	output, err := cmd.Output()
	if err != nil {
		return connections
	}

	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		fields := strings.Fields(line)
		if len(fields) < 6 {
			continue
		}

		// Skip header lines
		if fields[0] == "Proto" || fields[0] == "Active" {
			continue
		}

		protocol := fields[0]
		localAddr := fields[3]
		remoteAddr := fields[4]
		state := ""
		if len(fields) > 5 {
			state = fields[5]
		}

		// Parse addresses
		localParts := strings.Split(localAddr, ":")
		remoteParts := strings.Split(remoteAddr, ":")

		var localIP, localPort, remoteIP, remotePort string
		if len(localParts) >= 2 {
			localIP = strings.Join(localParts[:len(localParts)-1], ":")
			localPort = localParts[len(localParts)-1]
		}
		if len(remoteParts) >= 2 {
			remoteIP = strings.Join(remoteParts[:len(remoteParts)-1], ":")
			remotePort = remoteParts[len(remoteParts)-1]
		}

		connection := NetworkConnection{
			Protocol:    protocol,
			LocalAddr:   localIP,
			LocalPort:   localPort,
			RemoteAddr:  remoteIP,
			RemotePort:  remotePort,
			State:       state,
			PID:         0,  // Would need additional lookup
			ProcessName: "", // Would need additional lookup
		}

		connections = append(connections, connection)
	}

	return connections
}

// getNetworkInterfaces retrieves network interface statistics
func (sm *SystemMonitorModel) getNetworkInterfaces() []NetworkInterface {
	var interfaces []NetworkInterface

	if runtime.GOOS == "darwin" {
		// Use netstat -ib for interface statistics on macOS
		cmd := exec.Command("netstat", "-ib")
		output, err := cmd.Output()
		if err != nil {
			return interfaces
		}

		lines := strings.Split(string(output), "\n")
		for i, line := range lines {
			if i == 0 || line == "" { // Skip header
				continue
			}

			fields := strings.Fields(line)
			if len(fields) < 10 {
				continue
			}

			name := fields[0]
			if name == "Name" { // Skip header
				continue
			}

			bytesIn, _ := strconv.ParseUint(fields[6], 10, 64)
			bytesOut, _ := strconv.ParseUint(fields[9], 10, 64)
			packetsIn, _ := strconv.ParseUint(fields[4], 10, 64)
			packetsOut, _ := strconv.ParseUint(fields[7], 10, 64)

			iface := NetworkInterface{
				Name:       name,
				BytesIn:    bytesIn,
				BytesOut:   bytesOut,
				PacketsIn:  packetsIn,
				PacketsOut: packetsOut,
				Speed:      0, // Would need additional lookup
			}

			interfaces = append(interfaces, iface)
		}
	}

	return interfaces
}

// AlertManager methods

// CheckThresholds evaluates current system metrics against thresholds
func (am *AlertManager) CheckThresholds(stats SystemStats, processes []Process, connections []NetworkConnection) {
	now := time.Now()

	// Check CPU usage
	if len(stats.CPUUsage) > 0 {
		avgCPU := 0.0
		for _, usage := range stats.CPUUsage {
			avgCPU += usage
		}
		avgCPU /= float64(len(stats.CPUUsage))

		am.checkMetricThreshold("cpu_usage", AlertTypeCPU, avgCPU,
			am.thresholds.CPU.Warning, am.thresholds.CPU.Critical,
			"CPU Usage", "%", now)
	}

	// Check memory usage
	if stats.MemTotal > 0 {
		memUsage := float64(stats.MemUsed) / float64(stats.MemTotal) * 100
		am.checkMetricThreshold("memory_usage", AlertTypeMemory, memUsage,
			am.thresholds.Memory.Warning, am.thresholds.Memory.Critical,
			"Memory Usage", "%", now)
	}

	// Check load average
	loadAvg := stats.LoadAvg[0]
	am.checkMetricThreshold("load_average", AlertTypeSystem, loadAvg,
		am.thresholds.LoadAverage.Warning, am.thresholds.LoadAverage.Critical,
		"Load Average", "", now)

	// Check process count
	processCount := float64(len(processes))
	am.checkMetricThreshold("process_count", AlertTypeProcess, processCount,
		float64(am.thresholds.ProcessCount.Warning), float64(am.thresholds.ProcessCount.Critical),
		"Process Count", "processes", now)

	// Check network connections
	connectionCount := float64(len(connections))
	am.checkMetricThreshold("connection_count", AlertTypeNetwork, connectionCount,
		float64(am.thresholds.NetworkConnections.Warning), float64(am.thresholds.NetworkConnections.Critical),
		"Network Connections", "connections", now)

	// Check for zombie processes
	zombieCount := 0
	for _, proc := range processes {
		if proc.State == "Z" {
			zombieCount++
		}
	}
	if zombieCount > 0 {
		am.createAlert("zombie_processes", AlertTypeProcess, AlertLevelWarning,
			fmt.Sprintf("Found %d zombie processes", zombieCount),
			"Zombie processes indicate processes that have completed but haven't been cleaned up by their parent",
			float64(zombieCount), 0, "processes", now)
	}

	// Check for high memory processes
	for _, proc := range processes {
		if proc.Memory > 20.0 { // Process using more than 20% memory
			am.createAlert(fmt.Sprintf("high_memory_process_%d", proc.PID), AlertTypeProcess, AlertLevelWarning,
				fmt.Sprintf("Process %s (PID %d) using %.1f%% memory", proc.Name, proc.PID, proc.Memory),
				"High memory usage by individual process may indicate memory leak or inefficient resource usage",
				proc.Memory, 20.0, "%", now)
		}
	}
}

// checkMetricThreshold checks a metric against warning and critical thresholds
func (am *AlertManager) checkMetricThreshold(id string, alertType AlertType, value, warning, critical float64, name, unit string, timestamp time.Time) {
	var level AlertLevel
	var threshold float64
	var message string

	if value >= critical {
		level = AlertLevelCritical
		threshold = critical
		message = fmt.Sprintf("CRITICAL: %s is %.1f%s (threshold: %.1f%s)", name, value, unit, critical, unit)
	} else if value >= warning {
		level = AlertLevelWarning
		threshold = warning
		message = fmt.Sprintf("WARNING: %s is %.1f%s (threshold: %.1f%s)", name, value, unit, warning, unit)
	} else {
		// Value is below warning threshold, resolve any existing alert
		am.resolveAlert(id, timestamp)
		return
	}

	description := am.getAlertDescription(alertType, level)
	actions := am.getRecommendedActions(alertType, level)

	alert := &SystemAlert{
		ID:          id,
		Type:        alertType,
		Level:       level,
		Message:     message,
		Description: description,
		Timestamp:   timestamp,
		Source:      "SystemMonitor",
		Value:       value,
		Threshold:   threshold,
		Unit:        unit,
		Resolved:    false,
		Actions:     actions,
	}

	am.activeAlerts[id] = alert

	// Send notification
	select {
	case am.notifications <- *alert:
	default:
		// Channel full, skip notification
	}
}

// createAlert creates a new alert
func (am *AlertManager) createAlert(id string, alertType AlertType, level AlertLevel, message, description string, value, threshold float64, unit string, timestamp time.Time) {
	actions := am.getRecommendedActions(alertType, level)

	alert := &SystemAlert{
		ID:          id,
		Type:        alertType,
		Level:       level,
		Message:     message,
		Description: description,
		Timestamp:   timestamp,
		Source:      "SystemMonitor",
		Value:       value,
		Threshold:   threshold,
		Unit:        unit,
		Resolved:    false,
		Actions:     actions,
	}

	am.activeAlerts[id] = alert

	// Send notification
	select {
	case am.notifications <- *alert:
	default:
		// Channel full, skip notification
	}
}

// resolveAlert marks an alert as resolved
func (am *AlertManager) resolveAlert(id string, timestamp time.Time) {
	if alert, exists := am.activeAlerts[id]; exists {
		alert.Resolved = true
		alert.ResolvedAt = &timestamp

		// Move to history
		am.addToHistory(*alert)
		delete(am.activeAlerts, id)
	}
}

// addToHistory adds an alert to the history
func (am *AlertManager) addToHistory(alert SystemAlert) {
	am.alertHistory = append(am.alertHistory, alert)

	// Keep history size under limit
	if len(am.alertHistory) > am.maxHistory {
		am.alertHistory = am.alertHistory[1:]
	}
}

