			AlertLevelWarning:  "High system load detected. More processes are waiting for CPU time than available cores.",
			AlertLevelCritical: "Critical system load detected. System responsiveness is severely impacted.",
		},
		AlertTypeProcess: {
			AlertLevelWarning:  "Process-related issue detected. Individual process may be consuming excessive resources.",
			AlertLevelCritical: "Critical process issue detected. Process behavior may impact system stability.",
