// GetActiveAlerts returns all currently active alerts
func (am *AlertManager) GetActiveAlerts() []SystemAlert {
	alerts := make([]SystemAlert, 0, len(am.activeAlerts))
	for _, alert := range am.activeAlerts {
		alerts = append(alerts, *alert)
	}

	// Sort by timestamp (newest first)
	sort.Slice(alerts, func(i, j int) bool {
		return alerts[i].Timestamp.After(alerts[j].Timestamp)
	})

	return alerts
}

// GetAlertHistory returns the alert history
func (am *AlertManager) GetAlertHistory() []SystemAlert {
	// Return a copy to prevent external modification
	history := make([]SystemAlert, len(am.alertHistory))
	copy(history, am.alertHistory)

	// Sort by timestamp (newest first)
	sort.Slice(history, func(i, j int) bool {
		return history[i].Timestamp.After(history[j].Timestamp)
	})

	return history
}

