// ProcessSortType represents different ways to sort processes
type ProcessSortType string

const (
	SortByPID       ProcessSortType = "PID"
	SortByName      ProcessSortType = "Name"
	SortByUser      ProcessSortType = "User"
	SortByCPU       ProcessSortType = "CPU"
	SortByMemory    ProcessSortType = "Memory"
	SortByState     ProcessSortType = "State"
	SortByPPID      ProcessSortType = "PPID"
	SortByStartTime ProcessSortType = "StartTime"
	SortByThreads   ProcessSortType = "Threads"
	SortByPriority  ProcessSortType = "Priority"
	SortByRuntime   ProcessSortType = "Runtime"
)

// ProcessFilter holds filtering criteria for processes
type ProcessFilter struct {
	NamePattern     string
	UserPattern     string
	CommandPattern  string
	StateFilter     string
	MinCPU          float64
	MaxCPU          float64
	MinMemory       float64
	MaxMemory       float64
	ShowKernelProcs bool
}

// Process management methods

// sortProcesses sorts the process list based on current sort settings with enhanced criteria
func (sm *SystemMonitorModel) sortProcesses() {
	sort.Slice(sm.processes, func(i, j int) bool {
		var less bool
		switch ProcessSortType(sm.sortColumn) {
		case SortByPID:
			less = sm.processes[i].PID < sm.processes[j].PID
		case SortByName:
			less = strings.ToLower(sm.processes[i].Name) < strings.ToLower(sm.processes[j].Name)
		case SortByUser:
			less = strings.ToLower(sm.processes[i].User) < strings.ToLower(sm.processes[j].User)
		case SortByCPU:
			less = sm.processes[i].CPU < sm.processes[j].CPU
		case SortByMemory:
			less = sm.processes[i].Memory < sm.processes[j].Memory
		case SortByState:
			less = sm.processes[i].State < sm.processes[j].State
		case SortByPPID:
			less = sm.processes[i].PPID < sm.processes[j].PPID
		case SortByStartTime:
			less = sm.processes[i].StartTime < sm.processes[j].StartTime
		case SortByThreads:
			less = sm.processes[i].Threads < sm.processes[j].Threads
		case SortByPriority:
			less = sm.processes[i].Priority < sm.processes[j].Priority
		case SortByRuntime:
			less = sm.processes[i].Runtime < sm.processes[j].Runtime
		default:
			less = sm.processes[i].CPU < sm.processes[j].CPU
		}

		if sm.sortReverse {
			return !less
		}
		return less
	})
}

// filterProcesses filters processes based on search query with enhanced matching
func (sm *SystemMonitorModel) filterProcesses(processes []Process, query string) []Process {
	if query == "" {
		return processes
	}

	var filtered []Process
	query = strings.ToLower(query)

	for _, proc := range processes {
		if sm.matchesFilter(proc, query) {
			filtered = append(filtered, proc)
		}
	}

	return filtered
}

// matchesFilter checks if a process matches the given filter query
func (sm *SystemMonitorModel) matchesFilter(proc Process, query string) bool {
	// Support different filter formats:
	// - Simple text search: "firefox"
	// - Field-specific search: "user:root", "cpu:>50", "state:R"
	// - Combined search: "user:root firefox"

	if strings.Contains(query, ":") {
		return sm.matchesAdvancedFilter(proc, query)
	}

	// Simple text search across multiple fields
	searchFields := []string{
		strings.ToLower(proc.Name),
		strings.ToLower(proc.Command),
		strings.ToLower(proc.User),
		strings.ToLower(proc.State),
		fmt.Sprintf("%d", proc.PID),
		fmt.Sprintf("%d", proc.PPID),
	}

	for _, field := range searchFields {
		if strings.Contains(field, query) {
			return true
		}
	}

	return false
}

// matchesAdvancedFilter handles advanced filtering with field-specific queries
func (sm *SystemMonitorModel) matchesAdvancedFilter(proc Process, query string) bool {
	parts := strings.Fields(query)

	for _, part := range parts {
		if strings.Contains(part, ":") {
			// Field-specific filter
			fieldParts := strings.SplitN(part, ":", 2)
			if len(fieldParts) != 2 {
				continue
			}

			field := strings.ToLower(fieldParts[0])
			value := strings.ToLower(fieldParts[1])

			if !sm.matchesFieldFilter(proc, field, value) {
				return false
			}
		} else {
			// Regular text search
			if !sm.matchesFilter(proc, part) {
				return false
			}
		}
	}

	return true
}

// matchesFieldFilter checks if a process matches a specific field filter
func (sm *SystemMonitorModel) matchesFieldFilter(proc Process, field, value string) bool {
	switch field {
	case "user", "u":
		return strings.Contains(strings.ToLower(proc.User), value)
	case "name", "n":
		return strings.Contains(strings.ToLower(proc.Name), value)
	case "command", "cmd", "c":
		return strings.Contains(strings.ToLower(proc.Command), value)
	case "state", "s":
		return strings.Contains(strings.ToLower(proc.State), value)
	case "pid":
		if pid, err := strconv.Atoi(value); err == nil {
			return proc.PID == pid
		}
	case "ppid":
		if ppid, err := strconv.Atoi(value); err == nil {
			return proc.PPID == ppid
		}
	case "cpu":
		return sm.matchesNumericFilter(proc.CPU, value)
	case "memory", "mem":
		return sm.matchesNumericFilter(proc.Memory, value)
	case "threads", "t":
		return sm.matchesNumericFilter(float64(proc.Threads), value)
	case "priority", "pri":
		return sm.matchesNumericFilter(float64(proc.Priority), value)
	}

	return false
}

// matchesNumericFilter handles numeric comparisons (>, <, =, >=, <=)
func (sm *SystemMonitorModel) matchesNumericFilter(actual float64, filter string) bool {
	if strings.HasPrefix(filter, ">=") {
		if val, err := strconv.ParseFloat(filter[2:], 64); err == nil {
			return actual >= val
		}
	} else if strings.HasPrefix(filter, "<=") {
		if val, err := strconv.ParseFloat(filter[2:], 64); err == nil {
			return actual <= val
		}
	} else if strings.HasPrefix(filter, ">") {
		if val, err := strconv.ParseFloat(filter[1:], 64); err == nil {
			return actual > val
		}
	} else if strings.HasPrefix(filter, "<") {
		if val, err := strconv.ParseFloat(filter[1:], 64); err == nil {
			return actual < val
		}
	} else if strings.HasPrefix(filter, "=") {
		if val, err := strconv.ParseFloat(filter[1:], 64); err == nil {
			return math.Abs(actual-val) < 0.01 // Small epsilon for float comparison
		}
	} else {
		// Default to equality check
		if val, err := strconv.ParseFloat(filter, 64); err == nil {
			return math.Abs(actual-val) < 0.01
		}
	}

	return false
}

// killProcess attempts to kill a process by PID
func (sm *SystemMonitorModel) killProcess(pid int) {
	if pid <= 0 {
		return
	}

	// Send SIGTERM first
	if process, err := os.FindProcess(pid); err == nil {
		process.Signal(syscall.SIGTERM)
	}
}


// ASCII Chart visualization methods

// RenderMetricChart renders an ASCII chart for the specified metric
func (hm *HistoryManager) RenderMetricChart(metricName string, width, height int) string {
	metric := hm.GetMetricHistory(metricName)
	if metric == nil || len(metric.DataPoints) == 0 {
		return hm.renderPlaceholder(metricName, width, height)
	}

	// Extract values for chart rendering
	values := make([]float64, len(metric.DataPoints))
	for i, point := range metric.DataPoints {
		values[i] = point.Value
	}

	// Choose color based on metric type
	var color lipgloss.Color
	switch metricName {
	case "cpu_usage":
		color = lipgloss.Color("#ef4444") // Red for CPU
	case "memory_usage":
		color = lipgloss.Color("#8b5cf6") // Purple for memory
	case "load_average":
		color = lipgloss.Color("#f59e0b") // Yellow for load
	case "network_in", "network_out":
		color = lipgloss.Color("#06b6d4") // Cyan for network
	default:
		color = lipgloss.Color("#10b981") // Green for others
	}

	title := fmt.Sprintf("%s (%s)", strings.Title(strings.ReplaceAll(metricName, "_", " ")), metric.Unit)
	minVal, maxVal := metric.MinValue, metric.MaxValue

	// Handle infinite values
	if math.IsInf(minVal, 1) || math.IsInf(maxVal, -1) {
		minVal, maxVal = hm.findDataRange(values)
	}

	return hm.renderChart(title, values, width, height, color, minVal, maxVal)
}

// renderChart renders a single-line ASCII chart
func (hm *HistoryManager) renderChart(title string, data []float64, width, height int, color lipgloss.Color, minVal, maxVal float64) string {
	var lines []string

	// Chart title
	titleStyle := lipgloss.NewStyle().Foreground(color).Bold(true)
	lines = append(lines, titleStyle.Render(title))

	// Calculate chart dimensions
	chartWidth := width - 10 // Leave space for Y-axis labels
	chartHeight := height - 3 // Leave space for title and X-axis

	if chartHeight < 3 || chartWidth < 10 {
		return hm.renderPlaceholder(title, width, height)
	}

	// Find data range if not provided
	if maxVal == minVal {
		minVal, maxVal = hm.findDataRange(data)
		if maxVal == minVal {
			maxVal = minVal + 1 // Avoid division by zero
		}
	}

	// Build chart grid
	chart := make([][]rune, chartHeight)
	for i := range chart {
		chart[i] = make([]rune, chartWidth)
		for j := range chart[i] {
			chart[i][j] = ' '
		}
	}

	// Plot data points
	dataLen := len(data)
	if dataLen > 0 {
		for x := 0; x < chartWidth && x < dataLen; x++ {
			dataIndex := dataLen - chartWidth + x
			if dataIndex >= 0 && dataIndex < len(data) {
				value := data[dataIndex]

				// Normalize value to chart height
				normalizedValue := (value - minVal) / (maxVal - minVal)
				y := int(float64(chartHeight-1) * (1.0 - normalizedValue))

				// Clamp y to chart bounds
				if y < 0 {
					y = 0
				}
				if y >= chartHeight {
					y = chartHeight - 1
				}

				// Set chart character
				chart[y][x] = '█'
			}
		}
	}

	// Convert chart to string lines
	chartStyle := lipgloss.NewStyle().Foreground(color)
	for i, row := range chart {
		line := string(row)
		// Add Y-axis labels for first and last row
		if i == 0 {
			line = fmt.Sprintf("%6.1f │%s", maxVal, line)
		} else if i == len(chart)-1 {
			line = fmt.Sprintf("%6.1f │%s", minVal, line)
		} else {
			line = fmt.Sprintf("       │%s", line)
		}
		lines = append(lines, chartStyle.Render(line))
	}

	// Add X-axis
	xAxis := strings.Repeat("─", chartWidth)
	lines = append(lines, fmt.Sprintf("       └%s", xAxis))

	return strings.Join(lines, "\n")
}

// findDataRange finds the min and max values in a data slice
func (hm *HistoryManager) findDataRange(data []float64) (float64, float64) {
	if len(data) == 0 {
		return 0, 1
	}

	minVal, maxVal := data[0], data[0]
	for _, value := range data {
		if value < minVal {
			minVal = value
		}
		if value > maxVal {
			maxVal = value
		}
	}

	// Add some padding
	padding := (maxVal - minVal) * 0.1
	if padding == 0 {
		padding = 1
	}

	return minVal - padding, maxVal + padding
}

// renderPlaceholder renders a placeholder when no data is available
func (hm *HistoryManager) renderPlaceholder(title string, width, height int) string {
	style := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#64748b")).
		Padding(1).
		Width(width - 2).
		Height(height - 2).
		Align(lipgloss.Center)

	content := fmt.Sprintf("%s\n\nNo data available\nCollecting metrics...", title)
	return style.Render(content)
}

package main

import (
	"fmt"
	"math"
	"os"
	"os/exec"
	"strings"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// AIAssistantModel implements a dedicated AI assistant interface
type AIAssistantModel struct {
	// Component state
	active bool
	width  int
	height int

	// AI Assistant state
	currentAgent    string
	availableAgents []AIAgent
	chatHistory     []AIMessage
	input           string
	cursorPos       int
	scrollOffset    int
	isProcessing    bool

	// Agent selection
	showAgentSelector bool
	selectedAgentIdx  int

	// Chat interface
	showChatHistory bool
	maxHistorySize  int

	// Visual effects
	frame         int
	pulsePhase    float64
	glowIntensity float64

	// Configuration
	autoScroll bool
	timestamps bool
}

// AIAssistantMessage represents messages for the AI assistant
type (
	aiResponseMsg struct {
		response string
		agent    string
		error    error
	}
	aiProcessingMsg struct {
		processing bool
	}
)

// NewAIAssistantModel creates a new AI assistant component
func NewAIAssistantModel() *AIAssistantModel {
	// Define available AI agents with enhanced descriptions
	agents := []AIAgent{
		{
			Name:        "Claude CLI",
			Command:     "claude-code",
			Description: "Advanced code analysis, debugging, and development assistance with deep understanding of programming concepts",
			Icon:        "🧠",
			Color:       lipgloss.Color("#6366f1"),
			Available:   checkCommandAvailable("claude"),
		},
		{
			Name:        "Gemini CLI",
			Command:     "gemini",
			Description: "Google's powerful Gemini AI for coding tasks, explanations, and technical problem-solving",
			Icon:        "💎",
			Color:       lipgloss.Color("#06b6d4"),
			Available:   checkCommandAvailable("gemini"),
		},
		{
			Name:        "GitHub Copilot CLI",
			Command:     "gh copilot",
			Description: "GitHub Copilot command-line interface for code suggestions and shell commands",
			Icon:        "🐙",
			Color:       lipgloss.Color("#8b5cf6"),
			Available:   checkCommandAvailable("gh"),
		},
		{
			Name:        "OpenCode",
			Command:     "opencode",
			Description: "Open-source code generation and assistance with community-driven AI models",
			Icon:        "🔓",
			Color:       lipgloss.Color("#10b981"),
			Available:   checkCommandAvailable("opencode"),
		},
		{
			Name:        "Aider",
			Command:     "aider",
			Description: "AI pair programming assistant that can edit your code files directly",
			Icon:        "🤖",
			Color:       lipgloss.Color("#f59e0b"),
			Available:   checkCommandAvailable("aider"),
		},
		{
			Name:        "Shell GPT",
			Command:     "sgpt",
			Description: "ChatGPT integration for shell commands, code explanations, and general assistance",
			Icon:        "💬",
			Color:       lipgloss.Color("#ec4899"),
			Available:   checkCommandAvailable("sgpt"),
		},
	}

	// Set default agent to the first available one
	defaultAgent := "gemini" // Default to gemini since it's available
	for _, agent := range agents {
		if agent.Available {
			defaultAgent = agent.Command
			break
		}
	}

	return &AIAssistantModel{
		active:            false,
		currentAgent:      defaultAgent,
		availableAgents:   agents,
		chatHistory:       make([]AIMessage, 0),
		input:             "",
		cursorPos:         0,
		scrollOffset:      0,
		isProcessing:      false,
		showAgentSelector: false,
		selectedAgentIdx:  0,
		showChatHistory:   true,
		maxHistorySize:    100,
		frame:             0,
		pulsePhase:        0,
		glowIntensity:     0.5,
		autoScroll:        true,
		timestamps:        true,
	}
}

// Init initializes the AI assistant component
func (ai *AIAssistantModel) Init() tea.Cmd {
	return tea.Batch(
		tea.Tick(50*time.Millisecond, func(t time.Time) tea.Msg {
			return tickMsg(t)
		}),
	)
}

// Update handles messages for the AI assistant
func (ai *AIAssistantModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	if !ai.active {
		return ai, nil
	}

	switch msg := msg.(type) {
	case tea.KeyMsg:
		return ai.handleKeyPress(msg)

	case tickMsg:
		ai.frame++
		ai.pulsePhase += 0.1
		ai.glowIntensity = 0.3 + 0.4*float64(math.Sin(ai.pulsePhase))
		return ai, nil

	case aiResponseMsg:
		ai.isProcessing = false
		if msg.error != nil {
			ai.addMessage("assistant", fmt.Sprintf("Error: %v", msg.error), msg.agent)
		} else {
			ai.addMessage("assistant", msg.response, msg.agent)
		}
		if ai.autoScroll {
			ai.scrollToBottom()
		}
		return ai, nil

	case aiProcessingMsg:
		ai.isProcessing = msg.processing
		return ai, nil
	}

	return ai, nil
}

// handleKeyPress handles keyboard input
func (ai *AIAssistantModel) handleKeyPress(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch {
	case msg.String() == "tab":
		ai.showAgentSelector = !ai.showAgentSelector
		return ai, nil

	case msg.String() == "ctrl+h":
		ai.showChatHistory = !ai.showChatHistory
		return ai, nil

	case msg.String() == "ctrl+c":
		if ai.isProcessing {
			ai.isProcessing = false
			ai.addMessage("system", "Processing cancelled", "system")
		}
		return ai, nil

	case msg.String() == "ctrl+l":
		ai.chatHistory = make([]AIMessage, 0)
		return ai, nil

	case ai.showAgentSelector:
		return ai.handleAgentSelection(msg)

	default:
		return ai.handleChatInput(msg)
	}
}

// handleAgentSelection handles agent selection interface
func (ai *AIAssistantModel) handleAgentSelection(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch msg.String() {
	case "up", "k":
		if ai.selectedAgentIdx > 0 {
			ai.selectedAgentIdx--
		}
	case "down", "j":
		if ai.selectedAgentIdx < len(ai.availableAgents)-1 {
			ai.selectedAgentIdx++
		}
	case "enter":
		if ai.selectedAgentIdx < len(ai.availableAgents) {
			ai.currentAgent = ai.availableAgents[ai.selectedAgentIdx].Command
			ai.showAgentSelector = false
			ai.addMessage("system", fmt.Sprintf("Switched to %s", ai.availableAgents[ai.selectedAgentIdx].Name), "system")
		}
	case "esc":
		ai.showAgentSelector = false
	}
	return ai, nil
}

// handleChatInput handles chat input
func (ai *AIAssistantModel) handleChatInput(msg tea.KeyMsg) (ToolComponent, tea.Cmd) {
	switch msg.String() {
	case "enter":
		if ai.input != "" {
			return ai.sendMessage()
		}
	case "backspace":
		if ai.cursorPos > 0 {
			ai.input = ai.input[:ai.cursorPos-1] + ai.input[ai.cursorPos:]
			ai.cursorPos--
		}
	case "left":
		if ai.cursorPos > 0 {
			ai.cursorPos--
		}
	case "right":
		if ai.cursorPos < len(ai.input) {
			ai.cursorPos++
		}
	case "home", "ctrl+a":
		ai.cursorPos = 0
	case "end", "ctrl+e":
		ai.cursorPos = len(ai.input)
	case "up":
		ai.scrollUp()
	case "down":
		ai.scrollDown()
	default:
		if len(msg.String()) == 1 {
			ai.input = ai.input[:ai.cursorPos] + msg.String() + ai.input[ai.cursorPos:]
			ai.cursorPos++
		}
	}
	return ai, nil
}

// sendMessage sends a message to the AI
func (ai *AIAssistantModel) sendMessage() (ToolComponent, tea.Cmd) {
	message := strings.TrimSpace(ai.input)
	if message == "" {
		return ai, nil
	}

	// Add user message to history
	ai.addMessage("user", message, ai.currentAgent)

	// Clear input
	ai.input = ""
	ai.cursorPos = 0

	// Set processing state
	ai.isProcessing = true

	if ai.autoScroll {
		ai.scrollToBottom()
	}

	// Send to AI agent
	return ai, ai.processAIRequest(message)
}

// processAIRequest processes the AI request
func (ai *AIAssistantModel) processAIRequest(message string) tea.Cmd {
	return func() tea.Msg {
		// Find the current agent
		var agent *AIAgent
		for _, a := range ai.availableAgents {
			if a.Command == ai.currentAgent {
				agent = &a
				break
			}
		}

		if agent == nil || !agent.Available {
			return aiResponseMsg{
				response: "The selected AI agent is not available. Please check your installation or select a different agent.",
				agent:    ai.currentAgent,
				error:    fmt.Errorf("agent not available"),
			}
		}

		// Construct command based on agent type
		var cmd *exec.Cmd
		switch agent.Command {
		case "claude-code":
			// Claude Code: Try claude command if available
			cmd = exec.Command("claude", message)
		case "gemini":
			// Gemini CLI: Use -p flag for prompt
			cmd = exec.Command("gemini", "-p", message)
		case "gh copilot":
			// GitHub Copilot CLI: Use suggest command for code suggestions
			cmd = exec.Command("gh", "copilot", "suggest", message)
		case "opencode":
			cmd = exec.Command("opencode", message)
		case "aider":
			// Aider: Use --message flag for non-interactive mode
			cmd = exec.Command("aider", "--message", message)
		case "sgpt":
			// Shell GPT: Direct message input
			cmd = exec.Command("sgpt", message)
		default:
			return aiResponseMsg{
				response: "",
				agent:    agent.Command,
				error:    fmt.Errorf("unknown agent command: %s", agent.Command),
			}
		}

		// Set working directory
		if wd, err := os.Getwd(); err == nil {
			cmd.Dir = wd
		}

		// Execute command
		output, err := cmd.CombinedOutput()
		return aiResponseMsg{
			response: string(output),
			agent:    agent.Command,
			error:    err,
		}
	}
}

// View renders the AI assistant interface
func (ai *AIAssistantModel) View() string {
	if !ai.active {
		return ""
	}

	var sections []string

	// Header
	sections = append(sections, ai.renderHeader())

	// Agent selector or chat interface
	if ai.showAgentSelector {
		sections = append(sections, ai.renderAgentSelector())
	} else {
		// Chat history
		if ai.showChatHistory {
			sections = append(sections, ai.renderChatHistory())
		}

		// Input area
		sections = append(sections, ai.renderInputArea())
	}

	// Help footer
	sections = append(sections, ai.renderHelp())

	return lipgloss.JoinVertical(lipgloss.Left, sections...)
}

// renderHeader renders the header section
func (ai *AIAssistantModel) renderHeader() string {
	currentAgentName := "Unknown"
	currentAgentIcon := "🤖"
	currentAgentColor := lipgloss.Color("#6b7280")

	for _, agent := range ai.availableAgents {
		if agent.Command == ai.currentAgent {
			currentAgentName = agent.Name
			currentAgentIcon = agent.Icon
			currentAgentColor = agent.Color
			break
		}
	}

	titleStyle := lipgloss.NewStyle().
		Foreground(currentAgentColor).
		Bold(true).
		Padding(0, 1)

	statusStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Italic(true)

	processingIndicator := ""
	if ai.isProcessing {
		dots := strings.Repeat(".", (ai.frame/10)%4)
		processingIndicator = statusStyle.Render(fmt.Sprintf(" (processing%s)", dots))
	}

	title := titleStyle.Render(fmt.Sprintf("%s AI Assistant - %s", currentAgentIcon, currentAgentName))

	headerBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(currentAgentColor).
		Padding(1, 2).
		Width(ai.width - 4)

	return headerBox.Render(title + processingIndicator)
}

// renderAgentSelector renders the agent selection interface
func (ai *AIAssistantModel) renderAgentSelector() string {
	var items []string

	for i, agent := range ai.availableAgents {
		style := lipgloss.NewStyle().Padding(0, 2)

		if i == ai.selectedAgentIdx {
			style = style.Background(agent.Color).Foreground(lipgloss.Color("#000000"))
		} else if !agent.Available {
			style = style.Foreground(lipgloss.Color("#6b7280"))
		} else {
			style = style.Foreground(agent.Color)
		}

		status := "✓"
		if !agent.Available {
			status = "✗"
		}

		item := fmt.Sprintf("%s %s %s - %s", status, agent.Icon, agent.Name, agent.Description)
		items = append(items, style.Render(item))
	}

	selectorBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#6b7280")).
		Padding(1, 2).
		Width(ai.width - 4).
		Height(ai.height - 8)

	content := lipgloss.JoinVertical(lipgloss.Left, items...)
	return selectorBox.Render(content)
}

// renderChatHistory renders the chat history
func (ai *AIAssistantModel) renderChatHistory() string {
	if len(ai.chatHistory) == 0 {
		emptyStyle := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Align(lipgloss.Center).
			Padding(2)

		return emptyStyle.Render("No conversation yet. Type a message to start chatting with your AI assistant!")
	}

	var messages []string
	visibleHeight := ai.height - 12 // Account for header, input, and help

	startIdx := ai.scrollOffset
	endIdx := len(ai.chatHistory)

	if endIdx-startIdx > visibleHeight {
		endIdx = startIdx + visibleHeight
	}

	for i := startIdx; i < endIdx && i < len(ai.chatHistory); i++ {
		msg := ai.chatHistory[i]
		messages = append(messages, ai.renderMessage(msg))
	}

	chatBox := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#374151")).
		Padding(1, 2).
		Width(ai.width - 4).
		Height(visibleHeight)

	content := lipgloss.JoinVertical(lipgloss.Left, messages...)
	return chatBox.Render(content)
}

// renderMessage renders a single chat message
func (ai *AIAssistantModel) renderMessage(msg AIMessage) string {
	var style lipgloss.Style
	var prefix string

	switch msg.Role {
	case "user":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#3b82f6"))
		prefix = "You: "
	case "assistant":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#10b981"))
		prefix = "AI: "
	case "system":
		style = lipgloss.NewStyle().Foreground(lipgloss.Color("#6b7280")).Italic(true)
		prefix = "System: "
	}

	timestamp := ""
	if ai.timestamps {
		timestamp = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Render(fmt.Sprintf("[%s] ", msg.Timestamp.Format("15:04:05")))
	}

	content := style.Render(prefix + msg.Content)
	return timestamp + content
}

// renderInputArea renders the input area
func (ai *AIAssistantModel) renderInputArea() string {
	cursor := ""
	if ai.cursorPos == len(ai.input) {
		cursor = "│"
	}

	displayInput := ai.input[:ai.cursorPos] + cursor + ai.input[ai.cursorPos:]

	inputStyle := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#6366f1")).
		Padding(0, 2).
		Width(ai.width - 4)

	placeholder := ""
	if ai.input == "" && !ai.isProcessing {
		placeholder = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Render("Type your message here...")
	}

	content := displayInput + placeholder
	if ai.isProcessing {
		content = lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Italic(true).
			Render("Processing your request...")
	}

	return inputStyle.Render(content)
}

// renderHelp renders the help footer
func (ai *AIAssistantModel) renderHelp() string {
	helpStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6b7280")).
		Padding(0, 1)

	help := "Tab: Select Agent • Ctrl+H: Toggle History • Ctrl+L: Clear • Ctrl+C: Cancel • ↑↓: Scroll • Enter: Send"
	return helpStyle.Render(help)
}

// Helper methods

// addMessage adds a message to the chat history
func (ai *AIAssistantModel) addMessage(role, content, agent string) {
	msg := AIMessage{
		Role:      role,
		Content:   content,
		Timestamp: time.Now(),
		Agent:     agent,
	}

	ai.chatHistory = append(ai.chatHistory, msg)

	// Limit history size
	if len(ai.chatHistory) > ai.maxHistorySize {
		ai.chatHistory = ai.chatHistory[len(ai.chatHistory)-ai.maxHistorySize:]
	}
}

// scrollUp scrolls the chat history up
func (ai *AIAssistantModel) scrollUp() {
	if ai.scrollOffset > 0 {
		ai.scrollOffset--
	}
}

// scrollDown scrolls the chat history down
func (ai *AIAssistantModel) scrollDown() {
	maxScroll := len(ai.chatHistory) - (ai.height - 12)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if ai.scrollOffset < maxScroll {
		ai.scrollOffset++
	}
}

// scrollToBottom scrolls to the bottom of chat history
func (ai *AIAssistantModel) scrollToBottom() {
	maxScroll := len(ai.chatHistory) - (ai.height - 12)
	if maxScroll < 0 {
		maxScroll = 0
	}
	ai.scrollOffset = maxScroll
}

// Component interface implementation

// SetSize sets the component size
func (ai *AIAssistantModel) SetSize(width, height int) {
	ai.width = width
	ai.height = height
}

// GetViewType returns the view type
func (ai *AIAssistantModel) GetViewType() ViewType {
	return ViewAIAssistant
}

// IsActive returns whether the component is active
func (ai *AIAssistantModel) IsActive() bool {
	return ai.active
}

// SetActive sets the active state
func (ai *AIAssistantModel) SetActive(active bool) {
	ai.active = active
	if active {
		// Add welcome message if this is the first time
		if len(ai.chatHistory) == 0 {
			ai.addMessage("system", "Welcome to the AI Assistant! Select an agent with Tab and start chatting.", "system")
		}
	}
}

package main

import (
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ViewType represents the different tool views available in the multitool
type ViewType int

const (
	ViewOverview ViewType = iota
	ViewSystemMonitor
	ViewPortScanner
	ViewPackageManager
	ViewContainerMgmt
	ViewAIAssistant
	ViewBashTerminal
	ViewSettings
)

// String returns the string representation of ViewType
func (v ViewType) String() string {
	switch v {
	case ViewOverview:
		return "overview"
	case ViewSystemMonitor:
		return "system"
	case ViewPortScanner:
		return "scanner"
	case ViewPackageManager:
		return "packages"
	case ViewContainerMgmt:
		return "containers"
	case ViewAIAssistant:
		return "ai"
	case ViewBashTerminal:
		return "bash"
	case ViewSettings:
		return "settings"
	default:
		return "unknown"
	}
}

// ToolComponent defines the interface that all tool components must implement
type ToolComponent interface {
	// Init initializes the component and returns initial commands
	Init() tea.Cmd

	// Update handles messages and returns updated model and commands
	Update(msg tea.Msg) (ToolComponent, tea.Cmd)

	// View renders the component's interface
	View() string

	// SetSize updates the component's dimensions
	SetSize(width, height int)

	// GetViewType returns the component's view type
	GetViewType() ViewType

	// IsActive returns whether the component is currently active
	IsActive() bool

	// SetActive sets the component's active state
	SetActive(active bool)
}

// Global message types for inter-component communication
type (
	// tickMsg represents a tick message for animations and updates
	tickMsg time.Time
	// ViewSwitchMsg is sent when switching between different tool views
	ViewSwitchMsg struct {
		View     ViewType
		Previous ViewType
	}

	// ConfigUpdateMsg is sent when configuration changes
	ConfigUpdateMsg struct {
		Config *Config
	}

	// NotificationMsg is sent to display notifications to the user
	NotificationMsg struct {
		Message string
		Level   NotificationLevel
		Source  string
		Time    time.Time
	}

	// StatusUpdateMsg is sent to update the status bar
	StatusUpdateMsg struct {
		Status string
		Color  lipgloss.Color
	}

	// ErrorMsg wraps errors for consistent error handling
	ErrorMsg struct {
		Err    error
		Source string
		Level  ErrorLevel
	}

	// DataUpdateMsg is sent when shared data is updated
	DataUpdateMsg struct {
		Type string
		Data interface{}
	}

	// SaveConfigMsg is a message to trigger saving the configuration.
	SaveConfigMsg struct{}
)

// NotificationLevel represents the severity of notifications
type NotificationLevel int

const (
	NotificationInfo NotificationLevel = iota
	NotificationWarning
	NotificationError
	NotificationSuccess
)

// String returns the string representation of NotificationLevel
func (n NotificationLevel) String() string {
	switch n {
	case NotificationInfo:
		return "info"
	case NotificationWarning:
		return "warning"
	case NotificationError:
		return "error"
	case NotificationSuccess:
		return "success"
	default:
		return "unknown"
	}
}

// ErrorLevel represents the severity of errors
type ErrorLevel int

const (
	ErrorLevelInfo ErrorLevel = iota
	ErrorLevelWarning
	ErrorLevelError
	ErrorLevelCritical
)

// String returns the string representation of ErrorLevel
func (e ErrorLevel) String() string {
	switch e {
	case ErrorLevelInfo:
		return "info"
	case ErrorLevelWarning:
		return "warning"
	case ErrorLevelError:
		return "error"
	case ErrorLevelCritical:
		return "critical"
	default:
		return "unknown"
	}
}

