   345→// validateField validates a single configuration field
   346→func (cm *ConfigManager) validateField(field string, value interface{}) error {
   347→	validator, exists := cm.validators[field]
   348→	if !exists {
   349→		return nil // No validator for this field
   350→	}
   351→
   352→	if err := validator(value); err != nil {
   353→		return &ConfigurationError{
   354→			Field:   field,
   355→			Message: err.Error(),
   356→			Value:   value,
   357→		}
   358→	}
