   572→func (cm *ConfigManager) validatePortRange(rangeStr string) error {
   573→	parts := strings.Split(rangeStr, "-")
   574→	if len(parts) != 2 {
   575→		return fmt.Errorf("port range must be in format 'start-end'")
   576→	}
   577→
   578→	start, err := parsePort(parts[0])
   579→	if err != nil {
   580→		return fmt.Errorf("invalid start port: %w", err)
   581→	}
   582→
   583→	end, err := parsePort(parts[1])
   584→	if err != nil {
   585→		return fmt.Errorf("invalid end port: %w", err)
   586→	}
   587→
   588→	if start > end {
   589→		return fmt.Errorf("start port must be less than or equal to end port")
   590→	}
   591→
   592→	return nil
   593→}
   594→
   595→func parsePort(portStr string) (int, error) {
   596→	port := 0
   597→	for _, r := range portStr {
   598→		if r < '0' || r > '9' {
   599→			return 0, fmt.Errorf("port must be numeric")
   600→		}
   601→		port = port*10 + int(r-'0')
   602→	}
   603→
   604→	if port < 1 || port > 65535 {
   605→		return 0, fmt.Errorf("port must be between 1 and 65535")
   606→	}
   607→
   608→	return port, nil
   609→}
