	height int

	// Terminal state
	currentDir    string
	prompt        string
	input         string
	cursorPos     int
	history       []string
	historyPos    int
	output        []OutputLine
	scrollOffset  int
	maxOutputSize int

	// Command execution
	runningCmd  *exec.Cmd
	cmdOutput   chan string
	cmdDone     chan bool
