package main

import (
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ViewType represents the different tool views available in the multitool
type ViewType int

const (
	ViewOverview ViewType = iota
	ViewSystemMonitor
	ViewPortScanner
	ViewPackageManager
	ViewContainerMgmt
	ViewAIAssistant
	ViewBashTerminal
	ViewSettings
)

// String returns the string representation of ViewType
func (v ViewType) String() string {
	switch v {
	case ViewOverview:
		return "overview"
	case ViewSystemMonitor:
		return "system"
	case ViewPortScanner:
		return "scanner"
	case ViewPackageManager:
		return "packages"
	case ViewContainerMgmt:
		return "containers"
	case ViewAIAssistant:
		return "ai"
	case ViewBashTerminal:
		return "bash"
	case ViewSettings:
		return "settings"
	default:
		return "unknown"
	}
}

// ToolComponent defines the interface that all tool components must implement
type ToolComponent interface {
	// Init initializes the component and returns initial commands
	Init() tea.Cmd

	// Update handles messages and returns updated model and commands
	Update(msg tea.Msg) (ToolComponent, tea.Cmd)

	// View renders the component's interface
	View() string

	// SetSize updates the component's dimensions
	SetSize(width, height int)

	// GetViewType returns the component's view type
	GetViewType() ViewType

	// IsActive returns whether the component is currently active
	IsActive() bool

	// SetActive sets the component's active state
	SetActive(active bool)
}

// Global message types for inter-component communication
type (
	// tickMsg represents a tick message for animations and updates
	tickMsg time.Time
	// ViewSwitchMsg is sent when switching between different tool views
	ViewSwitchMsg struct {
		View     ViewType
		Previous ViewType
	}

	// ConfigUpdateMsg is sent when configuration changes
	ConfigUpdateMsg struct {
		Config *Config
	}

	// NotificationMsg is sent to display notifications to the user
	NotificationMsg struct {
		Message string
		Level   NotificationLevel
		Source  string
		Time    time.Time
	}

	// StatusUpdateMsg is sent to update the status bar
	StatusUpdateMsg struct {
		Status string
		Color  lipgloss.Color
	}

	// ErrorMsg wraps errors for consistent error handling
	ErrorMsg struct {
		Err    error
		Source string
		Level  ErrorLevel
	}

	// DataUpdateMsg is sent when shared data is updated
	DataUpdateMsg struct {
		Type string
		Data interface{}
	}

	// SaveConfigMsg is a message to trigger saving the configuration.
	SaveConfigMsg struct{}
)

// NotificationLevel represents the severity of notifications
type NotificationLevel int

const (
	NotificationInfo NotificationLevel = iota
	NotificationWarning
	NotificationError
	NotificationSuccess
)

// String returns the string representation of NotificationLevel
func (n NotificationLevel) String() string {
	switch n {
	case NotificationInfo:
		return "info"
	case NotificationWarning:
		return "warning"
	case NotificationError:
		return "error"
	case NotificationSuccess:
		return "success"
	default:
		return "unknown"
	}
}

// ErrorLevel represents the severity of errors
type ErrorLevel int

const (
	ErrorLevelInfo ErrorLevel = iota
	ErrorLevelWarning
	ErrorLevelError
	ErrorLevelCritical
)

// String returns the string representation of ErrorLevel
func (e ErrorLevel) String() string {
	switch e {
	case ErrorLevelInfo:
		return "info"
	case ErrorLevelWarning:
		return "warning"
	case ErrorLevelError:
		return "error"
	case ErrorLevelCritical:
		return "critical"
	default:
		return "unknown"
	}
}

// KeyBindings holds all key binding configurations
type KeyBindings struct {
	Quit                 []string `yaml:"quit"`
	SwitchToOverview     string   `yaml:"switch_to_overview"`
	SwitchToProcesses    string   `yaml:"switch_to_processes"`
	SwitchToNetwork      string   `yaml:"switch_to_network"`
	SwitchToAlerts       string   `yaml:"switch_to_alerts"`
	SwitchToBashTerminal string   `yaml:"switch_to_bash_terminal"`
	CycleThemes          string   `yaml:"cycle_themes"`
	KillProcess          string   `yaml:"kill_process"`
	SearchFilter         string   `yaml:"search_filter"`
	Help                 []string `yaml:"help"`
}

// DefaultKeyBindings returns the default key binding configuration
func DefaultKeyBindings() KeyBindings {
	return KeyBindings{
		Quit:                 []string{"q", "ctrl+c"},
		SwitchToOverview:     "1",
		SwitchToProcesses:    "2",
		SwitchToNetwork:      "3",
		SwitchToAlerts:       "4",
		SwitchToBashTerminal: "!",
		CycleThemes:          "t",
		KillProcess:          "k",
		SearchFilter:         "/",
		Help:                 []string{"?", "h"},
	}
}

// Config holds the application configuration
type Config struct {
	// Schema version for migrations
	Version int `yaml:"version"`

	// General Settings
	General GeneralSettings `yaml:"general"`

	// UI preferences
	Theme        ThemeSettings      `yaml:"theme"`
	KeyBindings  KeyBindings        `yaml:"keybindings"`
	RefreshRates RefreshRateConfig  `yaml:"refresh_rates"`
	AdvancedUI   AdvancedUISettings `yaml:"advanced_ui"`

	// Tool-specific settings
	SystemMonitor  SystemMonitorConfig  `yaml:"system_monitor"`
	PortScanner    PortScannerConfig    `yaml:"port_scanner"`
	PackageManager PackageManagerConfig `yaml:"package_manager"`
	ContainerMgmt  ContainerMgmtConfig  `yaml:"container_mgmt"`
	AIAssistant    AIAssistantConfig    `yaml:"ai_assistant"`

	// Profiles
	Profiles      []Profile `yaml:"profiles"`
	ActiveProfile string    `yaml:"active_profile"`

	// Global settings
	LogLevel        string `yaml:"log_level"`
	DataDirectory   string `yaml:"data_directory"`
	PluginDirectory string `yaml:"plugin_directory"`
}

// GeneralSettings holds general application settings
type GeneralSettings struct {
	AppName                   string `yaml:"app_name"`
	AutoSave                  bool   `yaml:"auto_save"`
	StartupView               string `yaml:"startup_view"`
	ShowTooltips              bool   `yaml:"show_tooltips"`
	ConfirmDestructiveActions bool   `yaml:"confirm_destructive_actions"`
}

// ThemeSettings replaces ThemeConfig and adds more options
type ThemeSettings struct {
	CurrentTheme    string  `yaml:"current_theme"`
	ThemePreview    bool    `yaml:"theme_preview"`
	EnableOrbs      bool    `yaml:"enable_orbs"`
	EnableLightRays bool    `yaml:"enable_light_rays"`
	EnableMatrix    bool    `yaml:"enable_matrix"`
	EnableEnergy    bool    `yaml:"enable_energy"`
	GlowIntensity   float64 `yaml:"glow_intensity"`
	PulseSpeed      float64 `yaml:"pulse_speed"`
	ParticleCount   int     `yaml:"particle_count"`
}

// AdvancedUISettings holds advanced UI and performance settings
type AdvancedUISettings struct {
	AnimationSpeed     string        `yaml:"animation_speed"` // "Off", "Slow", "Normal", "Fast"
	RefreshRate        time.Duration `yaml:"refresh_rate"`
	EnableTransparency bool          `yaml:"enable_transparency"`
	EnableShadows      bool          `yaml:"enable_shadows"`
	EnableGradients    bool          `yaml:"enable_gradients"`
	PerformanceMode    bool          `yaml:"performance_mode"`
	DebugMode          bool          `yaml:"debug_mode"`
	MemoryUsageLimitMB int           `yaml:"memory_usage_limit_mb"`
}

// Profile holds a named configuration profile
type Profile struct {
	Name   string `yaml:"name"`
	Config Config `yaml:"config"` // A profile contains a full config snapshot
}

// RefreshRateConfig holds refresh rate settings for different components
type RefreshRateConfig struct {
	SystemStats time.Duration `yaml:"system_stats"`
	Processes   time.Duration `yaml:"processes"`
	Network     time.Duration `yaml:"network"`
	Alerts      time.Duration `yaml:"alerts"`
}

// Tool-specific configuration types
type SystemMonitorConfig struct {
	ShowProcesses   bool          `yaml:"show_processes"`
	ProcessLimit    int           `yaml:"process_limit"`
	RefreshInterval time.Duration `yaml:"refresh_interval"`
}

type PortScannerConfig struct {
