package main

import (
	"fmt"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ViewManager handles view routing and state management
type ViewManager struct {
	// Current state
	currentView  ViewType
	previousView ViewType
	viewHistory  []ViewType

	// Component registry
	components map[ViewType]ToolComponent

	// State preservation
	componentStates map[ViewType]interface{}

	// Configuration
	maxHistorySize int

	// Dimensions
	width  int
	height int
}

// NewViewManager creates a new view manager
func NewViewManager() *ViewManager {
	return &ViewManager{
		currentView:     ViewOverview,
		previousView:    ViewOverview,
		viewHistory:     make([]ViewType, 0),
		components:      make(map[ViewType]ToolComponent),
		componentStates: make(map[ViewType]interface{}),
		maxHistorySize:  10,
	}
}

// RegisterComponent registers a tool component with the view manager
func (vm *ViewManager) RegisterComponent(viewType ViewType, component ToolComponent) {
	vm.components[viewType] = component
	if component != nil {
		component.SetSize(vm.width, vm.height)
		component.SetActive(viewType == vm.currentView)
	}
}

// UnregisterComponent removes a component from the view manager
func (vm *ViewManager) UnregisterComponent(viewType ViewType) {
	if component, exists := vm.components[viewType]; exists {
		if component != nil {
			component.SetActive(false)
		}
		delete(vm.components, viewType)
		delete(vm.componentStates, viewType)
	}
}

// SwitchView switches to a new view with state preservation
func (vm *ViewManager) SwitchView(newView ViewType) tea.Cmd {
	if newView == vm.currentView {
		return nil
	}

	// Save current component state
	vm.preserveCurrentState()

	// Deactivate current component
	if currentComponent := vm.GetCurrentComponent(); currentComponent != nil {
		currentComponent.SetActive(false)
	}

	// Update view state
	vm.addToHistory(vm.currentView)
	vm.previousView = vm.currentView
	vm.currentView = newView

	// Restore new component state
	vm.restoreComponentState(newView)

	// Activate new component
	if newComponent := vm.GetCurrentComponent(); newComponent != nil {
		newComponent.SetActive(true)
		// Initialize component if it hasn't been initialized yet
		return newComponent.Init()
	}

	return nil
}

// GoBack navigates to the previous view
func (vm *ViewManager) GoBack() tea.Cmd {
	if len(vm.viewHistory) > 0 {
		// Get the last view from history
		lastView := vm.viewHistory[len(vm.viewHistory)-1]
		vm.viewHistory = vm.viewHistory[:len(vm.viewHistory)-1]

		return vm.SwitchView(lastView)
	}

	// If no history, go to overview
	if vm.currentView != ViewOverview {
		return vm.SwitchView(ViewOverview)
	}

	return nil
}

// GetCurrentView returns the current view type
func (vm *ViewManager) GetCurrentView() ViewType {
	return vm.currentView
}

// GetPreviousView returns the previous view type
func (vm *ViewManager) GetPreviousView() ViewType {
	return vm.previousView
}

// GetCurrentComponent returns the currently active component
func (vm *ViewManager) GetCurrentComponent() ToolComponent {
	return vm.components[vm.currentView]
}

// GetComponent returns a specific component by view type
func (vm *ViewManager) GetComponent(viewType ViewType) ToolComponent {
	return vm.components[viewType]
}

// RouteMessage routes a message to the appropriate component
func (vm *ViewManager) RouteMessage(msg tea.Msg) ([]ToolComponent, []tea.Cmd) {
	var updatedComponents []ToolComponent
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case ViewSwitchMsg:
		// Handle view switching
		if cmd := vm.SwitchView(msg.View); cmd != nil {
			cmds = append(cmds, cmd)
		}

	case tea.WindowSizeMsg:
		// Update size for all components
		vm.SetSize(msg.Width, msg.Height)

	default:
		// Route to current component
		if currentComponent := vm.GetCurrentComponent(); currentComponent != nil {
			updatedComponent, cmd := currentComponent.Update(msg)
			if updatedComponent != nil {
				vm.components[vm.currentView] = updatedComponent
				updatedComponents = append(updatedComponents, updatedComponent)
			}
			if cmd != nil {
				cmds = append(cmds, cmd)
			}
		}

		// Also route global messages to all components that need them
		vm.routeGlobalMessage(msg, &updatedComponents, &cmds)
	}

	return updatedComponents, cmds
}

// SetSize updates the size for all components
func (vm *ViewManager) SetSize(width, height int) {
	vm.width = width
	vm.height = height

	// Update size for all registered components
	for _, component := range vm.components {
		if component != nil {
			component.SetSize(width, height)
		}
	}
}

// GetViewHistory returns the view navigation history
func (vm *ViewManager) GetViewHistory() []ViewType {
	return append([]ViewType(nil), vm.viewHistory...) // Return a copy
}

// ClearHistory clears the view navigation history
func (vm *ViewManager) ClearHistory() {
	vm.viewHistory = make([]ViewType, 0)
}

// IsComponentRegistered checks if a component is registered for a view type
func (vm *ViewManager) IsComponentRegistered(viewType ViewType) bool {
	_, exists := vm.components[viewType]
	return exists
}

// GetRegisteredViews returns all registered view types
func (vm *ViewManager) GetRegisteredViews() []ViewType {
	views := make([]ViewType, 0, len(vm.components))
	for viewType := range vm.components {
		views = append(views, viewType)
	}
	return views
}

// preserveCurrentState saves the current component's state
func (vm *ViewManager) preserveCurrentState() {
	if currentComponent := vm.GetCurrentComponent(); currentComponent != nil {
		// For now, we'll use a simple state preservation mechanism
		// In a more complex implementation, components could implement a Stateful interface
		vm.componentStates[vm.currentView] = struct {
			active bool
		}{
			active: currentComponent.IsActive(),
		}
	}
}

// restoreComponentState restores a component's state
func (vm *ViewManager) restoreComponentState(viewType ViewType) {
	// For now, this is a placeholder for state restoration
	// In a more complex implementation, this would restore saved component state
	if _, exists := vm.componentStates[viewType]; exists {
		// State restoration logic would go here
	}
}

// addToHistory adds a view to the navigation history
func (vm *ViewManager) addToHistory(view ViewType) {
	// Don't add the same view consecutively
	if len(vm.viewHistory) > 0 && vm.viewHistory[len(vm.viewHistory)-1] == view {
		return
	}

	vm.viewHistory = append(vm.viewHistory, view)

	// Limit history size
	if len(vm.viewHistory) > vm.maxHistorySize {
		vm.viewHistory = vm.viewHistory[1:]
	}
}

// routeGlobalMessage routes global messages to components that need them
func (vm *ViewManager) routeGlobalMessage(msg tea.Msg, updatedComponents *[]ToolComponent, cmds *[]tea.Cmd) {
	// Messages that should be sent to all components
	switch msg.(type) {
	case ConfigUpdateMsg, NotificationMsg, StatusUpdateMsg:
		for viewType, component := range vm.components {
			if component != nil && viewType != vm.currentView {
				updatedComponent, cmd := component.Update(msg)
				if updatedComponent != nil {
					vm.components[viewType] = updatedComponent
					*updatedComponents = append(*updatedComponents, updatedComponent)
				}
				if cmd != nil {
					*cmds = append(*cmds, cmd)
				}
			}
		}
	}
}

// ViewRouter provides routing functionality for the main model
type ViewRouter struct {
	viewManager *ViewManager

	// View metadata
	viewInfo map[ViewType]ViewInfo
}

// NewViewRouter creates a new view router
func NewViewRouter() *ViewRouter {
	viewInfo := map[ViewType]ViewInfo{
		ViewOverview: {
			Type:        ViewOverview,
			Name:        "Overview",
			Icon:        "⬢",
			Color:       lipgloss.Color("#6366f1"),
			KeyBinding:  "1",
			Description: "System overview and dashboard",
		},
		ViewSystemMonitor: {
			Type:        ViewSystemMonitor,
			Name:        "System",
			Icon:        "⚡",
			Color:       lipgloss.Color("#8b5cf6"),
			KeyBinding:  "2",
