	themes := m.themeManager.GetThemeNames()
	currentTheme := m.themeManager.GetCurrentTheme().Name

	// Find current theme index
	currentIndex := 0
	for i, theme := range themes {
		if theme == currentTheme {
			currentIndex = i
			break
		}
	}

	// Get next theme
	nextIndex := (currentIndex + 1) % len(themes)
	nextTheme := themes[nextIndex]

	// Apply the theme
	m.themeManager.ApplyTheme(nextTheme)

	// Update global colors
	m.updateGlobalColors()

	return m, nil
