// PortRange represents a range of ports to scan
type PortRange struct {
	Start int
	End   int
}

// String returns the string representation of PortRange
func (pr PortRange) String() string {
	if pr.Start == pr.End {
		return fmt.Sprintf("%d", pr.Start)
	}
	return fmt.Sprintf("%d-%d", pr.Start, pr.End)
}

// ParsePortRange parses a port range string (e.g., "80", "80-443", "1-1000")
func ParsePortRange(s string) (PortRange, error) {
	if strings.Contains(s, "-") {
		parts := strings.Split(s, "-")
		if len(parts) != 2 {
			return PortRange{}, fmt.Errorf("invalid port range format: %s", s)
		}

		start, err := strconv.Atoi(strings.TrimSpace(parts[0]))
		if err != nil {
			return PortRange{}, fmt.Errorf("invalid start port: %s", parts[0])
		}

		end, err := strconv.Atoi(strings.TrimSpace(parts[1]))
		if err != nil {
			return PortRange{}, fmt.Errorf("invalid end port: %s", parts[1])
		}

		if start > end || start < 1 || end > 65535 {
			return PortRange{}, fmt.Errorf("invalid port range: %d-%d", start, end)
		}

		return PortRange{Start: start, End: end}, nil
	}

	port, err := strconv.Atoi(strings.TrimSpace(s))
	if err != nil {
		return PortRange{}, fmt.Errorf("invalid port: %s", s)
	}

	if port < 1 || port > 65535 {
		return PortRange{}, fmt.Errorf("port out of range: %d", port)
	}

	return PortRange{Start: port, End: port}, nil
}

