// RateLimiter controls the rate of port scanning operations
type RateLimiter struct {
	tokens   chan struct{}
	interval time.Duration
	ticker   *time.Ticker
	done     chan struct{}
}

// NewRateLimiter creates a new rate limiter
func NewRateLimiter(maxConcurrent int, interval time.Duration) *RateLimiter {
	rl := &RateLimiter{
		tokens:   make(chan struct{}, maxConcurrent),
		interval: interval,
		done:     make(chan struct{}),
	}

	// Fill initial tokens
	for i := 0; i < maxConcurrent; i++ {
		rl.tokens <- struct{}{}
	}

	// Start token replenishment if interval is set
	if interval > 0 {
		rl.ticker = time.NewTicker(interval)
		go rl.replenishTokens()
	}

	return rl
}

// Acquire acquires a token, blocking if necessary
func (rl *RateLimiter) Acquire(ctx context.Context) error {
	select {
	case <-rl.tokens:
		return nil
	case <-ctx.Done():
		return ctx.Err()
	case <-rl.done:
		return context.Canceled
	}
}

// Release releases a token back to the pool
func (rl *RateLimiter) Release() {
	select {
	case rl.tokens <- struct{}{}:
	default:
		// Token pool is full, ignore
	}
}

// Close stops the rate limiter
func (rl *RateLimiter) Close() {
	close(rl.done)
	if rl.ticker != nil {
		rl.ticker.Stop()
	}
}

// replenishTokens periodically adds tokens to prevent starvation
func (rl *RateLimiter) replenishTokens() {
	for {
		select {
		case <-rl.ticker.C:
			// Try to add a token if there's space
			select {
			case rl.tokens <- struct{}{}:
			default:
				// Pool is full
			}
		case <-rl.done:
			return
		}
	}
}

// NewPortScanner creates a new port scanner
func NewPortScanner(concurrency int, timeout time.Duration) *PortScanner {
	// Create rate limiter with a small interval to prevent network flooding
	rateLimitInterval := time.Millisecond * 10 // 10ms between token replenishment

	return &PortScanner{
		concurrency:   concurrency,
		timeout:       timeout,
		serviceDB:     NewServiceDatabase(),
		bannerGrabber: NewBannerGrabber(),
		rateLimiter:   NewRateLimiter(concurrency, rateLimitInterval),
	}
}

// ScanPorts performs a port scan on the specified targets and ports
func (ps *PortScanner) ScanPorts(ctx context.Context, targets []string, portRanges []PortRange, scanType ScanType, progressChan chan<- ScanProgressUpdate) error {
	// Calculate total ports to scan
	totalPorts := 0
	for _, target := range targets {
		_ = target // Used for calculating total ports per target
		for _, portRange := range portRanges {
			totalPorts += portRange.End - portRange.Start + 1
		}
	}

	progress := &ScanProgress{
		TotalPorts: totalPorts,
		StartTime:  time.Now(),
		Status:     "Starting scan...",
	}

	// Send initial progress
	select {
	case progressChan <- ScanProgressUpdate{Progress: progress}:
	case <-ctx.Done():
		return ctx.Err()
	}

	// Use rate limiter for concurrency control and network flood prevention
	var wg sync.WaitGroup
	var mu sync.Mutex

	// Scan each target and port combination
	for _, target := range targets {
		for _, portRange := range portRanges {
			for port := portRange.Start; port <= portRange.End; port++ {
				select {
				case <-ctx.Done():
					progress.Cancelled = true
					progress.Status = "Scan cancelled"
					progressChan <- ScanProgressUpdate{Progress: progress}
					ps.rateLimiter.Close()
					return ctx.Err()
				default:
					// Acquire rate limit token
					if err := ps.rateLimiter.Acquire(ctx); err != nil {
						progress.Cancelled = true
						progress.Status = "Scan cancelled"
						progressChan <- ScanProgressUpdate{Progress: progress}
						ps.rateLimiter.Close()
						return err
					}

					wg.Add(1)
					go func(target string, port int) {
						defer wg.Done()
						defer ps.rateLimiter.Release()

						// Update current scan target
						mu.Lock()
						progress.CurrentTarget = target
						progress.CurrentPort = port
						progress.Status = fmt.Sprintf("Scanning %s:%d", target, port)
						mu.Unlock()

						// Perform the actual port scan
						result := ps.scanSinglePort(ctx, target, port, scanType)

						// Update progress
						mu.Lock()
						progress.ScannedPorts++
						switch result.State {
						case PortStateOpen:
							progress.OpenPorts++
						case PortStateClosed:
							progress.ClosedPorts++
						case PortStateFiltered:
							progress.FilteredPorts++
						}

						// Update estimated end time
						if progress.ScannedPorts > 0 {
							elapsed := time.Since(progress.StartTime)
							avgTimePerPort := elapsed / time.Duration(progress.ScannedPorts)
							remaining := progress.TotalPorts - progress.ScannedPorts
							progress.EstimatedEnd = time.Now().Add(avgTimePerPort * time.Duration(remaining))
						}
						mu.Unlock()

						// Send progress update
						select {
						case progressChan <- ScanProgressUpdate{Progress: progress, Result: &result}:
						case <-ctx.Done():
							return
						}
					}(target, port)
				}
			}
		}
	}

	// Wait for all scans to complete
	wg.Wait()

	// Clean up rate limiter
	ps.rateLimiter.Close()

	// Check if scan was cancelled after completion
	select {
	case <-ctx.Done():
		progress.Cancelled = true
		progress.Status = "Scan cancelled"
		progressChan <- ScanProgressUpdate{Progress: progress}
		return ctx.Err()
	default:
	}

	// Send final progress
	progress.Completed = true
	progress.Status = "Scan completed"
	progressChan <- ScanProgressUpdate{Progress: progress}

	return nil
}

// scanSinglePort scans a single port on a target
func (ps *PortScanner) scanSinglePort(ctx context.Context, target string, port int, scanType ScanType) ScanResult {
	// Check for cancellation before starting
	select {
	case <-ctx.Done():
		return ScanResult{
			Host:      target,
			Port:      port,
			Protocol:  "tcp",
			State:     PortStateUnknown,
			Timestamp: time.Now(),
			Error:     "Scan cancelled",
		}
	default:
	}

	result := ScanResult{
		Host:      target,
		Port:      port,
		Protocol:  "tcp", // Default to TCP
		Timestamp: time.Now(),
	}

	startTime := time.Now()

	switch scanType {
	case ScanTypeTCP, ScanTypeConnect:
		result = ps.scanTCPPort(ctx, target, port)
	case ScanTypeUDP:
		result.Protocol = "udp"
		result = ps.scanUDPPort(ctx, target, port)
	case ScanTypeSYN:
		result = ps.scanSYNPort(ctx, target, port)
	case ScanTypeComprehensive:
		// Try TCP first, then UDP if TCP is closed
		result = ps.scanTCPPort(ctx, target, port)
		if result.State == PortStateClosed {
			// Check for cancellation before UDP scan
			select {
			case <-ctx.Done():
				result.Error = "Scan cancelled"
				return result
			default:
			}
			udpResult := ps.scanUDPPort(ctx, target, port)
			if udpResult.State == PortStateOpen {
				result = udpResult
			}
		}
	}

	result.ResponseTime = time.Since(startTime)

	// Check for cancellation before service detection
	select {
	case <-ctx.Done():
		result.Error = "Scan cancelled"
		return result
	default:
	}

	// Perform service detection and banner grabbing for open ports
	if result.State == PortStateOpen {
		if serviceInfo, exists := ps.serviceDB.GetService(port); exists {
			result.Service = serviceInfo.Name
		}

		if banner := ps.bannerGrabber.GrabBanner(target, port); banner != "" {
			result.Banner = banner
			// Try to extract version information from banner
			if version := ps.extractVersionFromBanner(banner, result.Service); version != "" {
				result.Version = version
			}
		}
	}

	return result
}

// scanTCPPort performs a TCP connect scan on a port
func (ps *PortScanner) scanTCPPort(ctx context.Context, target string, port int) ScanResult {
	result := ScanResult{
		Host:      target,
		Port:      port,
		Protocol:  "tcp",
		Timestamp: time.Now(),
	}

	address := fmt.Sprintf("%s:%d", target, port)

	// Create a context with timeout
	timeoutCtx, cancel := context.WithTimeout(ctx, ps.timeout)
	defer cancel()

	// Attempt to connect
	dialer := &net.Dialer{}
	conn, err := dialer.DialContext(timeoutCtx, "tcp", address)
	if err != nil {
		if timeoutCtx.Err() == context.DeadlineExceeded {
			result.State = PortStateFiltered
			result.Error = "Connection timeout"
		} else {
			result.State = PortStateClosed
			result.Error = err.Error()
		}
		return result
	}

	conn.Close()
	result.State = PortStateOpen
	return result
}

// scanUDPPort performs a UDP scan on a port
func (ps *PortScanner) scanUDPPort(ctx context.Context, target string, port int) ScanResult {
	result := ScanResult{
		Host:      target,
		Port:      port,
		Protocol:  "udp",
		Timestamp: time.Now(),
	}

	address := fmt.Sprintf("%s:%d", target, port)

	// Create a context with timeout
	timeoutCtx, cancel := context.WithTimeout(ctx, ps.timeout)
	defer cancel()

	// UDP scanning is more complex - we'll use a simple approach
	var d net.Dialer
	conn, err := d.DialContext(timeoutCtx, "udp", address)
	if err != nil {
		result.State = PortStateFiltered
		result.Error = err.Error()
		return result
	}
	defer conn.Close()

	// Send a probe packet
	_, err = conn.Write([]byte("probe"))
	if err != nil {
		result.State = PortStateFiltered
		result.Error = err.Error()
		return result
	}

	// Try to read response with timeout
	conn.SetReadDeadline(time.Now().Add(ps.timeout))
	buffer := make([]byte, 1024)
	_, err = conn.Read(buffer)
	if err != nil {
		// No response doesn't necessarily mean closed for UDP
		result.State = PortStateOpen // Assume open if we can connect
	} else {
		result.State = PortStateOpen
	}

	return result
}

// scanSYNPort performs a SYN scan (requires raw sockets - simplified implementation)
func (ps *PortScanner) scanSYNPort(ctx context.Context, target string, port int) ScanResult {
	// SYN scanning requires raw sockets and root privileges
	// For now, fall back to TCP connect scan
	// In a full implementation, this would use raw sockets to send SYN packets
	return ps.scanTCPPort(ctx, target, port)
}

// extractVersionFromBanner attempts to extract version information from a banner
func (ps *PortScanner) extractVersionFromBanner(banner, service string) string {
	// Simple version extraction - in a real implementation, this would be more sophisticated
	banner = strings.ToLower(banner)

	// Look for common version patterns
	patterns := []string{
		`version (\d+\.\d+\.\d+)`,
		`v(\d+\.\d+\.\d+)`,
		`(\d+\.\d+\.\d+)`,
		`(\d+\.\d+)`,
	}

	for _, pattern := range patterns {
		// Simple pattern matching - in a real implementation, use regex
		_ = pattern // TODO: implement proper regex matching
		if strings.Contains(banner, "version") {
			parts := strings.Fields(banner)
			for i, part := range parts {
				if part == "version" && i+1 < len(parts) {
					return parts[i+1]
				}
			}
		}
	}

	return ""
}

