// handleHistoryKeys handles key presses in the history view
func (psm *PortScannerModel) handleHistoryKeys(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.showHistory = false
		return nil

	case "up", "k":
		if psm.selectedRow > 0 {
			psm.selectedRow--
		}
		return nil

	case "down", "j":
		if psm.selectedRow < len(psm.scanHistory)-1 {
			psm.selectedRow++
		}
		return nil

	case "enter":
		if len(psm.scanHistory) > 0 && psm.selectedRow < len(psm.scanHistory) {
			// Load results from selected history entry
			scan := psm.scanHistory[psm.selectedRow]
			psm.scanResults = scan.Results
			psm.showHistory = false
			psm.selectedRow = 0
			psm.scrollOffset = 0
		}
		return nil

	case "d":
		if len(psm.scanHistory) > 0 && psm.selectedRow < len(psm.scanHistory) {
			// Delete selected history entry
			psm.scanHistory = append(psm.scanHistory[:psm.selectedRow], psm.scanHistory[psm.selectedRow+1:]...)
			if psm.selectedRow >= len(psm.scanHistory) && len(psm.scanHistory) > 0 {
				psm.selectedRow = len(psm.scanHistory) - 1
			}
		}
		return nil
	}

	return nil
}

