	}

	var s strings.Builder

	progressStyle := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#10b981")).
		Padding(0, 1).
		Width(psm.width - 4)

