// min function is defined in system_monitor.go

// handleExportKeys handles key presses in the export view
func (psm *PortScannerModel) handleExportKeys(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.showExport = false
		psm.inputMode = InputModeNone
		return nil

	case "1":
		psm.exportFormat = ExportFormatJSON
		return nil

	case "2":
		psm.exportFormat = ExportFormatCSV
		return nil

	case "3":
		psm.exportFormat = ExportFormatXML
		return nil

	case "4":
		psm.exportFormat = ExportFormatTXT
		return nil

	case "f":
		psm.inputMode = InputModeTarget // Reuse for filename input
		psm.exportFilename = ""
		return nil

	case "enter":
		if psm.inputMode == InputModeTarget {
			// Apply filename and export
			psm.inputMode = InputModeNone
			return psm.exportWithFilename()
		} else {
			// Export with default filename
			return psm.exportCurrentResults()
		}

	case "backspace":
		if psm.inputMode == InputModeTarget && len(psm.exportFilename) > 0 {
			psm.exportFilename = psm.exportFilename[:len(psm.exportFilename)-1]
		}
		return nil

	default:
		if psm.inputMode == InputModeTarget && len(key) == 1 {
			psm.exportFilename += key
		}
		return nil
	}
}

// handleComparisonKeys handles key presses in the comparison view
func (psm *PortScannerModel) handleComparisonKeys(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.showComparison = false
		return nil

	case "up", "k":
		if psm.selectedRow > 0 {
			psm.selectedRow--
		}
		return nil

	case "down", "j":
		historyEntries, _ := psm.historyManager.GetHistory()
		if psm.selectedRow < len(historyEntries)-1 {
			psm.selectedRow++
		}
		return nil

	case "enter":
		// Compare with selected history entry
		historyEntries, err := psm.historyManager.GetHistory()
		if err != nil || psm.selectedRow >= len(historyEntries) {
			return nil
		}

		selectedEntry := historyEntries[psm.selectedRow]
		return psm.compareWithHistory(selectedEntry.ID)
	}

	return nil
}

// exportCurrentResults exports the current scan results
func (psm *PortScannerModel) exportCurrentResults() tea.Cmd {
	return func() tea.Msg {
		err := psm.exporter.ExportResults(psm.scanResults, psm.exportFormat, "")
		if err != nil {
			return errMsg(fmt.Errorf("export failed: %w", err))
		}
		psm.showExport = false
		return nil
	}
}

// exportWithFilename exports with a custom filename
func (psm *PortScannerModel) exportWithFilename() tea.Cmd {
	filename := psm.exportFilename
	return func() tea.Msg {
		err := psm.exporter.ExportResults(psm.scanResults, psm.exportFormat, filename)
		if err != nil {
			return errMsg(fmt.Errorf("export failed: %w", err))
		}
		psm.showExport = false
		return nil
	}
}

// compareWithHistory compares current results with a historical scan
func (psm *PortScannerModel) compareWithHistory(historyID string) tea.Cmd {
	return func() tea.Msg {
		// Create a temporary scan from current results
		currentScan := CompletedScan{
			ID:        "current",
			StartTime: time.Now(),
			Results:   psm.scanResults,
		}

		// Get historical scan
		historicalScan, err := psm.historyManager.GetScan(historyID)
		if err != nil {
			return errMsg(fmt.Errorf("failed to load historical scan: %w", err))
		}

		// Perform comparison
		comparison := psm.comparator.compareScanData(currentScan, *historicalScan)

		// Generate and display report (this would need UI implementation)
		report := psm.comparator.GenerateComparisonReport(comparison)
		_ = report // TODO: Display in UI

		psm.showComparison = false
		return nil
	}
}

// renderExportView renders the export dialog
func (psm *PortScannerModel) renderExportView() string {
	if !psm.showExport {
		return ""
	}

	var s strings.Builder

	title := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#00ff00")).
		Bold(true).
		Render("📤 EXPORT SCAN RESULTS")
	s.WriteString(title + "\n\n")

	// Format selection
	s.WriteString("Select Export Format:\n")
	formats := []struct {
		key    string
		format ExportFormat
		desc   string
	}{
		{"1", ExportFormatJSON, "JSON - Structured data format"},
		{"2", ExportFormatCSV, "CSV - Comma-separated values"},
		{"3", ExportFormatXML, "XML - Extensible markup language"},
		{"4", ExportFormatTXT, "TXT - Human-readable text"},
	}

	for _, f := range formats {
		style := lipgloss.NewStyle().Foreground(lipgloss.Color("#888888"))
		if f.format == psm.exportFormat {
			style = style.Foreground(lipgloss.Color("#00ff00")).Bold(true)
		}
		s.WriteString(style.Render(fmt.Sprintf("  %s. %s\n", f.key, f.desc)))
	}

	s.WriteString("\n")

	// Filename input
	if psm.inputMode == InputModeTarget {
		s.WriteString("Filename: " + psm.exportFilename + "_\n")
	} else {
		s.WriteString("Press 'f' to specify filename (optional)\n")
	}

	s.WriteString("\nControls:\n")
	s.WriteString("  ENTER: Export with current settings\n")
	s.WriteString("  ESC: Cancel\n")

	return s.String()
}

// renderComparisonView renders the comparison dialog
func (psm *PortScannerModel) renderComparisonView() string {
	if !psm.showComparison {
		return ""
	}

	var s strings.Builder

	title := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#ffff00")).
		Bold(true).
		Render("🔍 COMPARE WITH HISTORICAL SCAN")
	s.WriteString(title + "\n\n")

	// Get history entries
	historyEntries, err := psm.historyManager.GetHistory()
	if err != nil || len(historyEntries) == 0 {
		s.WriteString("No historical scans available for comparison.\n")
		s.WriteString("Press ESC to cancel.\n")
		return s.String()
	}

	s.WriteString("Select a historical scan to compare with:\n\n")

	// Display history entries
	maxEntries := min(len(historyEntries), 10)
	for i := 0; i < maxEntries; i++ {
		entry := historyEntries[i]
		style := lipgloss.NewStyle().Foreground(lipgloss.Color("#888888"))
		if i == psm.selectedRow {
			style = style.Foreground(lipgloss.Color("#ffff00")).Bold(true)
		}

		line := fmt.Sprintf("  %s - %s (%d ports, %d open)",
			entry.StartTime.Format("2006-01-02 15:04"),
			strings.Join(entry.Targets, ", "),
			entry.TotalPorts,
			entry.OpenPorts)

		if len(line) > 60 {
			line = line[:57] + "..."
		}

		s.WriteString(style.Render(line) + "\n")
	}

	s.WriteString("\nControls:\n")
	s.WriteString("  ↑↓: Navigate  ENTER: Compare  ESC: Cancel\n")

	return s.String()
}

