// PackageManager defines the interface that all package managers must implement
// Implements Task 4.1 - Package Manager Abstraction Layer
type PackageManager interface {
	// GetName returns the name of the package manager
	GetName() string

	// IsAvailable checks if the package manager is available on the system
	IsAvailable() bool

	// IsProjectSupported checks if the current directory supports this package manager
	IsProjectSupported(projectPath string) bool

	// ListPackages returns all installed packages
	ListPackages(ctx context.Context) ([]Package, error)

	// InstallPackage installs a package
	InstallPackage(ctx context.Context, packageName, version string) error

	// UpdatePackage updates a package to the latest or specified version
	UpdatePackage(ctx context.Context, packageName, version string) error

	// RemovePackage removes a package
	RemovePackage(ctx context.Context, packageName string) error

	// SearchPackages searches for packages matching the query
	SearchPackages(ctx context.Context, query string) ([]PackageSearchResult, error)

	// GetPackageInfo retrieves detailed information about a package
	GetPackageInfo(ctx context.Context, packageName string) (*PackageInfo, error)

	// UpdateAll updates all packages to their latest versions
	UpdateAll(ctx context.Context) error

	// CleanCache cleans the package manager cache
	CleanCache(ctx context.Context) error

	// GetDependencyTree returns the dependency tree for a package
	GetDependencyTree(ctx context.Context, packageName string) (*DependencyTree, error)

	// CheckSecurity checks for security vulnerabilities in packages
	CheckSecurity(ctx context.Context) ([]SecurityIssue, error)
}

// Package represents an installed package
type Package struct {
	Name          string    `json:"name"`
	Version       string    `json:"version"`
	Description   string    `json:"description"`
	Author        string    `json:"author"`
	License       string    `json:"license"`
	Homepage      string    `json:"homepage"`
	InstallDate   time.Time `json:"install_date"`
	Size          int64     `json:"size"`
	Dependencies  []string  `json:"dependencies"`
	DevDependency bool      `json:"dev_dependency"`
}

// PackageSearchResult represents a package found in search results
type PackageSearchResult struct {
	Name        string  `json:"name"`
	Version     string  `json:"version"`
	Description string  `json:"description"`
	Author      string  `json:"author"`
	Downloads   int64   `json:"downloads"`
	Score       float64 `json:"score"`
	Repository  string  `json:"repository"`
}

// PackageInfo contains detailed information about a package
type PackageInfo struct {
	Package
	Keywords     []string                  `json:"keywords"`
	Repository   string                    `json:"repository"`
	BugTracker   string                    `json:"bug_tracker"`
	Downloads    int64                     `json:"downloads"`
	LastUpdated  time.Time                 `json:"last_updated"`
	Versions     []string                  `json:"versions"`
	Dependencies map[string]DependencyInfo `json:"dependencies"`
	Maintainers  []string                  `json:"maintainers"`
	Tags         []string                  `json:"tags"`
}

// DependencyInfo represents information about a dependency
type DependencyInfo struct {
	Version     string `json:"version"`
	Required    bool   `json:"required"`
	Development bool   `json:"development"`
	Optional    bool   `json:"optional"`
}

// DependencyTree represents a tree of dependencies
type DependencyTree struct {
	Package      Package              `json:"package"`
	Dependencies []*DependencyTree    `json:"dependencies"`
	Conflicts    []DependencyConflict `json:"conflicts"`
	Depth        int                  `json:"depth"`
}

// DependencyConflict represents a dependency conflict
type DependencyConflict struct {
	Package1        string `json:"package1"`
	Package2        string `json:"package2"`
	ConflictReason  string `json:"conflict_reason"`
	Severity        string `json:"severity"`
	ResolveStrategy string `json:"resolve_strategy"`
}

// SecurityIssue represents a security vulnerability
type SecurityIssue struct {
	Package     string    `json:"package"`
	Version     string    `json:"version"`
	Advisory    string    `json:"advisory"`
	Severity    string    `json:"severity"`
	Title       string    `json:"title"`
	Description string    `json:"description"`
	Reference   string    `json:"reference"`
	FixVersion  string    `json:"fix_version"`
	PublishDate time.Time `json:"publish_date"`
}

// PackageManagerRegistry manages multiple package managers
type PackageManagerRegistry struct {
	managers        map[string]PackageManager
	projectPath     string
	securityChecker SecurityChecker
}

// SecurityChecker interface for checking package security
type SecurityChecker interface {
	CheckPackageSecurity(ctx context.Context, manager PackageManager, packageName, version string) ([]SecurityIssue, error)
}

// NewPackageManagerRegistry creates a new package manager registry
func NewPackageManagerRegistry(projectPath string) *PackageManagerRegistry {
	registry := &PackageManagerRegistry{
		managers:    make(map[string]PackageManager),
		projectPath: projectPath,
	}

	// Register built-in package managers
	registry.RegisterManager(&NPMManager{})
	registry.RegisterManager(&GoModManager{})
	registry.RegisterManager(&PipManager{})

	return registry
}

// RegisterManager registers a new package manager
func (r *PackageManagerRegistry) RegisterManager(manager PackageManager) {
	r.managers[manager.GetName()] = manager
}

// GetAvailableManagers returns all available package managers
func (r *PackageManagerRegistry) GetAvailableManagers() []PackageManager {
	var available []PackageManager
	for _, manager := range r.managers {
		if manager.IsAvailable() && manager.IsProjectSupported(r.projectPath) {
			available = append(available, manager)
		}
	}
	return available
}

// GetManager returns a specific package manager by name
func (r *PackageManagerRegistry) GetManager(name string) (PackageManager, bool) {
	manager, exists := r.managers[name]
	return manager, exists
}

// DetectProjectManagers detects which package managers are supported by the current project
func (r *PackageManagerRegistry) DetectProjectManagers() []PackageManager {
	var supported []PackageManager
	for _, manager := range r.managers {
		if manager.IsProjectSupported(r.projectPath) {
			supported = append(supported, manager)
		}
	}
	return supported
}

// NPMManager implements PackageManager for npm
type NPMManager struct{}

// GetName returns the name of npm package manager
func (n *NPMManager) GetName() string {
	return "npm"
}

// IsAvailable checks if npm is available on the system
func (n *NPMManager) IsAvailable() bool {
	_, err := exec.LookPath("npm")
	return err == nil
}

// IsProjectSupported checks if the current directory has a package.json
func (n *NPMManager) IsProjectSupported(projectPath string) bool {
	packageJSON := filepath.Join(projectPath, "package.json")
	_, err := os.Stat(packageJSON)
	return err == nil
}

// ListPackages returns all installed npm packages
func (n *NPMManager) ListPackages(ctx context.Context) ([]Package, error) {
	cmd := exec.CommandContext(ctx, "npm", "list", "--json", "--depth=0")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to list npm packages: %w", err)
	}

	var result struct {
		Dependencies map[string]struct {
			Version  string `json:"version"`
			Resolved string `json:"resolved"`
		} `json:"dependencies"`
	}

	if err := json.Unmarshal(output, &result); err != nil {
		return nil, fmt.Errorf("failed to parse npm list output: %w", err)
	}

	var packages []Package
	for name, dep := range result.Dependencies {
		packages = append(packages, Package{
			Name:    name,
			Version: dep.Version,
		})
	}

	sort.Slice(packages, func(i, j int) bool {
		return packages[i].Name < packages[j].Name
	})

	return packages, nil
}

// InstallPackage installs an npm package
func (n *NPMManager) InstallPackage(ctx context.Context, packageName, version string) error {
	var cmd *exec.Cmd
	if version != "" {
		cmd = exec.CommandContext(ctx, "npm", "install", packageName+"@"+version)
	} else {
		cmd = exec.CommandContext(ctx, "npm", "install", packageName)
	}

	return cmd.Run()
}

// UpdatePackage updates an npm package
func (n *NPMManager) UpdatePackage(ctx context.Context, packageName, version string) error {
	var cmd *exec.Cmd
	if version != "" {
		cmd = exec.CommandContext(ctx, "npm", "update", packageName+"@"+version)
	} else {
		cmd = exec.CommandContext(ctx, "npm", "update", packageName)
	}

	return cmd.Run()
}

// RemovePackage removes an npm package
func (n *NPMManager) RemovePackage(ctx context.Context, packageName string) error {
	cmd := exec.CommandContext(ctx, "npm", "uninstall", packageName)
	return cmd.Run()
}

// SearchPackages searches for npm packages
func (n *NPMManager) SearchPackages(ctx context.Context, query string) ([]PackageSearchResult, error) {
	cmd := exec.CommandContext(ctx, "npm", "search", query, "--json")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to search npm packages: %w", err)
	}

	var results []struct {
		Name        string   `json:"name"`
		Version     string   `json:"version"`
		Description string   `json:"description"`
		Author      string   `json:"author"`
		Keywords    []string `json:"keywords"`
		Score       struct {
			Final float64 `json:"final"`
		} `json:"score"`
	}

	if err := json.Unmarshal(output, &results); err != nil {
		return nil, fmt.Errorf("failed to parse npm search output: %w", err)
	}

	var packages []PackageSearchResult
	for _, result := range results {
		packages = append(packages, PackageSearchResult{
			Name:        result.Name,
			Version:     result.Version,
			Description: result.Description,
			Author:      result.Author,
			Score:       result.Score.Final,
		})
	}

	return packages, nil
}

// GetPackageInfo retrieves detailed information about an npm package
func (n *NPMManager) GetPackageInfo(ctx context.Context, packageName string) (*PackageInfo, error) {
	cmd := exec.CommandContext(ctx, "npm", "info", packageName, "--json")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to get npm package info: %w", err)
	}

	var info struct {
		Name         string            `json:"name"`
		Version      string            `json:"version"`
		Description  string            `json:"description"`
		Author       string            `json:"author"`
		License      string            `json:"license"`
		Homepage     string            `json:"homepage"`
		Keywords     []string          `json:"keywords"`
		Dependencies map[string]string `json:"dependencies"`
		Repository   struct {
			URL string `json:"url"`
		} `json:"repository"`
		Bugs struct {
			URL string `json:"url"`
		} `json:"bugs"`
		Time struct {
			Modified string `json:"modified"`
		} `json:"time"`
		Versions []string `json:"versions"`
	}

	if err := json.Unmarshal(output, &info); err != nil {
		return nil, fmt.Errorf("failed to parse npm info output: %w", err)
	}

	lastUpdated, _ := time.Parse(time.RFC3339, info.Time.Modified)

	deps := make(map[string]DependencyInfo)
	for name, version := range info.Dependencies {
		deps[name] = DependencyInfo{
			Version:  version,
			Required: true,
		}
	}

	return &PackageInfo{
		Package: Package{
			Name:        info.Name,
			Version:     info.Version,
			Description: info.Description,
			Author:      info.Author,
			License:     info.License,
			Homepage:    info.Homepage,
		},
		Keywords:     info.Keywords,
		Repository:   info.Repository.URL,
		BugTracker:   info.Bugs.URL,
		LastUpdated:  lastUpdated,
		Versions:     info.Versions,
		Dependencies: deps,
	}, nil
}

