// CheckSecurity checks for security vulnerabilities in npm packages
func (n *NPMManager) CheckSecurity(ctx context.Context) ([]SecurityIssue, error) {
	cmd := exec.CommandContext(ctx, "npm", "audit", "--json")
	output, err := cmd.Output()
	if err != nil {
		// npm audit returns non-zero exit code when vulnerabilities are found
		if exitError, ok := err.(*exec.ExitError); ok {
			output = exitError.Stderr
		} else {
			return nil, fmt.Errorf("failed to run npm audit: %w", err)
		}
	}

	var result struct {
		Vulnerabilities map[string]struct {
			Severity string `json:"severity"`
			Title    string `json:"title"`
			URL      string `json:"url"`
			Range    string `json:"range"`
		} `json:"vulnerabilities"`
	}

	if err := json.Unmarshal(output, &result); err != nil {
		return nil, fmt.Errorf("failed to parse npm audit output: %w", err)
	}

	var issues []SecurityIssue
	for pkg, vuln := range result.Vulnerabilities {
		issues = append(issues, SecurityIssue{
			Package:     pkg,
			Advisory:    vuln.URL,
			Severity:    vuln.Severity,
			Title:       vuln.Title,
			Reference:   vuln.URL,
			PublishDate: time.Now(), // npm audit doesn't provide publish date
		})
	}

	return issues, nil
}

