	return err == nil
}

// IsProjectSupported checks if the current directory has a go.mod
func (g *GoModManager) IsProjectSupported(projectPath string) bool {
	goMod := filepath.Join(projectPath, "go.mod")
	_, err := os.Stat(goMod)
	return err == nil
}

// ListPackages returns all Go module dependencies
func (g *GoModManager) ListPackages(ctx context.Context) ([]Package, error) {
	cmd := exec.CommandContext(ctx, "go", "list", "-m", "-json", "all")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to list go modules: %w", err)
	}

	var packages []Package
	decoder := json.NewDecoder(strings.NewReader(string(output)))

	for decoder.More() {
		var mod struct {
			Path    string `json:"Path"`
			Version string `json:"Version"`
			Main    bool   `json:"Main"`
		}

		if err := decoder.Decode(&mod); err != nil {
			continue
		}

		if !mod.Main { // Skip the main module
			packages = append(packages, Package{
				Name:    mod.Path,
				Version: mod.Version,
			})
		}
	}

	sort.Slice(packages, func(i, j int) bool {
		return packages[i].Name < packages[j].Name
	})

	return packages, nil
}

