// PipManager implements PackageManager for pip
type PipManager struct{}

// GetName returns the name of pip package manager
func (p *PipManager) GetName() string {
	return "pip"
}

// IsAvailable checks if pip is available on the system
func (p *PipManager) IsAvailable() bool {
	_, err := exec.LookPath("pip")
	return err == nil
}

// IsProjectSupported checks if the current directory has Python files or requirements.txt
func (p *PipManager) IsProjectSupported(projectPath string) bool {
	// Check for requirements.txt or any .py files
	requirementsTxt := filepath.Join(projectPath, "requirements.txt")
	if _, err := os.Stat(requirementsTxt); err == nil {
		return true
	}

	// Check for Python files
	entries, err := os.ReadDir(projectPath)
	if err != nil {
		return false
	}

	for _, entry := range entries {
		if strings.HasSuffix(entry.Name(), ".py") {
			return true
		}
	}

	return false
}

// ListPackages returns all installed pip packages
func (p *PipManager) ListPackages(ctx context.Context) ([]Package, error) {
	cmd := exec.CommandContext(ctx, "pip", "list", "--format=json")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to list pip packages: %w", err)
	}

	var results []struct {
		Name    string `json:"name"`
		Version string `json:"version"`
	}

	if err := json.Unmarshal(output, &results); err != nil {
		return nil, fmt.Errorf("failed to parse pip list output: %w", err)
	}

	var packages []Package
	for _, result := range results {
		packages = append(packages, Package{
			Name:    result.Name,
			Version: result.Version,
		})
	}

	sort.Slice(packages, func(i, j int) bool {
		return packages[i].Name < packages[j].Name
	})

	return packages, nil
}

// InstallPackage installs a pip package
func (p *PipManager) InstallPackage(ctx context.Context, packageName, version string) error {
	var cmd *exec.Cmd
	if version != "" {
		cmd = exec.CommandContext(ctx, "pip", "install", packageName+"=="+version)
	} else {
		cmd = exec.CommandContext(ctx, "pip", "install", packageName)
	}

	return cmd.Run()
}

// UpdatePackage updates a pip package
func (p *PipManager) UpdatePackage(ctx context.Context, packageName, version string) error {
	var cmd *exec.Cmd
	if version != "" {
		cmd = exec.CommandContext(ctx, "pip", "install", "--upgrade", packageName+"=="+version)
	} else {
		cmd = exec.CommandContext(ctx, "pip", "install", "--upgrade", packageName)
	}

	return cmd.Run()
}

// RemovePackage removes a pip package
func (p *PipManager) RemovePackage(ctx context.Context, packageName string) error {
	cmd := exec.CommandContext(ctx, "pip", "uninstall", "-y", packageName)
	return cmd.Run()
}

// SearchPackages searches for pip packages
func (p *PipManager) SearchPackages(ctx context.Context, query string) ([]PackageSearchResult, error) {
	// pip search was disabled, would need to use PyPI API
	return nil, fmt.Errorf("search not available for pip (deprecated), use PyPI web interface")
}

// GetPackageInfo retrieves detailed information about a pip package
func (p *PipManager) GetPackageInfo(ctx context.Context, packageName string) (*PackageInfo, error) {
	cmd := exec.CommandContext(ctx, "pip", "show", packageName)
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to get pip package info: %w", err)
	}

	// Parse pip show output (key: value format)
	lines := strings.Split(string(output), "\n")
	info := &PackageInfo{}

	for _, line := range lines {
		if strings.Contains(line, ":") {
			parts := strings.SplitN(line, ":", 2)
			if len(parts) != 2 {
				continue
			}
			key := strings.TrimSpace(parts[0])
			value := strings.TrimSpace(parts[1])

			switch key {
			case "Name":
				info.Name = value
			case "Version":
				info.Version = value
			case "Summary":
				info.Description = value
			case "Author":
				info.Author = value
			case "License":
				info.License = value
			case "Home-page":
				info.Homepage = value
			}
		}
	}

	return info, nil
}

// UpdateAll updates all pip packages
func (p *PipManager) UpdateAll(ctx context.Context) error {
	// pip doesn't have a built-in update all command
	// This would require listing all packages and updating each one
	return fmt.Errorf("update all not supported by pip directly")
}

// CleanCache cleans the pip cache
func (p *PipManager) CleanCache(ctx context.Context) error {
	cmd := exec.CommandContext(ctx, "pip", "cache", "purge")
	return cmd.Run()
}

// GetDependencyTree returns the dependency tree for a pip package
func (p *PipManager) GetDependencyTree(ctx context.Context, packageName string) (*DependencyTree, error) {
	return nil, fmt.Errorf("dependency tree not implemented for pip yet")
}

// CheckSecurity checks for security vulnerabilities in pip packages
func (p *PipManager) CheckSecurity(ctx context.Context) ([]SecurityIssue, error) {
	// This would require a tool like safety or pip-audit
	if !p.hasSafety() {
		return nil, fmt.Errorf("safety not available, install with: pip install safety")
	}

	cmd := exec.CommandContext(ctx, "safety", "check", "--json")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to run safety check: %w", err)
	}

	// Parse safety JSON output (simplified)
	var issues []SecurityIssue
	// This would need proper JSON parsing of safety output
	_ = output

	return issues, nil
}

// hasSafety checks if safety is available
func (p *PipManager) hasSafety() bool {
	_, err := exec.LookPath("safety")
	return err == nil
}

