	aiAssistant := NewAIAssistantModel()

	// Register components with the view manager
	viewRouter.GetViewManager().RegisterComponent(ViewSettings, settingsPage)
	viewRouter.GetViewManager().RegisterComponent(ViewAIAssistant, aiAssistant)

	m := model{
