	// Initialize light rays
	for i := range m.lightRays {
		m.lightRays[i] = lightRay{
			x:         rand.Float64() * 120,
			y:         rand.Float64() * 40,
			angle:     rand.Float64() * 6.28,
			length:    rand.Float64()*15 + 5,
			intensity: rand.Float64()*0.6 + 0.1,
			color:     colors[rand.Intn(len(colors))],
		}
	}

	// Initialize matrix rain
	chars := []rune("ﾊﾐﾋｰｳｼﾅﾓﾆｻﾜﾂｵﾘｱﾎﾃﾏｹﾒｴｶｷﾑﾕﾗｾﾈｽﾀﾇﾍ0123456789")
	for i := range m.matrixRain {
		m.matrixRain[i] = matrixDrop{
			x:         float64(rand.Intn(120)),
			y:         rand.Float64() * 40,
			speed:     rand.Float64()*0.3 + 0.1,
			length:    rand.Intn(8) + 3,
			chars:     make([]rune, rand.Intn(8)+3),
			intensity: rand.Float64()*0.7 + 0.3,
		}
		for j := range m.matrixRain[i].chars {
			m.matrixRain[i].chars[j] = chars[rand.Intn(len(chars))]
		}
	}

	// Initialize global colors from theme
	m.updateGlobalColors()

	// Initialize energy field
	for i := range m.energyField {
		connections := make([]int, 0)
		// Connect to 1-3 random other nodes
		numConnections := rand.Intn(3) + 1
		for j := 0; j < numConnections; j++ {
			target := rand.Intn(len(m.energyField))
			if target != i {
				connections = append(connections, target)
			}
		}

		m.energyField[i] = energyNode{
			x:           rand.Float64() * 120,
			y:           rand.Float64() * 40,
			connections: connections,
			pulsePhase:  rand.Float64() * 6.28,
			energy:      rand.Float64()*0.8 + 0.2,
		}
	}

	return m
}

func (m model) Init() tea.Cmd {
	return tea.Batch(
		tea.EnterAltScreen,
		tick(),
		fetchProcesses(),
		fetchNetworkData(),
		fetchSystemAlerts(),
	)
}

func tick() tea.Cmd {
	return tea.Tick(time.Millisecond*50, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

func fetchProcesses() tea.Cmd {
	return func() tea.Msg {
		processes, stats := getProcessesAndStats()
		return processData{
			processes:   processes,
			systemStats: stats,
			lastUpdate:  time.Now(),
		}
	}
}

type networkData struct {
	connections []NetworkConnection
	interfaces  []NetworkInterface
	lastUpdate  time.Time
}

type alertData struct {
	alerts     []SystemAlert
	lastUpdate time.Time
}

func fetchNetworkData() tea.Cmd {
	return func() tea.Msg {
		connections := getNetworkConnections()
		interfaces := getNetworkInterfaces()
		return networkData{
			connections: connections,
			interfaces:  interfaces,
			lastUpdate:  time.Now(),
		}
	}
}

func fetchSystemAlerts() tea.Cmd {
	return func() tea.Msg {
		alerts := getSystemAlerts()
		return alertData{
			alerts:     alerts,
			lastUpdate: time.Now(),
		}
	}
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height

		// Update component sizes
		if m.settingsPage != nil {
			m.settingsPage.SetSize(msg.Width, msg.Height)
		}
		if m.aiAssistant != nil {
			m.aiAssistant.SetSize(msg.Width, msg.Height)
		}

		return m, nil

	case tea.KeyMsg:
		if m.showKillDialog {
			switch msg.String() {
			case "y", "Y":
				killProcess(m.killPID)
				m.showKillDialog = false
				return m, fetchProcesses()
			case "n", "N", "esc":
				m.showKillDialog = false
				return m, nil
			}
			return m, nil
		}

		if m.searchMode {
			switch msg.String() {
			case "esc":
				m.searchMode = false
				m.searchQuery = ""
				m.filteredProcs = m.processes
				return m, nil
			case "enter":
				m.searchMode = false
				return m, nil
			case "backspace":
				if len(m.searchQuery) > 0 {
					m.searchQuery = m.searchQuery[:len(m.searchQuery)-1]
					m.filteredProcs = filterProcesses(m.processes, m.searchQuery)
				}
				return m, nil
			default:
				if len(msg.String()) == 1 {
					m.searchQuery += msg.String()
					m.filteredProcs = filterProcesses(m.processes, m.searchQuery)
				}
				return m, nil
			}
		}

		switch {
		case key.Matches(msg, quitKeys):
			m.quitting = true
			return m, tea.Quit

		case key.Matches(msg, tabKeys):
			modes := []string{"overview", "processes", "network", "alerts", "settings", "ai"}
			currentIndex := 0
			for i, mode := range modes {
				if mode == m.viewMode {
					currentIndex = i
					break
				}
			}
			newMode := modes[(currentIndex+1)%len(modes)]
			m.viewMode = newMode

			// Handle component activation/deactivation
			m.deactivateAllComponents()
			if newMode == "settings" && m.settingsPage != nil {
				m.settingsPage.SetActive(true)
			} else if newMode == "ai" && m.aiAssistant != nil {
				m.aiAssistant.SetActive(true)
			}

			m.selectedRow = 0
			m.scrollOffset = 0
			return m, nil

		case msg.String() == "1":
			m.viewMode = "overview"
			m.deactivateAllComponents()
			return m, nil
		case msg.String() == "2":
			m.viewMode = "processes"
			m.deactivateAllComponents()
			return m, nil
		case msg.String() == "3":
			m.viewMode = "network"
			m.deactivateAllComponents()
			return m, nil
		case msg.String() == "4":
			m.viewMode = "alerts"
			m.deactivateAllComponents()
			return m, nil
		case msg.String() == "5":
			m.viewMode = "settings"
			m.deactivateAllComponents()
			if m.settingsPage != nil {
				m.settingsPage.SetActive(true)
			}
			return m, nil
		case msg.String() == "6":
			m.viewMode = "ai"
			m.deactivateAllComponents()
			if m.aiAssistant != nil {
				m.aiAssistant.SetActive(true)
			}
			return m, nil
		case msg.String() == "!":
			m.viewMode = "bash"
			return m, nil
		case msg.String() == "t":
			// Cycle through themes
			return m.cycleTheme()

		case key.Matches(msg, killKeys):
			if m.viewMode == "processes" && len(m.filteredProcs) > 0 && m.selectedRow < len(m.filteredProcs) {
				m.killPID = m.filteredProcs[m.selectedRow].PID
				m.showKillDialog = true
			}
			return m, nil

		case key.Matches(msg, searchKeys):
			if m.viewMode == "processes" {
				m.searchMode = true
				m.searchQuery = ""
			}
			return m, nil

		case msg.String() == "up", msg.String() == "k":
			if m.selectedRow > 0 {
				m.selectedRow--
				if m.selectedRow < m.scrollOffset {
					m.scrollOffset = m.selectedRow
				}
			}
			return m, nil

		case msg.String() == "down", msg.String() == "j":
			maxItems := 0
			switch m.viewMode {
			case "processes":
				maxItems = len(m.filteredProcs)
			case "network":
				maxItems = len(m.connections)
			case "alerts":
				maxItems = len(m.alerts)
			}

			if m.selectedRow < maxItems-1 {
				m.selectedRow++
				visibleRows := m.height - 15
				if m.selectedRow >= m.scrollOffset+visibleRows {
					m.scrollOffset = m.selectedRow - visibleRows + 1
				}
			}
			return m, nil

		case msg.String() == "c":
			if m.viewMode == "processes" {
				m.sortColumn = "CPU"
				m.sortProcesses()
			}
			return m, nil

		case msg.String() == "m":
			if m.viewMode == "processes" {
				m.sortColumn = "Memory"
				m.sortProcesses()
			}
			return m, nil

		case msg.String() == "p":
			if m.viewMode == "processes" {
				m.sortColumn = "PID"
				m.sortProcesses()
			}
			return m, nil
		}

		// Route messages to active components
		if m.viewMode == "settings" && m.settingsPage != nil && m.settingsPage.IsActive() {
			updatedComponent, cmd := m.settingsPage.Update(msg)
			if updatedComponent != nil {
				m.settingsPage = updatedComponent.(*SettingsPageModel)
			}
			if cmd != nil {
				return m, cmd
			}
		}

		if m.viewMode == "ai" && m.aiAssistant != nil && m.aiAssistant.IsActive() {
			updatedComponent, cmd := m.aiAssistant.Update(msg)
			if updatedComponent != nil {
				m.aiAssistant = updatedComponent.(*AIAssistantModel)
			}
			if cmd != nil {
				return m, cmd
			}
		}

		return m, nil

	case tickMsg:
		m.frame++
		m.pulsePhase += 0.05
		m.glowIntensity = 0.3 + 0.2*math.Sin(m.pulsePhase)

		// Update elegant orbs
		for i := range m.orbs {
			orb := &m.orbs[i]
			orb.x += orb.vx
			orb.y += orb.vy

			// Gentle bouncing with smooth curves
			if orb.x <= 0 || orb.x >= 120 {
				orb.vx *= -0.8
				orb.x = math.Max(0, math.Min(120, orb.x))
			}
			if orb.y <= 0 || orb.y >= 40 {
				orb.vy *= -0.8
				orb.y = math.Max(0, math.Min(40, orb.y))
			}

			// Update pulse
			orb.intensity = 0.3 + 0.5*math.Sin(float64(m.frame)*0.02*orb.pulsePeriod+orb.pulseOffset)
		}

		// Update light rays
		for i := range m.lightRays {
			ray := &m.lightRays[i]
			ray.angle += 0.01
			ray.intensity = 0.2 + 0.4*math.Sin(float64(m.frame)*0.03+float64(i))
		}

		// Update matrix rain
		for i := range m.matrixRain {
			drop := &m.matrixRain[i]
			drop.y += drop.speed
			if drop.y > 40 {
				drop.y = -float64(drop.length)
				drop.x = float64(rand.Intn(120))
			}
		}

		// Update energy field
		for i := range m.energyField {
			node := &m.energyField[i]
			node.pulsePhase += 0.02
			node.energy = 0.4 + 0.4*math.Sin(node.pulsePhase)
		}

		// Fetch new data periodically
		var cmds []tea.Cmd
		if m.frame%40 == 0 { // 2 seconds
			cmds = append(cmds, fetchProcesses())
		}
		if m.frame%50 == 0 { // 2.5 seconds
			cmds = append(cmds, fetchNetworkData())
		}
		if m.frame%80 == 0 { // 4 seconds
			cmds = append(cmds, fetchSystemAlerts())
		}

		cmds = append(cmds, tick())
		return m, tea.Batch(cmds...)

	case processData:
		m.processes = msg.processes
		m.systemStats = msg.systemStats

		// Update histories smoothly
		for i, usage := range msg.systemStats.CPUUsage {
			if i < len(m.cpuHistory) {
				m.cpuHistory[i] = append(m.cpuHistory[i][1:], usage)
			}
		}

		memUsagePercent := float64(msg.systemStats.MemUsed) / float64(msg.systemStats.MemTotal) * 100
		m.memHistory = append(m.memHistory[1:], memUsagePercent)

		m.sortProcesses()
		m.filteredProcs = filterProcesses(m.processes, m.searchQuery)

		if m.selectedRow >= len(m.filteredProcs) {
			m.selectedRow = max(0, len(m.filteredProcs)-1)
		}

		return m, nil

	case networkData:
		m.connections = msg.connections
		m.interfaces = msg.interfaces

		// Update network traffic history
		totalTraffic := 0.0
		for _, iface := range m.interfaces {
			totalTraffic += float64(iface.BytesIn+iface.BytesOut) / 1024 / 1024 // MB
		}
		m.networkTraffic = append(m.networkTraffic[1:], totalTraffic)

		return m, nil

	case alertData:
		m.alerts = msg.alerts
		return m, nil

	case errMsg:
		m.err = msg
		return m, nil
	}

	return m, nil
}

func (m model) View() string {
	if m.quitting {
		return lipgloss.NewStyle().
			Foreground(primary).
			Align(lipgloss.Center).
			Render("Disconnecting from the matrix...\n")
	}

	if m.width == 0 || m.height == 0 {
		return "Initializing elegant interface..."
	}

	// Create main layout
	header := m.renderHeader()
	tabs := m.renderViewTabs()
	content := m.renderContent()
	controls := m.renderControls()

	// Add subtle background effects
	bg := m.renderBackgroundEffects()

	layout := lipgloss.JoinVertical(lipgloss.Left,
		header,
		tabs,
		content,
		controls,
	)

	// Overlay background effects
	return m.overlayEffects(layout, bg)
}

func (m model) renderHeader() string {
	title := "⟨ QUANTUM COMMAND CENTER ⟩"

	titleStyle := lipgloss.NewStyle().
		Foreground(primary).
		Bold(true).
		Align(lipgloss.Center).
		Width(m.width)

	// Add subtle glow effect
	glowStyle := lipgloss.NewStyle().
		Foreground(glow).
		Faint(true).
		Align(lipgloss.Center).
		Width(m.width)

	time := lipgloss.NewStyle().
		Foreground(textMuted).
		Align(lipgloss.Right).
		Width(m.width).
		Render(fmt.Sprintf("◉ %s", time.Now().Format("15:04:05")))

	return lipgloss.JoinVertical(lipgloss.Left,
		glowStyle.Render("═══════════════════════════════════════"),
		titleStyle.Render(title),
		glowStyle.Render("═══════════════════════════════════════"),
