func (m model) renderContent() string {
	switch m.viewMode {
	case "overview":
		return m.renderOverview()
	case "processes":
		return m.renderProcesses()
	case "network":
		return m.renderNetwork()
	case "alerts":
		return m.renderAlerts()
	case "bash":
