// changeDirectory handles the cd command
func (bt *BashTerminalModel) changeDirectory(parts []string) tea.Cmd {
	var targetDir string
	if len(parts) == 1 {
		// cd with no arguments goes to home
		home, err := os.UserHomeDir()
		if err != nil {
			bt.addOutput("Error getting home directory", OutputError, lipgloss.Color("#ef4444"))
			return nil
		}
		targetDir = home
	} else {
		targetDir = parts[1]
	}

	// Handle relative paths
	if !filepath.IsAbs(targetDir) {
		targetDir = filepath.Join(bt.currentDir, targetDir)
	}

	// Clean the path
	targetDir = filepath.Clean(targetDir)

	// Check if directory exists
	if info, err := os.Stat(targetDir); err != nil {
		bt.addOutput(fmt.Sprintf("cd: %s: No such file or directory", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		return nil
	} else if !info.IsDir() {
		bt.addOutput(fmt.Sprintf("cd: %s: Not a directory", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		return nil
	}

	// Change directory
	bt.currentDir = targetDir
	bt.prompt = generatePrompt(bt.currentDir)
	bt.addOutput(fmt.Sprintf("Changed directory to: %s", bt.currentDir), OutputInfo, lipgloss.Color("#10b981"))

	return nil
}

// showHistory displays command history
func (bt *BashTerminalModel) showHistory() {
	bt.addOutput("Command History:", OutputInfo, lipgloss.Color("#06b6d4"))
	for i, cmd := range bt.history {
		bt.addOutput(fmt.Sprintf("%3d  %s", i+1, cmd), OutputInfo, lipgloss.Color("#e2e8f0"))
	}
}

// handleThemeCommand handles theme-related commands
func (bt *BashTerminalModel) handleThemeCommand(args []string) tea.Cmd {
	if len(args) == 0 {
		bt.addOutput("Theme commands: list, set <theme>", OutputInfo, lipgloss.Color("#06b6d4"))
		return nil
	}

	switch args[0] {
	case "list":
		themes := []string{"quantum", "cyberpunk", "matrix", "neon", "classic"}
		bt.addOutput("Available themes:", OutputInfo, lipgloss.Color("#06b6d4"))
		for _, theme := range themes {
			bt.addOutput(fmt.Sprintf("  %s", theme), OutputInfo, lipgloss.Color("#e2e8f0"))
		}

	case "set":
		if len(args) > 1 {
			bt.addOutput(fmt.Sprintf("Theme set to: %s", args[1]), OutputInfo, lipgloss.Color("#10b981"))
			// TODO: Implement theme switching
		} else {
			bt.addOutput("Usage: theme set <theme_name>", OutputInfo, lipgloss.Color("#f59e0b"))
		}

	default:
		bt.addOutput("Unknown theme command", OutputError, lipgloss.Color("#ef4444"))
	}

	return nil
}

// History navigation

// handleHistoryUp navigates up in command history
func (bt *BashTerminalModel) handleHistoryUp() tea.Cmd {
	if len(bt.history) == 0 {
		return nil
	}

	if bt.historyPos == -1 {
		bt.historyPos = len(bt.history) - 1
	} else if bt.historyPos > 0 {
		bt.historyPos--
	}

	bt.input = bt.history[bt.historyPos]
	bt.cursorPos = len(bt.input)
	return nil
}

// handleHistoryDown navigates down in command history
func (bt *BashTerminalModel) handleHistoryDown() tea.Cmd {
	if len(bt.history) == 0 || bt.historyPos == -1 {
		return nil
	}

	if bt.historyPos < len(bt.history)-1 {
		bt.historyPos++
		bt.input = bt.history[bt.historyPos]
		bt.cursorPos = len(bt.input)
	} else {
		bt.historyPos = -1
		bt.input = ""
		bt.cursorPos = 0
	}

	return nil
}

// Tab completion

// handleTabCompletion handles tab completion for commands and files
func (bt *BashTerminalModel) handleTabCompletion() tea.Cmd {
	if bt.input == "" {
		return nil
	}

	// Simple file completion for now
	parts := strings.Fields(bt.input)
	if len(parts) == 0 {
		return nil
	}

	lastPart := parts[len(parts)-1]

	// Get directory to search in
	searchDir := bt.currentDir
	if strings.Contains(lastPart, "/") {
		searchDir = filepath.Dir(filepath.Join(bt.currentDir, lastPart))
		lastPart = filepath.Base(lastPart)
	}

	// Find matching files
	entries, err := os.ReadDir(searchDir)
	if err != nil {
		return nil
	}

	var matches []string
	for _, entry := range entries {
		if strings.HasPrefix(entry.Name(), lastPart) {
			matches = append(matches, entry.Name())
		}
	}

	if len(matches) == 1 {
		// Complete the match
		newInput := strings.Join(parts[:len(parts)-1], " ")
		if len(newInput) > 0 {
			newInput += " "
		}
		newInput += matches[0]
		bt.input = newInput
		bt.cursorPos = len(bt.input)
	} else if len(matches) > 1 {
		// Show matches
		bt.addOutput("Possible completions:", OutputInfo, lipgloss.Color("#06b6d4"))
		for _, match := range matches {
			bt.addOutput(fmt.Sprintf("  %s", match), OutputInfo, lipgloss.Color("#e2e8f0"))
		}
	}

	return nil
}

// Output management

// addOutput adds a line to the terminal output
func (bt *BashTerminalModel) addOutput(text string, outputType OutputType, color lipgloss.Color) {
	// Split long lines
	maxWidth := bt.width - 4
	if maxWidth < 40 {
		maxWidth = 40
	}

	lines := bt.wrapText(text, maxWidth)
	for _, line := range lines {
		bt.output = append(bt.output, OutputLine{
			Text:      line,
			Timestamp: time.Now(),
			Type:      outputType,
			Color:     color,
		})
	}

	// Limit output size
	if len(bt.output) > bt.maxOutputSize {
		bt.output = bt.output[len(bt.output)-bt.maxOutputSize:]
	}

	// Auto-scroll to bottom
	bt.scrollToBottom()
}

// wrapText wraps text to fit within the specified width
func (bt *BashTerminalModel) wrapText(text string, width int) []string {
	if len(text) <= width {
		return []string{text}
	}

	var lines []string
	for len(text) > width {
		// Find the last space before the width limit
		breakPoint := width
		for i := width - 1; i >= 0; i-- {
			if text[i] == ' ' {
				breakPoint = i
				break
			}
		}

		lines = append(lines, text[:breakPoint])
		text = strings.TrimSpace(text[breakPoint:])
	}

	if len(text) > 0 {
		lines = append(lines, text)
	}

	return lines
}

// Scrolling

// scrollUp scrolls the output up
func (bt *BashTerminalModel) scrollUp() {
	if bt.scrollOffset > 0 {
		bt.scrollOffset--
	}
}

// scrollDown scrolls the output down
func (bt *BashTerminalModel) scrollDown() {
	maxScroll := len(bt.output) - (bt.height - 5)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if bt.scrollOffset < maxScroll {
		bt.scrollOffset++
	}
}

// scrollToBottom scrolls to the bottom of the output
func (bt *BashTerminalModel) scrollToBottom() {
	maxScroll := len(bt.output) - (bt.height - 5)
	if maxScroll < 0 {
		maxScroll = 0
	}
	bt.scrollOffset = maxScroll
}

// Visual effects

// updateVisualEffects updates the visual effects state
func (bt *BashTerminalModel) updateVisualEffects() {
	bt.frame++
	bt.pulsePhase += 0.05
	bt.glowIntensity = 0.3 + 0.2*math.Sin(bt.pulsePhase)
}

// tickCmd returns a command for visual effects timing
func (bt *BashTerminalModel) tickCmd() tea.Cmd {
	return tea.Tick(time.Millisecond*50, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

// Rendering

// renderTerminalOnly renders the terminal without the AI panel
func (bt *BashTerminalModel) renderTerminalOnly() string {
	var s strings.Builder

	// Header
	header := bt.renderHeader()
	s.WriteString(header + "\n")

	// Output area
	output := bt.renderOutput()
	s.WriteString(output)

	// Input line
	input := bt.renderInputLine()
	s.WriteString(input)

	// Status bar
	status := bt.renderStatusBar()
	s.WriteString(status)

	return s.String()
}

// renderWithAIPanel renders the terminal with the AI assistant panel
func (bt *BashTerminalModel) renderWithAIPanel() string {
	terminalWidth := bt.width - bt.aiPanelWidth - 3
	if terminalWidth < 40 {
		terminalWidth = 40
		bt.aiPanelWidth = bt.width - 43
	}

	// Render terminal content
	terminalContent := bt.renderTerminalContent(terminalWidth)

	// Render AI panel
	aiPanel := bt.renderAIPanel()

	// Join horizontally
	return lipgloss.JoinHorizontal(lipgloss.Top, terminalContent, "│", aiPanel)
}

// renderHeader renders the terminal header
func (bt *BashTerminalModel) renderHeader() string {
	title := "⚡ QUANTUM BASH TERMINAL"
	if bt.showAIPanel {
		title += " + AI ASSISTANT"
	}

	titleStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true).
		Align(lipgloss.Center).
		Width(bt.width)

	timeStr := time.Now().Format("15:04:05")
	timeStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#94a3b8")).
		Align(lipgloss.Right).
		Width(bt.width)

	return titleStyle.Render(title) + "\n" + timeStyle.Render("◉ "+timeStr)
}

// renderOutput renders the terminal output area
func (bt *BashTerminalModel) renderOutput() string {
	var s strings.Builder

	outputHeight := bt.height - 6 // Leave space for header, input, status
	if outputHeight < 5 {
		outputHeight = 5
	}

	startIdx := bt.scrollOffset
	endIdx := startIdx + outputHeight
	if endIdx > len(bt.output) {
		endIdx = len(bt.output)
	}

	for i := startIdx; i < endIdx; i++ {
		line := bt.output[i]

		// Add timestamp for important messages
		prefix := ""
		if line.Type == OutputError || line.Type == OutputAI {
			prefix = line.Timestamp.Format("15:04 ")
		}

		styledLine := lipgloss.NewStyle().
			Foreground(line.Color).
			Render(prefix + line.Text)

		s.WriteString(styledLine + "\n")
	}

	// Fill remaining space
	for i := endIdx - startIdx; i < outputHeight; i++ {
		s.WriteString("\n")
	}

	return s.String()
}

// renderInputLine renders the command input line
func (bt *BashTerminalModel) renderInputLine() string {
	var s strings.Builder

	// Separator line
	separator := strings.Repeat("─", bt.width)
	s.WriteString(lipgloss.NewStyle().Foreground(lipgloss.Color("#64748b")).Render(separator) + "\n")

	// Input line
	promptStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#6366f1")).
		Bold(true)

	inputStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#e2e8f0"))

	// Add cursor
	displayInput := bt.input
	if bt.cursorPos < len(displayInput) {
		displayInput = displayInput[:bt.cursorPos] + "█" + displayInput[bt.cursorPos+1:]
	} else {
		displayInput += "█"
	}

	s.WriteString(promptStyle.Render(bt.prompt) + inputStyle.Render(displayInput))

	return s.String()
}

// renderStatusBar renders the status bar
func (bt *BashTerminalModel) renderStatusBar() string {
	var statusParts []string

	// Execution status
	if bt.isExecuting {
		statusParts = append(statusParts,
			lipgloss.NewStyle().Foreground(lipgloss.Color("#f59e0b")).Render("⚡ Executing"))
	}

	// AI panel status
	if bt.showAIPanel {
		statusParts = append(statusParts,
			lipgloss.NewStyle().Foreground(lipgloss.Color("#8b5cf6")).Render("🤖 AI Panel"))
	}

	// Directory
	statusParts = append(statusParts,
		lipgloss.NewStyle().Foreground(lipgloss.Color("#06b6d4")).Render("📁 "+filepath.Base(bt.currentDir)))

	// Commands count
	statusParts = append(statusParts,
		lipgloss.NewStyle().Foreground(lipgloss.Color("#10b981")).Render(fmt.Sprintf("📜 %d", len(bt.history))))

	status := strings.Join(statusParts, " • ")

	return lipgloss.NewStyle().
		Background(lipgloss.Color("#1e1e3f")).
		Foreground(lipgloss.Color("#e2e8f0")).
		Width(bt.width).
		Padding(0, 1).
		Render(status)
}

// renderTerminalContent renders terminal content with specified width
func (bt *BashTerminalModel) renderTerminalContent(width int) string {
	// Temporarily adjust width
	originalWidth := bt.width
	bt.width = width

	content := bt.renderTerminalOnly()

	// Restore original width
	bt.width = originalWidth

	return content
}

// renderAIPanel renders the AI assistant panel
func (bt *BashTerminalModel) renderAIPanel() string {
	var s strings.Builder

	// Panel header
	header := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#8b5cf6")).
		Bold(true).
		Align(lipgloss.Center).
		Width(bt.aiPanelWidth).
		Render("🤖 AI ASSISTANT")
	s.WriteString(header + "\n")

	// Agent selector
	agentInfo := bt.renderAgentSelector()
	s.WriteString(agentInfo + "\n")

	// Chat history
	chatHeight := bt.height - 8 // Leave space for header, agent, input
	if chatHeight < 5 {
		chatHeight = 5
	}

	chat := bt.renderAIChat(chatHeight)
	s.WriteString(chat)

	// AI input line
	aiInput := bt.renderAIInputLine()
	s.WriteString(aiInput)

	return s.String()
}

// renderAgentSelector renders the AI agent selector
func (bt *BashTerminalModel) renderAgentSelector() string {
	var selectedAgent *AIAgent
	for _, agent := range bt.availableAgents {
		if agent.Command == bt.selectedAgent {
			selectedAgent = &agent
			break
		}
	}

	if selectedAgent == nil {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("#ef4444")).
			Width(bt.aiPanelWidth).
			Render("No agent selected")
	}

	status := "❌ Unavailable"
	if selectedAgent.Available {
		status = "✅ Available"
	}

	return lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(selectedAgent.Color).
		Padding(0, 1).
		Width(bt.aiPanelWidth - 2).
		Render(fmt.Sprintf("%s %s\n%s\n%s",
			selectedAgent.Icon, selectedAgent.Name,
			selectedAgent.Description, status))
}

// renderAIChat renders the AI chat history
func (bt *BashTerminalModel) renderAIChat(height int) string {
	var s strings.Builder

	// Chat separator
	separator := strings.Repeat("─", bt.aiPanelWidth)
	s.WriteString(lipgloss.NewStyle().Foreground(lipgloss.Color("#64748b")).Render(separator) + "\n")

	if len(bt.aiHistory) == 0 {
		// No chat history
		placeholder := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#94a3b8")).
			Align(lipgloss.Center).
			Width(bt.aiPanelWidth).
			Height(height - 2).
			Render("No conversation yet.\nType a message below to start.")
		s.WriteString(placeholder)
	} else {
		// Show recent messages
		startIdx := len(bt.aiHistory) - height + 2
		if startIdx < 0 {
			startIdx = 0
		}

		for i := startIdx; i < len(bt.aiHistory) && i < startIdx+height-2; i++ {
			msg := bt.aiHistory[i]

			var style lipgloss.Style
			var prefix string

			if msg.Role == "user" {
				style = lipgloss.NewStyle().Foreground(lipgloss.Color("#06b6d4"))
				prefix = "👤 You: "
			} else {
				style = lipgloss.NewStyle().Foreground(lipgloss.Color("#10b981"))
				prefix = "🤖 AI: "
			}

			// Wrap message content
			maxWidth := bt.aiPanelWidth - len(prefix) - 2
			if maxWidth < 20 {
				maxWidth = 20
			}
			wrappedLines := bt.wrapText(msg.Content, maxWidth)

			for j, line := range wrappedLines {
				if j == 0 {
					s.WriteString(style.Render(prefix+line) + "\n")
				} else {
					s.WriteString(style.Render(strings.Repeat(" ", len(prefix))+line) + "\n")
				}
			}
		}
	}

	return s.String()
}

// renderAIInputLine renders the AI input line
func (bt *BashTerminalModel) renderAIInputLine() string {
	var s strings.Builder

	// Separator
	separator := strings.Repeat("─", bt.aiPanelWidth)
	s.WriteString(lipgloss.NewStyle().Foreground(lipgloss.Color("#64748b")).Render(separator) + "\n")

	// Input prompt
	promptStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#8b5cf6")).
		Bold(true)

	inputStyle := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#e2e8f0"))

	// Add cursor
	displayInput := bt.aiInput
	if bt.aiCursorPos < len(displayInput) {
		displayInput = displayInput[:bt.aiCursorPos] + "█" + displayInput[bt.aiCursorPos+1:]
	} else {
		displayInput += "█"
	}

	s.WriteString(promptStyle.Render("AI> ") + inputStyle.Render(displayInput))

	return s.String()
}

