// changeDirectorySafe handles the cd command with comprehensive error handling
func (bt *BashTerminalModel) changeDirectorySafe(parts []string) tea.Cmd {
	var targetDir string
	if len(parts) == 1 {
		// cd with no arguments goes to home
		home, err := os.UserHomeDir()
		if err != nil {
			bt.addOutput(fmt.Sprintf("Error getting home directory: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return nil
		}
		targetDir = home
	} else if len(parts) > 2 {
		// Too many arguments
		bt.addOutput("cd: too many arguments", OutputError, lipgloss.Color("#ef4444"))
		return nil
	} else {
		targetDir = parts[1]
	}

	// Handle special cases
	switch targetDir {
	case "-":
		// cd - (go to previous directory) - not implemented yet
		bt.addOutput("cd: OLDPWD not set", OutputError, lipgloss.Color("#ef4444"))
		return nil
	case "~":
		// Expand ~ to home directory
		home, err := os.UserHomeDir()
		if err != nil {
			bt.addOutput(fmt.Sprintf("Error getting home directory: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return nil
		}
		targetDir = home
	}

	// Handle tilde expansion at the beginning of path
	if strings.HasPrefix(targetDir, "~/") {
		home, err := os.UserHomeDir()
		if err != nil {
			bt.addOutput(fmt.Sprintf("Error getting home directory: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return nil
		}
		targetDir = filepath.Join(home, targetDir[2:])
	}

	// Handle relative paths
	if !filepath.IsAbs(targetDir) {
		targetDir = filepath.Join(bt.currentDir, targetDir)
	}

	// Clean the path to resolve . and .. components
	targetDir = filepath.Clean(targetDir)

	// Validate the target directory
	info, err := os.Stat(targetDir)
	if err != nil {
		if os.IsNotExist(err) {
			bt.addOutput(fmt.Sprintf("cd: %s: No such file or directory", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		} else if os.IsPermission(err) {
			bt.addOutput(fmt.Sprintf("cd: %s: Permission denied", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		} else {
			bt.addOutput(fmt.Sprintf("cd: %s: %v", parts[1], err), OutputError, lipgloss.Color("#ef4444"))
		}
		return nil
	}

	if !info.IsDir() {
		bt.addOutput(fmt.Sprintf("cd: %s: Not a directory", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		return nil
	}

	// Check if we have permission to access the directory
	if !bt.canAccessDirectory(targetDir) {
		bt.addOutput(fmt.Sprintf("cd: %s: Permission denied", parts[1]), OutputError, lipgloss.Color("#ef4444"))
		return nil
	}

	// Change directory successfully
	bt.currentDir = targetDir
	bt.prompt = generatePrompt(bt.currentDir)
	bt.addOutput(fmt.Sprintf("Changed directory to: %s", bt.currentDir), OutputInfo, lipgloss.Color("#10b981"))

	return nil
}

