package main

import (
	"bufio"
	"fmt"
	"io"
	"math"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// BashTerminalModel implements a bash terminal interface with AI assistant integration
type BashTerminalModel struct {
	// Component state
	active bool
	width  int
	height int

	// Terminal state
	currentDir    string
	prompt        string
	input         string
	cursorPos     int
	history       []string
	historyPos    int
	output        []OutputLine
	scrollOffset  int
	maxOutputSize int

	// Command execution
	runningCmd  *exec.Cmd
	cmdOutput   chan string
	cmdDone     chan bool
	isExecuting bool

	// AI Assistant panel state
	showAIPanel     bool
	aiPanelWidth    int
	aiInput         string
	aiCursorPos     int
	aiHistory       []AIMessage
	selectedAgent   string
	availableAgents []AIAgent

	// Visual effects
	frame         int
	pulsePhase    float64
	glowIntensity float64
}

// OutputLine represents a line of terminal output with styling
type OutputLine struct {
	Text      string
	Timestamp time.Time
	Type      OutputType
	Color     lipgloss.Color
}

// OutputType represents different types of terminal output
type OutputType int

const (
	OutputCommand OutputType = iota
	OutputResult
	OutputError
	OutputInfo
	OutputAI
)

// Terminal command execution messages
type (
	cmdOutputMsg struct {
		output string
	}
	cmdCompleteMsg struct {
		exitCode int
		error    error
	}
	cmdStartMsg struct {
		command string
	}
)

// NewBashTerminalModel creates a new bash terminal component
func NewBashTerminalModel() *BashTerminalModel {
	// Get current working directory
	currentDir, err := os.Getwd()
	if err != nil {
		currentDir = "~"
	}

	// Define available AI agents
	agents := []AIAgent{
		{
			Name:        "Claude Code",
			Command:     "claude-code",
			Description: "Advanced code analysis and development assistance",
			Icon:        "🧠",
			Color:       lipgloss.Color("#6366f1"),
			Available:   checkCommandAvailable("claude-code"),
		},
		{
			Name:        "OpenCode",
			Command:     "opencode",
			Description: "Open-source code generation and assistance",
			Icon:        "🔓",
			Color:       lipgloss.Color("#10b981"),
			Available:   checkCommandAvailable("opencode"),
		},
		{
			Name:        "Gemini CLI",
			Command:     "gemini",
			Description: "Google's Gemini AI for coding tasks",
			Icon:        "💎",
			Color:       lipgloss.Color("#06b6d4"),
			Available:   checkCommandAvailable("gemini"),
		},
		{
			Name:        "GitHub Copilot CLI",
			Command:     "gh copilot",
			Description: "GitHub Copilot command-line interface",
			Icon:        "🐙",
			Color:       lipgloss.Color("#8b5cf6"),
			Available:   checkCommandAvailable("gh"),
		},
		{
			Name:        "Aider",
			Command:     "aider",
			Description: "AI pair programming in your terminal",
			Icon:        "🤖",
			Color:       lipgloss.Color("#f59e0b"),
			Available:   checkCommandAvailable("aider"),
		},
		{
			Name:        "Shell GPT",
			Command:     "sgpt",
			Description: "ChatGPT in your shell",
			Icon:        "💬",
			Color:       lipgloss.Color("#ec4899"),
			Available:   checkCommandAvailable("sgpt"),
		},
	}

	bt := &BashTerminalModel{
		active:          false,
		currentDir:      currentDir,
		prompt:          generatePrompt(currentDir),
		input:           "",
		cursorPos:       0,
		history:         []string{},
		historyPos:      -1,
		output:          []OutputLine{},
		scrollOffset:    0,
		maxOutputSize:   1000,
		cmdOutput:       make(chan string, 100),
		cmdDone:         make(chan bool, 1),
		isExecuting:     false,
		showAIPanel:     false,
		aiPanelWidth:    40,
		aiInput:         "",
		aiCursorPos:     0,
		aiHistory:       []AIMessage{},
		selectedAgent:   "claude-code",
		availableAgents: agents,
		glowIntensity:   0.5,
		pulsePhase:      0,
	}

	// Add welcome message
	bt.addOutput("Welcome to Quantum Terminal! Type 'help' for available commands.", OutputInfo, lipgloss.Color("#06b6d4"))
	bt.addOutput("Press '!' to toggle AI Assistant panel", OutputInfo, lipgloss.Color("#8b5cf6"))

	return bt
}

// checkCommandAvailable checks if a command is available in PATH
func checkCommandAvailable(command string) bool {
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return false
	}
	_, err := exec.LookPath(parts[0])
	return err == nil
}

// generatePrompt creates a shell prompt string
func generatePrompt(dir string) string {
	// Get just the directory name for a cleaner prompt
	dirName := filepath.Base(dir)
	if dirName == "." || dirName == "/" {
		dirName = dir
	}
	return fmt.Sprintf("quantum:%s$ ", dirName)
}

// ToolComponent interface implementation

// Init initializes the bash terminal component
func (bt *BashTerminalModel) Init() tea.Cmd {
	return tea.Batch(
		bt.tickCmd(),
	)
}

// Update handles messages for the bash terminal
func (bt *BashTerminalModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case tea.KeyMsg:
		if !bt.active {
			return bt, nil
		}

		if cmd := bt.handleKeyMsg(msg); cmd != nil {
			cmds = append(cmds, cmd)
		}

	case cmdOutputMsg:
		bt.addOutput(msg.output, OutputResult, lipgloss.Color("#e2e8f0"))

	case cmdCompleteMsg:
		bt.isExecuting = false
		if msg.error != nil {
			bt.addOutput(fmt.Sprintf("Command failed: %v", msg.error), OutputError, lipgloss.Color("#ef4444"))
		} else {
			bt.addOutput(fmt.Sprintf("Command completed (exit code: %d)", msg.exitCode), OutputInfo, lipgloss.Color("#10b981"))
		}

	case cmdStartMsg:
		bt.isExecuting = true
		bt.addOutput(fmt.Sprintf("Executing: %s", msg.command), OutputInfo, lipgloss.Color("#f59e0b"))

	case tickMsg:
		bt.updateVisualEffects()
		cmds = append(cmds, bt.tickCmd())
	}

	return bt, tea.Batch(cmds...)
}

// View renders the bash terminal interface
func (bt *BashTerminalModel) View() string {
	if !bt.active || bt.width == 0 || bt.height == 0 {
		return ""
	}

	if bt.showAIPanel {
		return bt.renderWithAIPanel()
	}

	return bt.renderTerminalOnly()
}

// SetSize updates the component dimensions
func (bt *BashTerminalModel) SetSize(width, height int) {
	bt.width = width
	bt.height = height
}

// GetViewType returns the component's view type
func (bt *BashTerminalModel) GetViewType() ViewType {
	return ViewBashTerminal
}

// IsActive returns whether the component is currently active
func (bt *BashTerminalModel) IsActive() bool {
	return bt.active
}

// SetActive sets the component's active state
func (bt *BashTerminalModel) SetActive(active bool) {
	bt.active = active
}

// Key handling

// handleKeyMsg processes key messages for the terminal
func (bt *BashTerminalModel) handleKeyMsg(msg tea.KeyMsg) tea.Cmd {
	switch msg.String() {
	case "!":
		// Toggle AI panel
		bt.showAIPanel = !bt.showAIPanel
		return nil

	case "ctrl+c":
		// Interrupt running command
		if bt.isExecuting && bt.runningCmd != nil {
			bt.runningCmd.Process.Signal(syscall.SIGINT)
			bt.isExecuting = false
			bt.addOutput("^C", OutputInfo, lipgloss.Color("#f59e0b"))
		}
		return nil

	case "ctrl+l":
		// Clear terminal
		bt.output = []OutputLine{}
		bt.scrollOffset = 0
		return nil

	case "enter":
		if bt.showAIPanel && bt.aiInput != "" {
			return bt.handleAIInput()
		}
		return bt.handleCommandInput()

	case "up":
		if bt.showAIPanel {
			// Handle AI panel navigation
			return nil
		}
		return bt.handleHistoryUp()

	case "down":
		if bt.showAIPanel {
			// Handle AI panel navigation
			return nil
		}
		return bt.handleHistoryDown()

	case "left":
		if bt.showAIPanel {
			if bt.aiCursorPos > 0 {
				bt.aiCursorPos--
			}
		} else {
			if bt.cursorPos > 0 {
				bt.cursorPos--
			}
		}
		return nil

	case "right":
		if bt.showAIPanel {
			if bt.aiCursorPos < len(bt.aiInput) {
				bt.aiCursorPos++
			}
		} else {
			if bt.cursorPos < len(bt.input) {
				bt.cursorPos++
			}
		}
		return nil

	case "backspace":
		if bt.showAIPanel {
			if bt.aiCursorPos > 0 {
				bt.aiInput = bt.aiInput[:bt.aiCursorPos-1] + bt.aiInput[bt.aiCursorPos:]
				bt.aiCursorPos--
			}
		} else {
			if bt.cursorPos > 0 {
				bt.input = bt.input[:bt.cursorPos-1] + bt.input[bt.cursorPos:]
				bt.cursorPos--
			}
		}
		return nil

	case "delete":
		if bt.showAIPanel {
			if bt.aiCursorPos < len(bt.aiInput) {
				bt.aiInput = bt.aiInput[:bt.aiCursorPos] + bt.aiInput[bt.aiCursorPos+1:]
			}
		} else {
			if bt.cursorPos < len(bt.input) {
				bt.input = bt.input[:bt.cursorPos] + bt.input[bt.cursorPos+1:]
			}
		}
		return nil

	case "home", "ctrl+a":
		if bt.showAIPanel {
			bt.aiCursorPos = 0
		} else {
			bt.cursorPos = 0
		}
		return nil

	case "end", "ctrl+e":
		if bt.showAIPanel {
			bt.aiCursorPos = len(bt.aiInput)
		} else {
			bt.cursorPos = len(bt.input)
		}
		return nil

	case "page_up":
		bt.scrollUp()
		return nil

	case "page_down":
		bt.scrollDown()
		return nil

	case "tab":
		// Tab completion
		if !bt.showAIPanel {
			return bt.handleTabCompletion()
		}
		return nil

	default:
		// Regular character input
		if len(msg.String()) == 1 {
			char := msg.String()
			if bt.showAIPanel {
				bt.aiInput = bt.aiInput[:bt.aiCursorPos] + char + bt.aiInput[bt.aiCursorPos:]
				bt.aiCursorPos++
			} else {
				bt.input = bt.input[:bt.cursorPos] + char + bt.input[bt.cursorPos:]
				bt.cursorPos++
			}
		}
		return nil
	}
}

// Command execution

// handleCommandInput processes command input and execution with error handling
func (bt *BashTerminalModel) handleCommandInput() tea.Cmd {
	if bt.input == "" {
		bt.addOutput(bt.prompt, OutputCommand, lipgloss.Color("#6366f1"))
		return nil
	}

	command := strings.TrimSpace(bt.input)

	// Validate command length to prevent potential buffer overflow
	if len(command) > 4096 {
		bt.addOutput("Error: Command too long (max 4096 characters)", OutputError, lipgloss.Color("#ef4444"))
		bt.input = ""
		bt.cursorPos = 0
		return nil
	}

	// Basic security check - prevent obviously dangerous commands
	if bt.isDangerousCommand(command) {
		bt.addOutput("Warning: Potentially dangerous command blocked. Use with caution.", OutputError, lipgloss.Color("#ef4444"))
		bt.input = ""
		bt.cursorPos = 0
		return nil
	}

	// Add to history with bounds checking
	if command != "" { // Don't add empty commands to history
		bt.history = append(bt.history, command)
		if len(bt.history) > 100 {
			bt.history = bt.history[1:] // Remove oldest command
		}
	}
	bt.historyPos = -1

	// Display command
	bt.addOutput(bt.prompt+command, OutputCommand, lipgloss.Color("#6366f1"))

	// Handle built-in commands with error handling
	if cmd := bt.handleBuiltinCommandSafe(command); cmd != nil {
		bt.input = ""
		bt.cursorPos = 0
		return cmd
	}

	// Check if we should execute external command
	if bt.isExecuting {
		bt.addOutput("Error: Another command is already running. Use Ctrl+C to interrupt.", OutputError, lipgloss.Color("#ef4444"))
		bt.input = ""
		bt.cursorPos = 0
		return nil
	}

	// Execute external command
	bt.input = ""
	bt.cursorPos = 0
	return bt.executeCommand(command)
}

// handleBuiltinCommand handles built-in terminal commands (legacy method)
func (bt *BashTerminalModel) handleBuiltinCommand(command string) tea.Cmd {
	return bt.handleBuiltinCommandSafe(command)
}

// handleBuiltinCommandSafe handles built-in terminal commands with error handling
func (bt *BashTerminalModel) handleBuiltinCommandSafe(command string) tea.Cmd {
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return nil
	}

	switch parts[0] {
	case "help":
		bt.showHelp()
		return nil

	case "clear", "cls":
		bt.output = []OutputLine{}
		bt.scrollOffset = 0
		return nil

	case "cd":
		return bt.changeDirectorySafe(parts)

	case "pwd":
		bt.addOutput(bt.currentDir, OutputResult, lipgloss.Color("#e2e8f0"))
		return nil

	case "history":
		bt.showHistory()
		return nil

	case "ai":
		return bt.handleAICommandSafe(parts[1:])

	case "theme":
		return bt.handleThemeCommandSafe(parts[1:])

	case "exit", "quit":
		// This would typically quit the application
		bt.addOutput("Use 'q' or Ctrl+C to quit the application", OutputInfo, lipgloss.Color("#f59e0b"))
		return nil

	default:
		return nil // Not a built-in command
	}
}

// executeCommand executes an external command with comprehensive error handling
func (bt *BashTerminalModel) executeCommand(command string) tea.Cmd {
	return func() tea.Msg {
		// Parse command and arguments with error checking
		parts := strings.Fields(command)
		if len(parts) == 0 {
			bt.addOutput("Error: Empty command", OutputError, lipgloss.Color("#ef4444"))
			return cmdCompleteMsg{exitCode: 1, error: fmt.Errorf("empty command")}
		}

		// Check if command exists in PATH
		if _, err := exec.LookPath(parts[0]); err != nil {
			bt.addOutput(fmt.Sprintf("Command not found: %s", parts[0]), OutputError, lipgloss.Color("#ef4444"))
			return cmdCompleteMsg{exitCode: 127, error: fmt.Errorf("command not found: %s", parts[0])}
		}

		// Validate current directory exists
		if _, err := os.Stat(bt.currentDir); err != nil {
			bt.addOutput(fmt.Sprintf("Error: Invalid working directory: %s", bt.currentDir), OutputError, lipgloss.Color("#ef4444"))
			// Try to recover by changing to home directory
			if home, homeErr := os.UserHomeDir(); homeErr == nil {
				bt.currentDir = home
				bt.prompt = generatePrompt(bt.currentDir)
				bt.addOutput(fmt.Sprintf("Recovered by changing to home directory: %s", home), OutputInfo, lipgloss.Color("#f59e0b"))
			} else {
				return cmdCompleteMsg{exitCode: 1, error: fmt.Errorf("invalid working directory and cannot recover: %s", bt.currentDir)}
			}
		}

		// Create command with timeout context
		cmd := exec.Command(parts[0], parts[1:]...)
		cmd.Dir = bt.currentDir

		// Set up environment variables
		cmd.Env = os.Environ()

		// Set up pipes with error handling
		stdout, err := cmd.StdoutPipe()
		if err != nil {
			bt.addOutput(fmt.Sprintf("Error setting up stdout pipe: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return cmdCompleteMsg{exitCode: 1, error: fmt.Errorf("failed to create stdout pipe: %w", err)}
		}
		stderr, err := cmd.StderrPipe()
		if err != nil {
			stdout.Close() // Clean up already created pipe
			bt.addOutput(fmt.Sprintf("Error setting up stderr pipe: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return cmdCompleteMsg{exitCode: 1, error: fmt.Errorf("failed to create stderr pipe: %w", err)}
		}

		// Start command with error handling
		if err := cmd.Start(); err != nil {
			stdout.Close()
			stderr.Close()
			bt.addOutput(fmt.Sprintf("Failed to start command: %v", err), OutputError, lipgloss.Color("#ef4444"))
			return cmdCompleteMsg{exitCode: 1, error: fmt.Errorf("failed to start command: %w", err)}
		}

		bt.runningCmd = cmd

		// Read output in goroutines with error channels
		stdoutDone := make(chan error, 1)
		stderrDone := make(chan error, 1)

		go func() {
			stdoutDone <- bt.readCommandOutputSafe(stdout, false)
		}()
		go func() {
			stderrDone <- bt.readCommandOutputSafe(stderr, true)
		}()

		// Wait for completion with timeout handling
		err = cmd.Wait()
		exitCode := 0

		// Handle command completion errors
		if err != nil {
			if exitError, ok := err.(*exec.ExitError); ok {
				exitCode = exitError.ExitCode()
				if exitCode == 130 {
					bt.addOutput("Command interrupted by user (Ctrl+C)", OutputInfo, lipgloss.Color("#f59e0b"))
				} else {
					bt.addOutput(fmt.Sprintf("Command exited with code %d", exitCode), OutputInfo, lipgloss.Color("#f59e0b"))
				}
			} else {
				// Non-exit error (e.g., signal)
				exitCode = 1
				bt.addOutput(fmt.Sprintf("Command failed: %v", err), OutputError, lipgloss.Color("#ef4444"))
			}
		}

		// Wait for output readers to complete
		<-stdoutDone
		<-stderrDone

		// Clear running command reference
		bt.runningCmd = nil

		return cmdCompleteMsg{exitCode: exitCode, error: err}
	}
}

// readCommandOutput reads output from command stdout/stderr (legacy method)
func (bt *BashTerminalModel) readCommandOutput(pipe io.ReadCloser, isError bool) {
	_ = bt.readCommandOutputSafe(pipe, isError)
}

// readCommandOutputSafe reads output from command stdout/stderr with error handling
func (bt *BashTerminalModel) readCommandOutputSafe(pipe io.ReadCloser, isError bool) error {
	defer func() {
		if err := pipe.Close(); err != nil {
			// Log pipe close error but don't fail the operation
			bt.addOutput(fmt.Sprintf("Warning: Failed to close pipe: %v", err), OutputInfo, lipgloss.Color("#f59e0b"))
		}
	}()

	scanner := bufio.NewScanner(pipe)
	// Set a reasonable buffer size limit to prevent memory issues
	scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024) // 1MB max line length

	for scanner.Scan() {
		line := scanner.Text()

		// Sanitize output - remove potentially harmful control sequences
		line = bt.sanitizeOutput(line)

		color := lipgloss.Color("#e2e8f0")
		outputType := OutputResult
		if isError {
			color = lipgloss.Color("#ef4444")
			outputType = OutputError
		}
		bt.addOutput(line, outputType, color)
	}

	// Check for scanning errors
	if err := scanner.Err(); err != nil {
		bt.addOutput(fmt.Sprintf("Error reading command output: %v", err), OutputError, lipgloss.Color("#ef4444"))
		return fmt.Errorf("scanner error: %w", err)
	}

	return nil
}

// AI Assistant functionality

// handleAIInput processes AI assistant input
func (bt *BashTerminalModel) handleAIInput() tea.Cmd {
	if bt.aiInput == "" {
		return nil
	}

	input := strings.TrimSpace(bt.aiInput)

	// Add user message to AI history
	bt.aiHistory = append(bt.aiHistory, AIMessage{
		Role:      "user",
		Content:   input,
		Timestamp: time.Now(),
		Agent:     bt.selectedAgent,
	})

	// Clear input
	bt.aiInput = ""
	bt.aiCursorPos = 0

	// Find selected agent
	var agent *AIAgent
	for _, a := range bt.availableAgents {
		if a.Command == bt.selectedAgent {
			agent = &a
			break
		}
	}

	if agent == nil || !agent.Available {
		bt.aiHistory = append(bt.aiHistory, AIMessage{
			Role:      "assistant",
			Content:   "Sorry, the selected AI agent is not available.",
			Timestamp: time.Now(),
			Agent:     bt.selectedAgent,
		})
		return nil
	}

	// Execute AI command
	return bt.executeAICommand(agent, input)
}

// executeAICommand executes an AI assistant command
func (bt *BashTerminalModel) executeAICommand(agent *AIAgent, input string) tea.Cmd {
	return func() tea.Msg {
		// Construct AI command
		var cmdParts []string
		switch agent.Command {
		case "claude-code":
			cmdParts = []string{"claude-code", input}
		case "opencode":
			cmdParts = []string{"opencode", input}
		case "gemini":
			cmdParts = []string{"gemini", input}
		case "gh copilot":
			cmdParts = []string{"gh", "copilot", "suggest", input}
		case "aider":
			cmdParts = []string{"aider", "--message", input}
		case "sgpt":
			cmdParts = []string{"sgpt", input}
		default:
			return nil
		}

		// Execute command
		cmd := exec.Command(cmdParts[0], cmdParts[1:]...)
		cmd.Dir = bt.currentDir

		output, err := cmd.CombinedOutput()
		if err != nil {
			bt.aiHistory = append(bt.aiHistory, AIMessage{
				Role:      "assistant",
				Content:   fmt.Sprintf("Error: %v\n%s", err, string(output)),
				Timestamp: time.Now(),
				Agent:     agent.Command,
			})
		} else {
			bt.aiHistory = append(bt.aiHistory, AIMessage{
				Role:      "assistant",
				Content:   string(output),
				Timestamp: time.Now(),
				Agent:     agent.Command,
			})
		}

		return nil
	}
}

// handleAICommand handles the 'ai' built-in command
func (bt *BashTerminalModel) handleAICommand(args []string) tea.Cmd {
	if len(args) == 0 {
		bt.addOutput("Available AI agents:", OutputInfo, lipgloss.Color("#06b6d4"))
		for _, agent := range bt.availableAgents {
			status := "❌ Not available"
			if agent.Available {
				status = "✅ Available"
			}
			bt.addOutput(fmt.Sprintf("  %s %s - %s %s", agent.Icon, agent.Name, agent.Description, status), OutputInfo, agent.Color)
		}
		return nil
	}

	switch args[0] {
	case "select":
		if len(args) > 1 {
			for _, agent := range bt.availableAgents {
				if strings.Contains(strings.ToLower(agent.Name), strings.ToLower(args[1])) ||
					strings.Contains(agent.Command, args[1]) {
					bt.selectedAgent = agent.Command
					bt.addOutput(fmt.Sprintf("Selected AI agent: %s %s", agent.Icon, agent.Name), OutputInfo, agent.Color)
					return nil
				}
			}
			bt.addOutput("AI agent not found", OutputError, lipgloss.Color("#ef4444"))
		} else {
			bt.addOutput("Usage: ai select <agent_name>", OutputInfo, lipgloss.Color("#f59e0b"))
		}

	case "panel":
		bt.showAIPanel = !bt.showAIPanel
		status := "hidden"
		if bt.showAIPanel {
			status = "shown"
		}
		bt.addOutput(fmt.Sprintf("AI panel %s", status), OutputInfo, lipgloss.Color("#8b5cf6"))

	default:
		bt.addOutput("AI commands: select <agent>, panel", OutputInfo, lipgloss.Color("#06b6d4"))
	}

	return nil
}

