// sanitizeOutput removes potentially harmful control sequences from command output
func (bt *BashTerminalModel) sanitizeOutput(output string) string {
	// Remove common ANSI escape sequences that could interfere with our TUI
	// Keep basic color codes but remove potentially harmful sequences
	ansiRegex := `\x1b\[[0-9;]*[A-Za-z]`
	// For now, just strip all ANSI sequences to be safe
	// TODO: Implement selective ANSI filtering if needed
	result := output

	// Remove null bytes and other control characters except newlines and tabs
	filtered := make([]rune, 0, len(result))
	for _, r := range result {
		if r == '\n' || r == '\t' || r >= 32 {
			filtered = append(filtered, r)
		}
	}

	return string(filtered)
}

// isDangerousCommand performs basic security checks on commands
func (bt *BashTerminalModel) isDangerousCommand(command string) bool {
	// List of potentially dangerous patterns (not exhaustive, just basic protection)
	dangerousPatterns := []string{
		"rm -rf /",
		":(){ :|:& };:", // Fork bomb
		"dd if=/dev/zero",
		"mkfs",
		"format",
		"> /etc/",
	}

	lowerCmd := strings.ToLower(command)
	for _, pattern := range dangerousPatterns {
		if strings.Contains(lowerCmd, pattern) {
			return true
		}
	}

	return false
}

// canAccessDirectory checks if we can access a directory
func (bt *BashTerminalModel) canAccessDirectory(dir string) bool {
	// Try to read the directory to check permissions
	_, err := os.ReadDir(dir)
	return err == nil
}

// getAvailableAgentsList returns a comma-separated list of available agent names
func (bt *BashTerminalModel) getAvailableAgentsList() string {
	var names []string
	for _, agent := range bt.availableAgents {
		status := "unavailable"
		if agent.Available {
			status = "available"
		}
		names = append(names, fmt.Sprintf("%s (%s)", strings.ToLower(strings.ReplaceAll(agent.Name, " ", "")), status))
	}
	return strings.Join(names, ", ")
}

