func (ps *PortScanner) ScanPorts(ctx context.Context, targets []string, portRanges []PortRange, scanType ScanType, progressChan chan<- ScanProgressUpdate) error {
	// Validate inputs
	if ctx == nil {
		return fmt.Errorf("context cannot be nil")
	}
	if len(targets) == 0 {
		return fmt.Errorf("no targets specified")
	}
	if len(portRanges) == 0 {
		return fmt.Errorf("no port ranges specified")
	}
	if progressChan == nil {
		return fmt.Errorf("progress channel cannot be nil")
	}

	// Validate targets
	for i, target := range targets {
		if strings.TrimSpace(target) == "" {
			return fmt.Errorf("target %d is empty", i+1)
		}
		// Basic format validation
		if len(target) > 253 { // Max domain name length
			return fmt.Errorf("target %d is too long: %s", i+1, target)
		}
	}

	// Calculate total ports to scan with overflow protection
	totalPorts := 0
	for _, target := range targets {
		_ = target // Used for calculating total ports per target
		for _, portRange := range portRanges {
			// Validate port range
			if portRange.Start < 1 || portRange.Start > 65535 || portRange.End < 1 || portRange.End > 65535 {
				return fmt.Errorf("invalid port range: %d-%d", portRange.Start, portRange.End)
			}
			if portRange.Start > portRange.End {
				return fmt.Errorf("invalid port range: start %d > end %d", portRange.Start, portRange.End)
			}

			rangeSize := portRange.End - portRange.Start + 1
			// Check for potential overflow
			if totalPorts > (1<<31-1)-rangeSize {
				return fmt.Errorf("total ports to scan exceeds maximum limit")
			}
			totalPorts += rangeSize
		}
	}

	// Validate reasonable scan size
	if totalPorts > 1000000 { // 1M ports max
		return fmt.Errorf("scan too large: %d ports exceeds maximum of 1,000,000", totalPorts)
	}

