// NewBannerGrabber creates a new banner grabber
func NewBannerGrabber() *BannerGrabber {
	return &BannerGrabber{
		timeout: 5 * time.Second,
	}
}

// GrabBanner attempts to grab a service banner from a port
func (bg *BannerGrabber) GrabBanner(host string, port int) string {
	address := fmt.Sprintf("%s:%d", host, port)

	// Create connection with timeout
	conn, err := net.DialTimeout("tcp", address, bg.timeout)
	if err != nil {
		return ""
	}
	defer conn.Close()

	// Set read deadline
	conn.SetReadDeadline(time.Now().Add(bg.timeout))

	// Try to read banner (some services send banner immediately)
	buffer := make([]byte, 1024)
	n, err := conn.Read(buffer)
	if err != nil {
		// If no immediate banner, try sending a probe
		return bg.probeBanner(conn, port)
	}

	banner := strings.TrimSpace(string(buffer[:n]))
	if len(banner) > 0 {
		return banner
	}

	// Try probing if no immediate banner
	return bg.probeBanner(conn, port)
}

// probeBanner sends protocol-specific probes to elicit a banner
func (bg *BannerGrabber) probeBanner(conn net.Conn, port int) string {
	// Set write deadline
	conn.SetWriteDeadline(time.Now().Add(bg.timeout))

	var probe string
	switch port {
	case 21: // FTP
		probe = "USER anonymous\r\n"
	case 22: // SSH
		probe = "SSH-2.0-Scanner\r\n"
	case 25: // SMTP
		probe = "EHLO scanner\r\n"
	case 80, 8080: // HTTP
		probe = "GET / HTTP/1.0\r\n\r\n"
	case 110: // POP3
		probe = "USER test\r\n"
	case 143: // IMAP
		probe = "A001 CAPABILITY\r\n"
	case 443: // HTTPS
		// For HTTPS, we can't easily grab banner without TLS handshake
		return ""
	default:
		// Generic probe
		probe = "\r\n"
	}

	// Send probe
	_, err := conn.Write([]byte(probe))
	if err != nil {
		return ""
	}

	// Read response
	conn.SetReadDeadline(time.Now().Add(bg.timeout))
	buffer := make([]byte, 1024)
	n, err := conn.Read(buffer)
	if err != nil {
		return ""
	}

	banner := strings.TrimSpace(string(buffer[:n]))

	// Clean up banner (remove control characters, limit length)
	banner = bg.cleanBanner(banner)

	return banner
}

// cleanBanner cleans and formats a banner string
func (bg *BannerGrabber) cleanBanner(banner string) string {
	if len(banner) == 0 {
		return ""
	}

	// Remove control characters except newlines and tabs
	cleaned := strings.Map(func(r rune) rune {
		if r < 32 && r != '\n' && r != '\t' {
			return -1
		}
		return r
	}, banner)

	// Limit length
	if len(cleaned) > 200 {
		cleaned = cleaned[:200] + "..."
	}

	// Replace multiple whitespace with single space
	cleaned = strings.Join(strings.Fields(cleaned), " ")

	return cleaned
}

