// PortState represents the state of a scanned port
type PortState int

const (
	PortStateOpen PortState = iota
	PortStateClosed
	PortStateFiltered
	PortStateUnknown
)

// String returns the string representation of PortState
func (ps PortState) String() string {
	switch ps {
	case PortStateOpen:
		return "OPEN"
	case PortStateClosed:
		return "CLOSED"
	case PortStateFiltered:
		return "FILTERED"
	case PortStateUnknown:
		return "UNKNOWN"
	default:
		return "UNKNOWN"
	}
}

// Color returns the color for the port state
func (ps PortState) Color() lipgloss.Color {
	switch ps {
	case PortStateOpen:
		return lipgloss.Color("#10b981") // success/green
	case PortStateClosed:
		return lipgloss.Color("#6b7280") // gray
	case PortStateFiltered:
		return lipgloss.Color("#f59e0b") // warning/yellow
	case PortStateUnknown:
		return lipgloss.Color("#ef4444") // danger/red
	default:
		return lipgloss.Color("#6b7280") // gray
	}
}

// ScanProgress tracks the progress of an ongoing scan
type ScanProgress struct {
	TotalPorts    int
	ScannedPorts  int
	OpenPorts     int
	ClosedPorts   int
	FilteredPorts int
	StartTime     time.Time
	EstimatedEnd  time.Time
	CurrentTarget string
	CurrentPort   int
	Status        string
	Cancelled     bool
	Completed     bool
}

// Progress returns the completion percentage (0-100)
func (sp *ScanProgress) Progress() float64 {
	if sp.TotalPorts == 0 {
		return 0
	}
	return float64(sp.ScannedPorts) / float64(sp.TotalPorts) * 100
}

// ElapsedTime returns the time elapsed since scan start
func (sp *ScanProgress) ElapsedTime() time.Duration {
	return time.Since(sp.StartTime)
}

// EstimatedTimeRemaining returns the estimated time remaining
func (sp *ScanProgress) EstimatedTimeRemaining() time.Duration {
	if sp.ScannedPorts == 0 {
		return 0
	}

	elapsed := sp.ElapsedTime()
	avgTimePerPort := elapsed / time.Duration(sp.ScannedPorts)
	remaining := sp.TotalPorts - sp.ScannedPorts
	return avgTimePerPort * time.Duration(remaining)
}

// ScanProgressUpdate represents an update to scan progress
type ScanProgressUpdate struct {
	Progress *ScanProgress
	Result   *ScanResult
	Error    error
}

// CompletedScan represents a completed scan session
type CompletedScan struct {
	ID            string
	Targets       []string
	PortRanges    []PortRange
	ScanType      ScanType
	StartTime     time.Time
	EndTime       time.Time
	Duration      time.Duration
	TotalPorts    int
	OpenPorts     int
	ClosedPorts   int
	FilteredPorts int
