	return tea.Tick(time.Millisecond*100, func(t time.Time) tea.Msg {
		return tickMsg(t)
	})
}

// updateVisualEffects updates the visual effects state
func (psm *PortScannerModel) updateVisualEffects() {
	psm.frame++
	psm.pulsePhase += 0.05
	psm.glowIntensity = 0.3 + 0.2*math.Sin(psm.pulsePhase)
	psm.animFrame = (psm.animFrame + 1) % len(psm.scanAnimation)
}

// handleKeyMsg processes key messages for the port scanner
func (psm *PortScannerModel) handleKeyMsg(msg tea.KeyMsg) tea.Cmd {
	key := msg.String()

	// Handle input modes
	if psm.inputMode != InputModeNone {
		return psm.handleInputMode(key)
	}

	// Handle different views
	if psm.showConfig {
		return psm.handleConfigKeys(key)
	}

	if psm.showHistory {
		return psm.handleHistoryKeys(key)
	}

	if psm.showDetails {
		return psm.handleDetailsKeys(key)
	}

	if psm.showExport {
		return psm.handleExportKeys(key)
	}

	if psm.showComparison {
		return psm.handleComparisonKeys(key)
	}

	// Main view key handling
	return psm.handleMainKeys(key)
}

// handleMainKeys handles key presses in the main view
func (psm *PortScannerModel) handleMainKeys(key string) tea.Cmd {
	switch key {
	case "s":
		if !psm.isScanning {
			return psm.startScan()
		}
		return nil

	case "c":
		if psm.isScanning {
			return psm.cancelScan()
		}
		return nil

	case "C":
		psm.showConfig = true
		return nil

	case "h":
		psm.showHistory = true
		return nil

	case "d":
		if len(psm.scanResults) > 0 && psm.selectedRow < len(psm.scanResults) {
			psm.selectedResult = &psm.scanResults[psm.selectedRow]
			psm.showDetails = true
		}
		return nil

	case "f":
		psm.inputMode = InputModeTarget
		return nil

	case "p":
		psm.inputMode = InputModePort
		return nil

	case "up", "k":
		if psm.selectedRow > 0 {
			psm.selectedRow--
			if psm.selectedRow < psm.scrollOffset {
				psm.scrollOffset = psm.selectedRow
			}
		}
		return nil

	case "down", "j":
		if psm.selectedRow < len(psm.scanResults)-1 {
			psm.selectedRow++
			visibleRows := psm.height - 15
			if psm.selectedRow >= psm.scrollOffset+visibleRows {
				psm.scrollOffset = psm.selectedRow - visibleRows + 1
			}
		}
		return nil

	case "H":
		psm.sortColumn = SortByHost
		psm.sortResults()
		return nil

	case "P":
		psm.sortColumn = SortByPort
		psm.sortResults()
		return nil

	case "S":
		psm.sortColumn = SortByPortState
		psm.sortResults()
		return nil

	case "R":
		psm.sortReverse = !psm.sortReverse
		psm.sortResults()
		return nil

	case "r":
		// Clear results
		psm.scanResults = make([]ScanResult, 0)
		psm.selectedRow = 0
		psm.scrollOffset = 0
		return nil

	case "e":
		// Show export dialog
		if len(psm.scanResults) > 0 {
			psm.showExport = true
		}
		return nil

	case "x":
		// Quick export with default settings
		if len(psm.scanResults) > 0 {
			return psm.exportCurrentResults()
		}
		return nil

	case "m":
		// Show comparison dialog
		psm.showComparison = true
		return nil
	}

	return nil
}

