// handleHistoryKeys handles key presses in the history view
func (psm *PortScannerModel) handleHistoryKeys(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.showHistory = false
		return nil

	case "up", "k":
		if psm.selectedRow > 0 {
			psm.selectedRow--
		}
		return nil

	case "down", "j":
		if psm.selectedRow < len(psm.scanHistory)-1 {
			psm.selectedRow++
		}
		return nil

	case "enter":
		if len(psm.scanHistory) > 0 && psm.selectedRow < len(psm.scanHistory) {
			// Load results from selected history entry
			scan := psm.scanHistory[psm.selectedRow]
			psm.scanResults = scan.Results
			psm.showHistory = false
			psm.selectedRow = 0
			psm.scrollOffset = 0
		}
		return nil

	case "d":
		if len(psm.scanHistory) > 0 && psm.selectedRow < len(psm.scanHistory) {
			// Delete selected history entry
			psm.scanHistory = append(psm.scanHistory[:psm.selectedRow], psm.scanHistory[psm.selectedRow+1:]...)
			if psm.selectedRow >= len(psm.scanHistory) && len(psm.scanHistory) > 0 {
				psm.selectedRow = len(psm.scanHistory) - 1
			}
		}
		return nil
	}

	return nil
}

// handleDetailsKeys handles key presses in the details view
func (psm *PortScannerModel) handleDetailsKeys(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.showDetails = false
		psm.selectedResult = nil
		return nil
	}

	return nil
}

// handleInputMode handles input mode key presses
func (psm *PortScannerModel) handleInputMode(key string) tea.Cmd {
	switch key {
	case "esc":
		psm.inputMode = InputModeNone
		return nil

	case "enter":
		psm.applyInput()
		psm.inputMode = InputModeNone
		return nil

	case "backspace":
		psm.handleBackspace()
		return nil

	default:
		if len(key) == 1 {
			psm.handleCharInput(key)
		}
		return nil
	}
}

// applyInput applies the current input to the appropriate field
func (psm *PortScannerModel) applyInput() {
	switch psm.inputMode {
	case InputModeTarget:
		targets := strings.Split(psm.targetInput, ",")
		psm.targets = make([]string, 0, len(targets))
		for _, target := range targets {
			target = strings.TrimSpace(target)
			if target != "" {
				psm.targets = append(psm.targets, target)
			}
		}

	case InputModePort:
		ranges := strings.Split(psm.portInput, ",")
		psm.portRanges = make([]PortRange, 0, len(ranges))
		for _, rangeStr := range ranges {
			rangeStr = strings.TrimSpace(rangeStr)
			if portRange, err := ParsePortRange(rangeStr); err == nil {
				psm.portRanges = append(psm.portRanges, portRange)
			}
		}

	case InputModeTimeout:
		if timeout, err := strconv.Atoi(psm.timeoutInput); err == nil && timeout > 0 {
			psm.timeout = time.Duration(timeout) * time.Second
		}

	case InputModeConcurrency:
		if concurrency, err := strconv.Atoi(psm.concurrencyInput); err == nil && concurrency > 0 && concurrency <= 1000 {
			psm.concurrency = concurrency
		}
	}
}

// handleBackspace handles backspace in input mode
func (psm *PortScannerModel) handleBackspace() {
	switch psm.inputMode {
	case InputModeTarget:
		if len(psm.targetInput) > 0 {
			psm.targetInput = psm.targetInput[:len(psm.targetInput)-1]
		}
	case InputModePort:
		if len(psm.portInput) > 0 {
			psm.portInput = psm.portInput[:len(psm.portInput)-1]
		}
	case InputModeTimeout:
		if len(psm.timeoutInput) > 0 {
			psm.timeoutInput = psm.timeoutInput[:len(psm.timeoutInput)-1]
		}
	case InputModeConcurrency:
		if len(psm.concurrencyInput) > 0 {
			psm.concurrencyInput = psm.concurrencyInput[:len(psm.concurrencyInput)-1]
		}
	}
}

// handleCharInput handles character input in input mode
func (psm *PortScannerModel) handleCharInput(char string) {
	switch psm.inputMode {
	case InputModeTarget:
		psm.targetInput += char
	case InputModePort:
		psm.portInput += char
	case InputModeTimeout:
		if char >= "0" && char <= "9" {
			psm.timeoutInput += char
		}
	case InputModeConcurrency:
		if char >= "0" && char <= "9" {
			psm.concurrencyInput += char
		}
	}
}

// startScan initiates a new port scan
func (psm *PortScannerModel) startScan() tea.Cmd {
	if psm.isScanning {
		return nil
	}

	// Validate inputs
	if len(psm.targets) == 0 {
		return nil
	}

	if len(psm.portRanges) == 0 {
		return nil
	}

	// Clear previous results
	psm.scanResults = make([]ScanResult, 0)
	psm.selectedRow = 0
	psm.scrollOffset = 0

	// Create scanner
	psm.scanner = NewPortScanner(psm.concurrency, psm.timeout)

	// Create channels
	psm.resultsChan = make(chan ScanResult, 100)
	psm.progressChan = make(chan ScanProgressUpdate, 10)
	psm.errorChan = make(chan error, 10)

	// Create context for cancellation
	psm.scanContext, psm.scanCancel = context.WithCancel(context.Background())

	// Initialize scan progress
	psm.currentScan = &ScanProgress{
		StartTime: time.Now(),
		Status:    "Initializing scan...",
	}

	psm.isScanning = true
	psm.scanCancelled = false

	// Start the scan in a goroutine
	go func() {
		err := psm.scanner.ScanPorts(psm.scanContext, psm.targets, psm.portRanges, psm.scanType, psm.progressChan)
		if err != nil && err != context.Canceled {
			psm.errorChan <- err
		}
	}()

	return nil
}

// cancelScan cancels the current scan
func (psm *PortScannerModel) cancelScan() tea.Cmd {
	if !psm.isScanning || psm.scanCancel == nil {
		return nil
	}

	psm.scanCancel()
	psm.scanCancelled = true

	if psm.currentScan != nil {
		psm.currentScan.Cancelled = true
		psm.currentScan.Status = "Cancelling scan..."
	}

	return nil
}

// handleScanProgress handles scan progress updates
func (psm *PortScannerModel) handleScanProgress(update ScanProgressUpdate) {
	if update.Progress != nil {
		psm.currentScan = update.Progress
	}

	if update.Result != nil {
		psm.scanResults = append(psm.scanResults, *update.Result)
		psm.sortResults()
	}

	if update.Error != nil {
		// Handle scan error
		if psm.currentScan != nil {
			psm.currentScan.Status = fmt.Sprintf("Error: %s", update.Error.Error())
		}
	}

	// Check if scan is complete
	if psm.currentScan != nil && (psm.currentScan.Completed || psm.currentScan.Cancelled) {
		psm.finalizeScan()
	}
}

// handleScanComplete handles scan completion
func (psm *PortScannerModel) handleScanComplete(scan CompletedScan) {
	// Add to history
	psm.scanHistory = append(psm.scanHistory, scan)

	// Keep only the last 50 scans in history
	if len(psm.scanHistory) > 50 {
		psm.scanHistory = psm.scanHistory[1:]
	}
}

// finalizeScan finalizes the current scan
func (psm *PortScannerModel) finalizeScan() {
	if psm.currentScan == nil {
		return
	}

	// Create completed scan record
	completedScan := CompletedScan{
		ID:            fmt.Sprintf("scan_%d", time.Now().Unix()),
		Targets:       psm.targets,
		PortRanges:    psm.portRanges,
		ScanType:      psm.scanType,
		StartTime:     psm.currentScan.StartTime,
		EndTime:       time.Now(),
		Duration:      time.Since(psm.currentScan.StartTime),
		TotalPorts:    psm.currentScan.TotalPorts,
		OpenPorts:     psm.currentScan.OpenPorts,
		ClosedPorts:   psm.currentScan.ClosedPorts,
		FilteredPorts: psm.currentScan.FilteredPorts,
		Results:       psm.scanResults,
		Cancelled:     psm.currentScan.Cancelled,
	}

	// Store in persistent history
	if psm.historyManager != nil {
		if err := psm.historyManager.StoreScan(completedScan); err != nil {
			// Log error but don't fail the scan
			_ = err
		}
	}

	// Add to local history
	psm.scanHistory = append(psm.scanHistory, completedScan)

	// Keep only the last 50 scans in local history
	if len(psm.scanHistory) > 50 {
		psm.scanHistory = psm.scanHistory[1:]
	}

	// Reset scan state
	psm.isScanning = false
	psm.currentScan = nil
	psm.scanContext = nil
	psm.scanCancel = nil

	// Close channels
	if psm.resultsChan != nil {
		close(psm.resultsChan)
		psm.resultsChan = nil
	}
	if psm.progressChan != nil {
		close(psm.progressChan)
		psm.progressChan = nil
	}
	if psm.errorChan != nil {
		close(psm.errorChan)
		psm.errorChan = nil
	}
}

// sortResults sorts the scan results based on current sort settings
func (psm *PortScannerModel) sortResults() {
	sort.Slice(psm.scanResults, func(i, j int) bool {
		a, b := psm.scanResults[i], psm.scanResults[j]

		var less bool
		switch psm.sortColumn {
		case SortByHost:
			less = a.Host < b.Host
		case SortByPort:
			less = a.Port < b.Port
		case SortByPortState:
			less = a.State < b.State
		case SortByService:
			less = a.Service < b.Service
		case SortByResponseTime:
			less = a.ResponseTime < b.ResponseTime
		case SortByTimestamp:
			less = a.Timestamp.Before(b.Timestamp)
		default:
			less = a.Port < b.Port
		}

		if psm.sortReverse {
			return !less
		}
		return less
	})
}

