// NewBannerGrabber creates a new banner grabber
func NewBannerGrabber() *BannerGrabber {
	return &BannerGrabber{
		timeout: 5 * time.Second,
	}
}

// GrabBanner attempts to grab a service banner from a port with comprehensive error handling
func (bg *BannerGrabber) GrabBanner(host string, port int) string {
	// Validate inputs
	if host == "" {
		return ""
	}
	if port < 1 || port > 65535 {
		return ""
	}

	address := fmt.Sprintf("%s:%d", host, port)

	// Create connection with timeout and error handling
	conn, err := net.DialTimeout("tcp", address, bg.timeout)
	if err != nil {
		// Log connection failure but don't expose internal details
		return ""
	}
	defer func() {
		if closeErr := conn.Close(); closeErr != nil {
			// Log close error but continue execution
			_ = closeErr
		}
	}()

	// Set read deadline with error handling
	if err := conn.SetReadDeadline(time.Now().Add(bg.timeout)); err != nil {
		return ""
	}

	// Try to read banner (some services send banner immediately)
	buffer := make([]byte, 1024)
	n, err := conn.Read(buffer)
	if err != nil {
		// If no immediate banner, try sending a probe with error recovery
		if netErr, ok := err.(net.Error); ok && netErr.Timeout() {
			// Timeout occurred, try probing
			return bg.probeBannerSafe(conn, port)
		}
		// Other network errors, try probe as fallback
		return bg.probeBannerSafe(conn, port)
	}

	// Validate read length
	if n > 0 && n <= len(buffer) {
		banner := strings.TrimSpace(string(buffer[:n]))
		if len(banner) > 0 {
			// Clean and validate banner before returning
			cleanedBanner := bg.cleanBanner(banner)
			if cleanedBanner != "" {
				return cleanedBanner
			}
		}
	}

	// Try probing if no immediate banner
	return bg.probeBannerSafe(conn, port)
}

// probeBanner sends protocol-specific probes to elicit a banner (legacy method)
func (bg *BannerGrabber) probeBanner(conn net.Conn, port int) string {
	return bg.probeBannerSafe(conn, port)
}

// probeBannerSafe sends protocol-specific probes to elicit a banner with comprehensive error handling
func (bg *BannerGrabber) probeBannerSafe(conn net.Conn, port int) string {
	// Validate connection
	if conn == nil {
		return ""
	}

	// Set write deadline with error handling
	if err := conn.SetWriteDeadline(time.Now().Add(bg.timeout)); err != nil {
		return ""
	}

	var probe string
	switch port {
	case 21: // FTP
		probe = "USER anonymous\r\n"
	case 22: // SSH
		probe = "SSH-2.0-Scanner\r\n"
	case 25: // SMTP
		probe = "EHLO scanner\r\n"
	case 80, 8080: // HTTP
		probe = "GET / HTTP/1.0\r\n\r\n"
	case 110: // POP3
		probe = "USER test\r\n"
	case 143: // IMAP
		probe = "A001 CAPABILITY\r\n"
	case 443: // HTTPS
		// For HTTPS, we can't easily grab banner without TLS handshake
		return ""
	default:
		// Generic probe
		probe = "\r\n"
	}

	// Send probe with error handling
	_, err := conn.Write([]byte(probe))
	if err != nil {
		// Log write error but don't expose details
		return ""
	}

	// Set read deadline with error handling
	if err := conn.SetReadDeadline(time.Now().Add(bg.timeout)); err != nil {
		return ""
	}

	// Read response with bounds checking
	buffer := make([]byte, 1024)
	n, err := conn.Read(buffer)
	if err != nil {
		// Handle different types of read errors
		if netErr, ok := err.(net.Error); ok {
			if netErr.Timeout() {
				// Timeout is expected for some services
				return ""
			}
		}
		// Other network errors
		return ""
	}

	// Validate read length
	if n <= 0 || n > len(buffer) {
		return ""
	}

	banner := strings.TrimSpace(string(buffer[:n]))

	// Clean up banner (remove control characters, limit length)
	banner = bg.cleanBanner(banner)

	return banner
}

// cleanBanner cleans and formats a banner string
func (bg *BannerGrabber) cleanBanner(banner string) string {
	if len(banner) == 0 {
		return ""
	}

	// Remove control characters except newlines and tabs
	cleaned := strings.Map(func(r rune) rune {
		if r < 32 && r != '\n' && r != '\t' {
			return -1
		}
		return r
	}, banner)

	// Limit length
	if len(cleaned) > 200 {
		cleaned = cleaned[:200] + "..."
	}

	// Replace multiple whitespace with single space
	cleaned = strings.Join(strings.Fields(cleaned), " ")

	return cleaned
}

