// ScanProgress tracks the progress of an ongoing scan
type ScanProgress struct {
	TotalPorts    int
	ScannedPorts  int
	OpenPorts     int
	ClosedPorts   int
	FilteredPorts int
	StartTime     time.Time
	EstimatedEnd  time.Time
