// Progress returns the completion percentage (0-100)
func (sp *ScanProgress) Progress() float64 {
	if sp.TotalPorts == 0 {
		return 0
	}
	return float64(sp.ScannedPorts) / float64(sp.TotalPorts) * 100
}

// ElapsedTime returns the time elapsed since scan start
func (sp *ScanProgress) ElapsedTime() time.Duration {
	return time.Since(sp.StartTime)
}

// EstimatedTimeRemaining returns the estimated time remaining
func (sp *ScanProgress) EstimatedTimeRemaining() time.Duration {
	if sp.ScannedPorts == 0 {
		return 0
	}

	elapsed := sp.ElapsedTime()
	avgTimePerPort := elapsed / time.Duration(sp.ScannedPorts)
	remaining := sp.TotalPorts - sp.ScannedPorts
	return avgTimePerPort * time.Duration(remaining)
}

