// NewPortScannerModel creates a new port scanner component
func NewPortScannerModel() *PortScannerModel {
	// Create directories for export and history
	homeDir, _ := os.UserHomeDir()
	exportDir := filepath.Join(homeDir, ".terminal-multitool", "exports")
	historyDir := filepath.Join(homeDir, ".terminal-multitool", "history")

	// Initialize export and history managers
	exporter := NewScanExporter(exportDir)
	historyManager := NewScanHistoryManager(historyDir, 100) // Keep last 100 scans
	historyManager.Initialize()
	comparator := NewScanComparator(historyManager)

	psm := &PortScannerModel{
		active:           false,
		targets:          []string{"127.0.0.1"},
		portRanges:       []PortRange{{Start: 1, End: 1000}},
		scanType:         ScanTypeTCP,
		concurrency:      50,
		timeout:          5 * time.Second,
		enableBanner:     true,
		enableService:    true,
		scanResults:      make([]ScanResult, 0),
		scanHistory:      make([]CompletedScan, 0),
		sortColumn:       SortByPort,
		sortReverse:      false,
		inputMode:        InputModeNone,
		targetInput:      "127.0.0.1",
		portInput:        "1-1000",
		timeoutInput:     "5",
		concurrencyInput: "50",
		exportFormat:     ExportFormatJSON,
		exporter:         exporter,
		historyManager:   historyManager,
		comparator:       comparator,
		serviceDB:        NewServiceDatabase(),
		bannerGrabber:    NewBannerGrabber(),
		glowIntensity:    0.5,
		pulsePhase:       0,
		scanAnimation:    []string{"⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"},
	}

	return psm
}

// ToolComponent interface implementation

// Init initializes the port scanner component
func (psm *PortScannerModel) Init() tea.Cmd {
	return psm.tickCmd()
}

// Update handles messages for the port scanner
func (psm *PortScannerModel) Update(msg tea.Msg) (ToolComponent, tea.Cmd) {
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case tea.KeyMsg:
		if !psm.active {
			return psm, nil
		}

		if cmd := psm.handleKeyMsg(msg); cmd != nil {
			cmds = append(cmds, cmd)
		}

	case scanProgressMsg:
		psm.handleScanProgress(msg.update)

	case scanCompleteMsg:
		psm.handleScanComplete(msg.scan)

	case tickMsg:
		psm.updateVisualEffects()
		cmds = append(cmds, psm.tickCmd())

		// Check for scan updates
		if psm.isScanning && psm.progressChan != nil {
			select {
			case update := <-psm.progressChan:
				cmds = append(cmds, func() tea.Msg {
					return scanProgressMsg{update: update}
				})
			default:
				// No update available
			}
		}
	}

	return psm, tea.Batch(cmds...)
}

// View renders the port scanner interface
func (psm *PortScannerModel) View() string {
	if !psm.active || psm.width == 0 || psm.height == 0 {
		return ""
	}

	if psm.showExport {
		return psm.renderExportView()
	}

	if psm.showComparison {
		return psm.renderComparisonView()
	}

	if psm.showConfig {
		return psm.renderConfigView()
	}

	if psm.showHistory {
		return psm.renderHistoryView()
	}

	if psm.showDetails && psm.selectedResult != nil {
		return psm.renderDetailsView()
	}

	return psm.renderMainView()
}

