// renderScanProgress renders the scan progress bar and statistics
func (psm *PortScannerModel) renderScanProgress() string {
	if psm.currentScan == nil {
		return ""
	}

	var s strings.Builder

	progressStyle := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(lipgloss.Color("#10b981")).
		Padding(0, 1).
		Width(psm.width - 4)

	// Progress bar
	progress := psm.currentScan.Progress()
	barWidth := 40
	filledWidth := int(progress * float64(barWidth) / 100)

	progressBar := strings.Repeat("█", filledWidth) + strings.Repeat("░", barWidth-filledWidth)

	// Statistics
	elapsed := psm.currentScan.ElapsedTime()
	remaining := psm.currentScan.EstimatedTimeRemaining()

	content := fmt.Sprintf("%s %.1f%% (%d/%d ports)\nOpen: %d | Closed: %d | Filtered: %d\nElapsed: %v | Remaining: %v\nStatus: %s",
		progressBar, progress, psm.currentScan.ScannedPorts, psm.currentScan.TotalPorts,
		psm.currentScan.OpenPorts, psm.currentScan.ClosedPorts, psm.currentScan.FilteredPorts,
		elapsed.Round(time.Second), remaining.Round(time.Second),
		psm.currentScan.Status)

	s.WriteString(progressStyle.Render(content))
	return s.String()
}

// renderResultsTable renders the scan results table
func (psm *PortScannerModel) renderResultsTable() string {
	var s strings.Builder

	// Table header
	headers := []string{"HOST", "PORT", "STATE", "SERVICE", "VERSION", "RESPONSE"}
	widths := []int{15, 8, 10, 15, 15, 10}

	// Adjust widths based on available space
	totalWidth := psm.width - 10
	if totalWidth > 0 {
		// Distribute remaining width
		remaining := totalWidth - 63 // Base width of fixed columns
		if remaining > 0 {
			widths[0] += remaining / 3 // HOST
			widths[3] += remaining / 3 // SERVICE
			widths[4] += remaining / 3 // VERSION
		}
	}

	var headerParts []string
	for i, header := range headers {
		style := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#06b6d4")).
			Bold(true).
			Width(widths[i]).
			Align(lipgloss.Left)
		headerParts = append(headerParts, style.Render(header))
	}

	s.WriteString(strings.Join(headerParts, " ") + "\n")
	s.WriteString(strings.Repeat("─", psm.width-2) + "\n")

	// Table rows
	if len(psm.scanResults) == 0 {
		noResults := lipgloss.NewStyle().
			Foreground(lipgloss.Color("#6b7280")).
			Align(lipgloss.Center).
			Width(psm.width - 2).
			Render("No scan results available. Press 's' to start a scan.")
		s.WriteString(noResults + "\n")
		return s.String()
	}

	visibleRows := psm.height - 12
	startIdx := psm.scrollOffset
	endIdx := min(startIdx+visibleRows, len(psm.scanResults))

	for i := startIdx; i < endIdx; i++ {
		if i >= len(psm.scanResults) {
			break
		}

		result := psm.scanResults[i]
		isSelected := i == psm.selectedRow

		// Format fields
		host := result.Host
		if len(host) > widths[0] {
			host = host[:widths[0]-3] + "..."
		}

		port := fmt.Sprintf("%d", result.Port)
		state := result.State.String()
		service := result.Service
		if len(service) > widths[3] {
			service = service[:widths[3]-3] + "..."
		}

		version := result.Version
		if len(version) > widths[4] {
			version = version[:widths[4]-3] + "..."
		}

		response := fmt.Sprintf("%.0fms", float64(result.ResponseTime.Nanoseconds())/1000000)

		// Create row parts with appropriate colors
		parts := []string{
			lipgloss.NewStyle().Width(widths[0]).Render(host),
			lipgloss.NewStyle().Width(widths[1]).Render(port),
			lipgloss.NewStyle().Width(widths[2]).Foreground(result.State.Color()).Render(state),
			lipgloss.NewStyle().Width(widths[3]).Render(service),
			lipgloss.NewStyle().Width(widths[4]).Render(version),
			lipgloss.NewStyle().Width(widths[5]).Render(response),
		}

		row := strings.Join(parts, " ")

		if isSelected {
			row = lipgloss.NewStyle().
				Foreground(lipgloss.Color("#0f0f23")).
				Background(lipgloss.Color("#06b6d4")).
				Bold(true).
				Width(psm.width - 2).
				Render(" " + row + " ")
		}

		s.WriteString(row + "\n")
	}

	return s.String()
}

