		{"3", ExportFormatXML, "XML - Extensible markup language"},
		{"4", ExportFormatTXT, "TXT - Human-readable text"},
	}

	for _, f := range formats {
		style := lipgloss.NewStyle().Foreground(lipgloss.Color("#888888"))
		if f.format == psm.exportFormat {
			style = style.Foreground(lipgloss.Color("#00ff00")).Bold(true)
		}
		s.WriteString(style.Render(fmt.Sprintf("  %s. %s\n", f.key, f.desc)))
	}

	s.WriteString("\n")

	// Filename input
	if psm.inputMode == InputModeTarget {
		s.WriteString("Filename: " + psm.exportFilename + "_\n")
	} else {
		s.WriteString("Press 'f' to specify filename (optional)\n")
	}

	s.WriteString("\nControls:\n")
	s.WriteString("  ENTER: Export with current settings\n")
	s.WriteString("  ESC: Cancel\n")

	return s.String()
}

// renderComparisonView renders the comparison dialog
func (psm *PortScannerModel) renderComparisonView() string {
	if !psm.showComparison {
		return ""
	}

	var s strings.Builder

	title := lipgloss.NewStyle().
		Foreground(lipgloss.Color("#ffff00")).
		Bold(true).
		Render("🔍 COMPARE WITH HISTORICAL SCAN")
	s.WriteString(title + "\n\n")

	// Get history entries
	historyEntries, err := psm.historyManager.GetHistory()
	if err != nil || len(historyEntries) == 0 {
		s.WriteString("No historical scans available for comparison.\n")
		s.WriteString("Press ESC to cancel.\n")
		return s.String()
	}

	s.WriteString("Select a historical scan to compare with:\n\n")

	// Display history entries
	maxEntries := min(len(historyEntries), 10)
	for i := 0; i < maxEntries; i++ {
		entry := historyEntries[i]
		style := lipgloss.NewStyle().Foreground(lipgloss.Color("#888888"))
		if i == psm.selectedRow {
			style = style.Foreground(lipgloss.Color("#ffff00")).Bold(true)
		}

		line := fmt.Sprintf("  %s - %s (%d ports, %d open)",
			entry.StartTime.Format("2006-01-02 15:04"),
			strings.Join(entry.Targets, ", "),
			entry.TotalPorts,
			entry.OpenPorts)

		if len(line) > 60 {
			line = line[:57] + "..."
		}

		s.WriteString(style.Render(line) + "\n")
	}

	s.WriteString("\nControls:\n")
	s.WriteString("  ↑↓: Navigate  ENTER: Compare  ESC: Cancel\n")

	return s.String()
}

