// processAIRequest processes the AI request with comprehensive error handling
func (ai *AIAssistantModel) processAIRequest(message string) tea.Cmd {
	return func() tea.Msg {
		// Validate input message
		if strings.TrimSpace(message) == "" {
			return aiResponseMsg{
				response: "Error: Empty message provided",
				agent:    ai.currentAgent,
				error:    fmt.Errorf("empty message"),
			}
		}

		// Validate message length (prevent extremely long messages)
		if len(message) > 10000 {
			return aiResponseMsg{
				response: "Error: Message too long (max 10,000 characters)",
				agent:    ai.currentAgent,
				error:    fmt.Errorf("message too long: %d characters", len(message)),
			}
		}

		// Find the current agent with error handling
		var agent *AIAgent
		for _, a := range ai.availableAgents {
			if a.Command == ai.currentAgent {
				agent = &a
				break
			}
		}

		if agent == nil {
			return aiResponseMsg{
				response: fmt.Sprintf("Error: Agent '%s' not found. Available agents: %s", ai.currentAgent, ai.getAvailableAgentNames()),
				agent:    ai.currentAgent,
				error:    fmt.Errorf("agent not found: %s", ai.currentAgent),
			}
		}

		if !agent.Available {
			return aiResponseMsg{
				response: fmt.Sprintf("Error: Agent '%s' is not available. Please check your installation or select a different agent.", agent.Name),
				agent:    ai.currentAgent,
				error:    fmt.Errorf("agent not available: %s", agent.Name),
			}
		}

		// Safely construct command with error recovery
		var cmd *exec.Cmd
		func() {
			defer func() {
				if r := recover(); r != nil {
					// Recover from any panic during command construction
					cmd = nil
				}
			}()

			switch agent.Command {
			case "claude-code":
				// Claude Code: Try claude command if available
				cmd = exec.Command("claude", message)
			case "gemini":
				// Gemini CLI: Use -p flag for prompt
				cmd = exec.Command("gemini", "-p", message)
			case "gh copilot":
				// GitHub Copilot CLI: Use suggest command for code suggestions
				cmd = exec.Command("gh", "copilot", "suggest", message)
			case "opencode":
				cmd = exec.Command("opencode", message)
			case "aider":
				// Aider: Use --message flag for non-interactive mode
				cmd = exec.Command("aider", "--message", message)
			case "sgpt":
				// Shell GPT: Direct message input
				cmd = exec.Command("sgpt", message)
			default:
				cmd = nil
			}
		}()

		if cmd == nil {
			return aiResponseMsg{
				response: fmt.Sprintf("Error: Unknown or unsupported agent command: %s", agent.Command),
				agent:    agent.Command,
				error:    fmt.Errorf("unknown agent command: %s", agent.Command),
			}
		}

		// Set working directory with error handling
		if wd, err := os.Getwd(); err == nil {
			cmd.Dir = wd
		} else {
			// Log warning but continue execution
			_ = err // Could log this if we had a logger
		}

		// Set environment variables for security
		if cmd.Env == nil {
			cmd.Env = os.Environ()
		}

		// Set reasonable timeout for AI operations
		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
		defer cancel()

		// Create command with context for timeout handling
		cmdWithContext := exec.CommandContext(ctx, cmd.Args[0], cmd.Args[1:]...)
		cmdWithContext.Dir = cmd.Dir
		cmdWithContext.Env = cmd.Env

		// Execute command with comprehensive error handling
		output, err := cmdWithContext.CombinedOutput()

		// Handle different types of errors
		if err != nil {
			if ctx.Err() == context.DeadlineExceeded {
				return aiResponseMsg{
					response: fmt.Sprintf("Error: AI request timed out after 30 seconds using %s", agent.Name),
					agent:    agent.Command,
					error:    fmt.Errorf("timeout: %w", err),
				}
			}

			if exitError, ok := err.(*exec.ExitError); ok {
				// Command executed but returned non-zero exit code
				errorOutput := string(exitError.Stderr)
				if errorOutput == "" {
					errorOutput = string(output) // Sometimes error is in stdout
				}
				return aiResponseMsg{
					response: fmt.Sprintf("Error from %s: %s", agent.Name, errorOutput),
					agent:    agent.Command,
					error:    err,
				}
			}

			// Other execution errors
			return aiResponseMsg{
				response: fmt.Sprintf("Error executing %s: %v", agent.Name, err),
				agent:    agent.Command,
				error:    err,
			}
		}

		// Clean and validate output
		cleanedOutput := ai.cleanAIOutput(string(output))
		if cleanedOutput == "" {
			return aiResponseMsg{
				response: fmt.Sprintf("%s processed the request but returned no output", agent.Name),
				agent:    agent.Command,
				error:    nil,
			}
		}

		return aiResponseMsg{
			response: cleanedOutput,
			agent:    agent.Command,
			error:    nil,
		}
	}
}

