	// Validate inputs
	if role == "" {
		role = "unknown"
	}
	if content == "" {
		content = "(empty message)"
	}
	if agent == "" {
		agent = "unknown"
	}

	msg := AIMessage{
		Role:      role,
		Content:   content,
		Timestamp: time.Now(),
		Agent:     agent,
	}

