// Helper methods

// getAvailableAgentNames returns a comma-separated list of available agent names
func (ai *AIAssistantModel) getAvailableAgentNames() string {
	var names []string
	for _, agent := range ai.availableAgents {
		if agent.Available {
			names = append(names, agent.Name)
		}
	}
	return strings.Join(names, ", ")
}

// cleanAIOutput cleans and validates AI output
func (ai *AIAssistantModel) cleanAIOutput(output string) string {
	if output == "" {
		return ""
	}

	// Remove excessive whitespace
	output = strings.TrimSpace(output)

	// Limit output length to prevent UI issues
	if len(output) > 50000 {
		output = output[:50000] + "\n\n[Output truncated - response too long]"
	}

	// Remove any potentially harmful escape sequences (basic sanitization)
	output = strings.ReplaceAll(output, "\x1b", "")
	output = strings.ReplaceAll(output, "\033", "")

	return output
}

// addMessage adds a message to the chat history with error handling
func (ai *AIAssistantModel) addMessage(role, content, agent string) {
	// Validate inputs
	if role == "" {
		role = "unknown"
	}
	if content == "" {
		content = "(empty message)"
	}
	if agent == "" {
		agent = "unknown"
	}

	msg := AIMessage{
		Role:      role,
		Content:   content,
		Timestamp: time.Now(),
		Agent:     agent,
	}

	ai.chatHistory = append(ai.chatHistory, msg)

	// Limit history size with error recovery
	if len(ai.chatHistory) > ai.maxHistorySize && ai.maxHistorySize > 0 {
		// Safely truncate history
		startIdx := len(ai.chatHistory) - ai.maxHistorySize
		if startIdx < 0 {
			startIdx = 0
		}
		ai.chatHistory = ai.chatHistory[startIdx:]
	}
}

