	if len(message) > 10000 {
		ai.addMessage("system", "Message too long (max 10,000 characters). Please shorten your message.", "system")
		return ai, nil
	}

	// Check if already processing
	if ai.isProcessing {
		ai.addMessage("system", "Please wait for the current request to complete before sending another message.", "system")
		return ai, nil
	}

	// Validate current agent
	agentValid := false
	for _, agent := range ai.availableAgents {
		if agent.Command == ai.currentAgent && agent.Available {
			agentValid = true
			break
		}
	}

	if !agentValid {
		ai.addMessage("system", fmt.Sprintf("Selected agent '%s' is not available. Please select a different agent using Tab.", ai.currentAgent), "system")
		return ai, nil
	}

	// Add user message to history
	ai.addMessage("user", message, ai.currentAgent)

	// Clear input
	ai.input = ""
	ai.cursorPos = 0

	// Set processing state
	ai.isProcessing = true

	if ai.autoScroll {
		ai.scrollToBottom()
	}

	// Send to AI agent
	return ai, ai.processAIRequest(message)
}

